  type: ItemType;
  stats: Partial<PlayerStats>; 
  rarity: Rarity;
  price: number;
  level: number;
  projectileType?: ProjectileType;
  ability?: AbilityType;
  description?: string;
  stackSize?: number; 
  quantity?: number; 
  classType?: HeroClass; 

  // Consumable Specifics
  restoreAmount?: number;

  // Pet Specifics
  petSkill?: PetSkillType;
  petValue?: number; // Heal amount or Dmg
  petCooldown?: number; 

  setName?: string;
  setBonus?: string; 
  setBonusStats?: Partial<PlayerStats>;

  onHitEffect?: {
      type: StatusEffectType;
