  maxHealth: number;
  speed: number;
  radius: number;
  scale: number;
  active: boolean;
  state?: 'CHASE' | 'CHARGE_PREP' | 'CHARGE' | 'SHOOT';
  stateTimer?: number;
  chargeDir?: Vector3;

  burnTimer?: number;
