export interface SkillLevels {
    orbital: number;
    thunder: number;
    regen: number;
    magnet: number;
    dash: number;
    weapon: number;
    barrier: number;
    storm: number;
    special: number; // E Skill (Class Specific)

    // Active Skills (Q)
    piercing: number;
    gravity: number;
    rage: number;

    // Passive Skills
    burning: number;
    freezing: number;
    freezeSpell: number; // Renamed to Blizzard (Passive)
