    stormMaxCooldown: number;
}

export interface GameNotification {
    id: string;
    message: string;
    color: string;
    type: 'ITEM' | 'BOSS' | 'SYSTEM';
    action?: {
        label: string;
        onClick: () => void;
    };
}

export interface BossData {
    active: boolean;
    name: string;
    hp: number;
    maxHp: number;
}

export interface GameStatistics {
    totalRuns: number;
    highestWave: number;
    highestCP: number;
    bestRunClass: HeroClass | null;
    classRuns: Record<HeroClass, number>;
    classHighestWave: Record<HeroClass, number>;
}

import React, { useRef, useEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import { InstancedMesh, Object3D, Vector3, Color } from 'three';
import { useGameStore } from '../store';
import { ARENA_SIZE, COLORS } from '../constants';
import { GameStatus, EnemyData, BulletData } from '../types';
import { SpatialHashGrid } from '../utils/SpatialHashGrid';

const MAX_ENEMIES = 400;

const dummy = new Object3D();
const tempVec = new Vector3();
const tempColor = new Color();
const pushDir = new Vector3();

// Enemy Types Map
// 0: Basic
// 1: Elite (Melee)
// 2: Boss
// 3: Ranged (Fast)
// 4: Speedy (New)
// 5: Elite Shooter (New)
// 6: Ranged (Slow)

interface EnemyManagerProps {
  bulletsDataRef: React.MutableRefObject<BulletData[]>;
  enemyBulletsDataRef: React.MutableRefObject<BulletData[]>;
  enemiesDataRef: React.MutableRefObject<EnemyData[]>;
  spatialGrid: React.MutableRefObject<SpatialHashGrid>;
}

export const EnemyManager: React.FC<EnemyManagerProps> = ({ bulletsDataRef, enemyBulletsDataRef, enemiesDataRef, spatialGrid }) => {
  const meshRef = useRef<InstancedMesh>(null);
  const stunIconsRef = useRef<InstancedMesh>(null);
  const { playerPosition, addScore, takeDamage, status, level, stats, spawnDrop, wave, waveTimer, advanceWave, addNotification, setBossData, earthwall, updateMinimapEnemies, obstacles } = useGameStore();

  const enemies = enemiesDataRef;

  const spawnTimer = useRef(0);
  const dotTicker = useRef(0);
  const waveState = useRef({ wave: 1, bossSpawned: false, eliteSpawned: false });
  const minimapThrottle = useRef(0); 

  useEffect(() => {
    const handleBarrier = (e: CustomEvent) => {
        const { position, radius, force } = e.detail;
        enemies.current.forEach(enemy => {
            if (enemy.active) {
                const dist = enemy.position.distanceTo(position);
                if (dist < radius) {
                    const dir = new Vector3().subVectors(enemy.position, position).normalize();
                    enemy.position.add(dir.multiplyScalar(force));
                    enemy.freezeTimer = 0.5;
                }
            }
        });
    };
    window.addEventListener('barrier-trigger', handleBarrier as EventListener);
    return () => window.removeEventListener('barrier-trigger', handleBarrier as EventListener);
  }, []);

  useFrame((state, delta) => {
    if (status !== GameStatus.PLAYING) return;
    if (!meshRef.current) return;

    spatialGrid.current.clear();
    const activeBullets = bulletsDataRef.current;

    activeBullets.forEach(b => { 
        if(b.active && b.type === 'BLACKHOLE') {
            b.currentPullCount = 0; 
        }
    });

    if (!meshRef.current.userData.enemies) {
        meshRef.current.userData.enemies = enemies.current;
    }

    if (waveTimer > 30) {
        advanceWave();
    }

    if (wave !== waveState.current.wave) {
        waveState.current.wave = wave;
        waveState.current.bossSpawned = false;
        waveState.current.eliteSpawned = false;
    }

    spawnTimer.current += delta;
    const spawnRate = Math.max(0.05, 0.8 - (level * 0.02) - (wave * 0.05));

    if (spawnTimer.current > spawnRate) {
        spawnTimer.current = 0;
        const enemy = enemies.current.find(e => !e.active);
        if (enemy) {
            enemy.active = true;
            enemy.burnTimer = 0;
            enemy.poisonTimer = 0;
            enemy.freezeTimer = 0;
            enemy.slowTimer = 0;
            enemy.slowFactor = 0;
            enemy.bossPattern = 0;
            enemy.bossTimer = 0;
            enemy.bossAngle = 0;

            let angle, dist, spawnPos;
            do {
                angle = Math.random() * Math.PI * 2;
                dist = (ARENA_SIZE / 2) - 5;
                spawnPos = new Vector3(Math.cos(angle) * dist, 0, Math.sin(angle) * dist);
            } while (spawnPos.distanceTo(playerPosition) < 20);

            enemy.position.copy(spawnPos);

            const hpMult = 1 + (wave * 0.5) + (level * 0.1);
            // MODIFIED: Speed progression 50% slower
            const speedMult = 1 + (wave * 0.025);
            const globalHpReduction = 0.4;
            const r = Math.random();

            let isBoss = false;

            if (wave % 10 === 0 && !waveState.current.bossSpawned) {
                isBoss = true;
                waveState.current.bossSpawned = true;
                const bossName = wave % 20 === 0 ? "VOID REAPER" : "ABYSS LORD";
                addNotification(`⚠️ ${bossName} APPEARED ⚠️`, COLORS.enemyBoss, 'BOSS');
                setBossData({ active: true, name: bossName, hp: 1, maxHp: 1 });

                enemy.type = 2; 
                // MODIFIED: Boss HP 20% less
                enemy.health = (2000 + (level * 250) + (wave * 100)) * hpMult * globalHpReduction * 0.8;
                enemy.speed = (2.5 + (level * 0.1)) * speedMult;
                enemy.radius = 2.5;
                enemy.scale = 3.0; 
                setBossData({ hp: enemy.health, maxHp: enemy.health });

            } else {
                // MODIFIED: Elite Monster Logic (Spawn at any wave, 2x more spawn)
                // Old chance was mainly tied to wave. New chance is flat random increased by wave.
                const isElite = (r < (0.05 + (wave * 0.01))) || (wave % 5 === 0 && !waveState.current.eliteSpawned);

                if (wave % 5 === 0 && !waveState.current.eliteSpawned) {
                     waveState.current.eliteSpawned = true;
                     addNotification("⚠️ ELITE SQUAD", COLORS.enemyElite, 'BOSS');
                }

                if (isElite) {
                    if (Math.random() > 0.7) {
                        // MODIFIED: New Elite Shooter (Type 5)
                        enemy.type = 5; 
                        enemy.health = (120 + (level * 15)) * hpMult * globalHpReduction;
                        enemy.speed = (3.5 + (level * 0.1)) * speedMult;
                        enemy.radius = 1.8;
                        enemy.scale = 1.6;
                    } else {
                        // Standard Elite (Type 1)
                        enemy.type = 1; 
                        enemy.health = (150 + (level * 20)) * hpMult * globalHpReduction;
                        enemy.speed = (4 + (level * 0.1)) * speedMult;
                        enemy.radius = 1.5;
                        enemy.scale = 1.5; 
                    }
                } 
                // MODIFIED: Ranged Spawn Logic (50% less)
                // Original chance was roughly > 0.85 (15%). Reducing to ~7.5%.
                // Split between Type 3 (Fast) and Type 6 (Slow)
                else if (wave >= 3 && r > 0.925) { 
                    if (Math.random() > 0.5) {
                        enemy.type = 3; // Normal Ranged
                        enemy.health = (15 + (level * 5)) * hpMult * globalHpReduction;
                        enemy.speed = 3.0 * speedMult;
                        enemy.radius = 0.8;
                        enemy.scale = 1.0; 
                    } else {
                        // MODIFIED: Slow Ranged (Type 6)
                        enemy.type = 6;
                        enemy.health = (20 + (level * 6)) * hpMult * globalHpReduction;
                        enemy.speed = 2.0 * speedMult;
                        enemy.radius = 0.8;
                        enemy.scale = 1.1;
                    }
                } 
                // MODIFIED: Speedy Monster (Type 4) - 50% HP, 2x Speed
                else if (wave >= 2 && r > 0.85) { 
                    enemy.type = 4;
                    const baseHp = (10 + (level * 4)) * hpMult * globalHpReduction;
                    enemy.health = baseHp * 0.5;
                    const baseSpeed = (4 + (level * 0.15)) * speedMult;
                    enemy.speed = baseSpeed * 2.0;
                    enemy.radius = 0.6;
                    enemy.scale = 0.8;
                }
                // Basic Enemy (Type 0)
                else {
                    enemy.type = 0; 
                    enemy.health = (10 + (level * 4)) * hpMult * globalHpReduction;
                    enemy.speed = (4 + (level * 0.15)) * speedMult;
                    enemy.radius = 0.6;
                    enemy.scale = 1.0;
                }
            }
            enemy.maxHealth = enemy.health;
        }
    }

    dotTicker.current += delta;
    const shouldTickDoT = dotTicker.current > 0.5;
    if (shouldTickDoT) dotTicker.current = 0;

    const time = state.clock.getElapsedTime();

    for (let i = 0; i < MAX_ENEMIES; i++) {
        const e = enemies.current[i];
        if (e.active) {
            spatialGrid.current.add(i, e.position.x, e.position.z);

            const distToPlayer = e.position.distanceTo(playerPosition);
            let currentSpeed = e.speed;
            let canMove = true;

            if (e.type === 2) {
                 const currentBossData = useGameStore.getState().bossData;
                 if (Math.abs(currentBossData.hp - e.health) > 5) {
                     setBossData({ hp: e.health });
                 }
            }

            // DoT Logic
            if (e.burnTimer && e.burnTimer > 0) {
                e.burnTimer -= delta;
                if (shouldTickDoT) {
                    const dmg = (e.burnDamage || 5) * 0.5;
                    e.health -= dmg;
                    window.dispatchEvent(new CustomEvent('damage', { detail: { position: e.position, damage: dmg, isDoT: true, damageType: 'FIRE' } }));
                }
            }
            if (e.poisonTimer && e.poisonTimer > 0) {
                e.poisonTimer -= delta;
                if (shouldTickDoT) {
                    const dmg = (e.poisonDamage || 3) * 0.5;
                    e.health -= dmg;
                    window.dispatchEvent(new CustomEvent('damage', { detail: { position: e.position, damage: dmg, isDoT: true, damageType: 'POISON' } }));
                }
            }

            if (e.freezeTimer && e.freezeTimer > 0) {
                e.freezeTimer -= delta;
                canMove = false;
                if (stunIconsRef.current) {
                    dummy.position.copy(e.position).add(tempVec.set(0, (e.scale * 1.8) + 0.5, 0)); 
                    dummy.rotation.set(time * 5, time * 3, 0);
                    dummy.scale.set(0.5, 0.5, 0.5);
                    dummy.updateMatrix();
                    stunIconsRef.current.setMatrixAt(i, dummy.matrix);
                } 
            } else {
                if (stunIconsRef.current) {
                    dummy.position.set(0, -100, 0);
                    dummy.updateMatrix();
                    stunIconsRef.current.setMatrixAt(i, dummy.matrix);
                }
            }

            if (e.slowTimer && e.slowTimer > 0) {
                e.slowTimer -= delta;
                currentSpeed *= (1 - (e.slowFactor || 0.5));
            }

            // --- COLOR LOGIC ---
            if (e.freezeTimer && e.freezeTimer > 0) tempColor.set('#3b82f6');
            else if (e.burnTimer && e.burnTimer > 0) tempColor.set('#ef4444');
            else {
                if (e.type === 2) tempColor.set(COLORS.enemyBoss);
                else if (e.type === 3) tempColor.set(COLORS.enemyShooter);
                else if (e.type === 4) tempColor.set(COLORS.enemySpeedy); // New Color
                else if (e.type === 5) tempColor.set(COLORS.enemyEliteShooter); // New Color
                else if (e.type === 6) tempColor.set(COLORS.enemySlowShooter); // New Color
                else if (e.type === 1) {
                     if (e.scale > 1.4) tempColor.set(COLORS.enemyElite);
                     else tempColor.set(COLORS.enemyOrc);
                }
                else tempColor.set(COLORS.enemySlime);

                if (e.poisonTimer && e.poisonTimer > 0) tempColor.lerp(new Color('#4ade80'), 0.5);
            }

            meshRef.current.setColorAt(i, tempColor);

            if (canMove) {
                let moved = false;
                // Blackhole & Earthwall logic ...
                for(let b=0; b < activeBullets.length; b++) {
                    const bullet = activeBullets[b];
                    if (bullet.active && bullet.type === 'BLACKHOLE') {
                        const max = bullet.maxPullCount || 8;
                        const current = bullet.currentPullCount || 0;
                        if (current < max && e.position.distanceTo(bullet.position) < 15.0) {
                            pushDir.subVectors(bullet.position, e.position).normalize();
                            e.position.add(pushDir.multiplyScalar(currentSpeed * 2.0 * delta));
                            moved = true;
                            bullet.currentPullCount = current + 1;
                        }
                    }
                }
                if (earthwall.active) {
                    const distToWall = e.position.distanceTo(earthwall.position);
                    if (distToWall < earthwall.radius + e.radius) {
                        pushDir.subVectors(e.position, earthwall.position).normalize();
                        if (pushDir.lengthSq() === 0) pushDir.set(1, 0, 0);
                        e.position.copy(earthwall.position).add(pushDir.multiplyScalar(earthwall.radius + e.radius));
                        moved = true; 
                    }
                }

                if (!moved) {
                    const nextPos = e.position.clone();
                    // Shooters keep distance
                    if ((e.type === 3 || e.type === 5 || e.type === 6) && distToPlayer > 15) { 
                         tempVec.subVectors(playerPosition, e.position).normalize();
                         nextPos.add(tempVec.multiplyScalar(currentSpeed * delta));
                    } else if (e.type === 2 && distToPlayer > 10) { // Boss keeps slight distance
                         tempVec.subVectors(playerPosition, e.position).normalize();
                         nextPos.add(tempVec.multiplyScalar(currentSpeed * delta));
                    } else if (e.type !== 3 && e.type !== 5 && e.type !== 6 && e.type !== 2) {
                         tempVec.subVectors(playerPosition, e.position).normalize();
                         nextPos.add(tempVec.multiplyScalar(currentSpeed * delta));
                    }

                    for(const obs of obstacles) {
                        const distToObs = nextPos.distanceTo(obs.position);
                        const minDist = obs.radius + e.radius;
                        if (distToObs < minDist) {
                            pushDir.subVectors(nextPos, obs.position).normalize();
                            nextPos.copy(obs.position).add(pushDir.multiplyScalar(minDist));
                        }
                    }
                    e.position.copy(nextPos);
                }
            }

            // --- SHOOTING LOGIC ---
            e.stateTimer = (e.stateTimer || 0) + delta;

            // BOSS AI (Bullet Hell)
            if (e.type === 2 && canMove) {
                // Cycle Patterns every 5 seconds
                e.bossTimer = (e.bossTimer || 0) + delta;
                if (e.bossTimer > 5.0) {
                    e.bossTimer = 0;
                    e.bossPattern = ((e.bossPattern || 0) + 1) % 3;
                }

                const pattern = e.bossPattern || 0;

                // Pattern 0: Spiral
                if (pattern === 0) {
                    if (e.stateTimer > 0.05) { // Rapid fire
                        e.stateTimer = 0;
                        e.bossAngle = (e.bossAngle || 0) + 0.3;
                        const bullet = enemyBulletsDataRef.current.find(b => !b.active);
                        if (bullet) {
                            bullet.active = true;
                            bullet.lifetime = 4.0;
                            bullet.damage = 15; // Moderate dmg
                            bullet.position.copy(e.position).add(new Vector3(0, 1.5, 0));
                            bullet.velocity.set(Math.cos(e.bossAngle), 0, Math.sin(e.bossAngle)).multiplyScalar(10);
                        }
                    }
                } 
                // Pattern 1: Nova (Bursts)
                else if (pattern === 1) {
                     if (e.stateTimer > 0.8) {
                        e.stateTimer = 0;
                        for(let k=0; k<12; k++) {
                            const bullet = enemyBulletsDataRef.current.find(b => !b.active);
                            if (bullet) {
                                bullet.active = true;
                                bullet.lifetime = 4.0;
                                bullet.damage = 15;
                                bullet.position.copy(e.position).add(new Vector3(0, 1.5, 0));
                                const a = (Math.PI * 2 * k) / 12;
                                bullet.velocity.set(Math.cos(a), 0, Math.sin(a)).multiplyScalar(8);
                            }
                        }
                     }
                }
                // Pattern 2: Targeted Stream
                else if (pattern === 2) {
                    if (e.stateTimer > 0.15) {
                        e.stateTimer = 0;
                        const bullet = enemyBulletsDataRef.current.find(b => !b.active);
                        if (bullet) {
                            bullet.active = true;
                            bullet.lifetime = 4.0;
                            bullet.damage = 20; // High dmg
                            bullet.position.copy(e.position).add(new Vector3(0, 1.5, 0));

                            tempVec.subVectors(playerPosition, e.position).normalize();
                            // Slight spread
                            const spread = (Math.random() - 0.5) * 0.3;
                            tempVec.applyAxisAngle(new Vector3(0,1,0), spread);
                            bullet.velocity.copy(tempVec).multiplyScalar(14);
                        }
                    }
                }
            }
            // Standard Shooters
            else if ((e.type === 3 || e.type === 5 || e.type === 6) && canMove) {
                // Fire rate check
                const fireRate = e.type === 5 ? 1.5 : (e.type === 6 ? 3.0 : 2.0); // Elite faster, Slow slower

                if (e.stateTimer > fireRate && distToPlayer < 25) {
                    e.stateTimer = 0;

                    // Type 5: Elite Shooter (Spread)
                    if (e.type === 5) {
                        const baseDir = new Vector3().subVectors(playerPosition, e.position).normalize();
                        for(let k=-1; k<=1; k++) {
                             const bullet = enemyBulletsDataRef.current.find(b => !b.active);
                             if (bullet) {
                                bullet.active = true;
                                bullet.lifetime = 3.0;
                                bullet.damage = 10;
                                bullet.position.copy(e.position).add(new Vector3(0, 1, 0));
                                const dir = baseDir.clone().applyAxisAngle(new Vector3(0,1,0), k * 0.3);
                                bullet.velocity.copy(dir).multiplyScalar(12);
                             }
                        }
                    }
                    // Type 6: Slow Shooter (50% Dmg, Slow speed)
                    else if (e.type === 6) {
                        const bullet = enemyBulletsDataRef.current.find(b => !b.active);
                        if (bullet) {
                            bullet.active = true;
                            bullet.lifetime = 6.0; // Longer life for slow bullets
                            bullet.damage = 5; // 50% dmg
                            bullet.position.copy(e.position).add(new Vector3(0, 1, 0));
                            pushDir.subVectors(playerPosition, e.position).normalize();
                            bullet.velocity.copy(pushDir).multiplyScalar(6); // Very slow
                        }
                    }
                    // Type 3: Normal Shooter
                    else {
                        const bullet = enemyBulletsDataRef.current.find(b => !b.active);
                        if (bullet) {
                            bullet.active = true;
                            bullet.lifetime = 3.0;
                            bullet.damage = 10;
                            bullet.position.copy(e.position).add(new Vector3(0, 1, 0));
                            pushDir.subVectors(playerPosition, e.position).normalize();
                            bullet.velocity.copy(pushDir).multiplyScalar(15);
                        }
                    }
                }
            }

            // Collision Damage (Melee)
            if (e.type !== 3 && e.type !== 5 && e.type !== 6 && distToPlayer < e.radius + 0.5 && canMove) {
                const dmg = (e.type === 2 ? 30 : 10) * (1 + wave * 0.1); 
                takeDamage(dmg * delta);
            }

            if (e.health <= 0) {
                e.active = false;

                let goldDrops = 0;
                if (e.type === 2) goldDrops = 10; 
                else if (e.type === 1 || e.type === 5) goldDrops = 3; 
                else if (Math.random() < 0.5) goldDrops = 1; 

                for(let g=0; g<goldDrops; g++) {
                    const offset = tempVec.set((Math.random()-0.5), 0, (Math.random()-0.5));
                    spawnDrop(e.position.clone().add(offset), 'GOLD', 10);
                }

                addScore(0); 

                if (e.type === 2) { // Boss Death
                    setBossData({ active: false });
                    const roll = Math.random();
                    let dropped = false;
                    if (wave >= 60 && roll < Math.min(0.20, (wave - 50) * 0.01)) { spawnDrop(e.position, 'ITEM', 0, 'MYTHIC'); dropped = true; }
                    if (!dropped && wave >= 30 && Math.random() < Math.min(0.50, (wave - 20) * 0.02)) { spawnDrop(e.position, 'ITEM', 0, 'LEGENDARY'); dropped = true; }
                    if (!dropped) spawnDrop(e.position, 'ITEM', 0, 'EPIC');
                    spawnDrop(e.position.clone().add(tempVec.set(1,0,0)), 'XP', 1000); 
                } 
                else if (e.type === 1 || e.type === 5) { // Elite Death
                     if (Math.random() > 0.5) spawnDrop(e.position, 'ITEM', 0); 
                     for(let k=0; k<5; k++) {
                         const offset = tempVec.set((Math.random()-0.5)*2, 0, (Math.random()-0.5)*2);
                         spawnDrop(e.position.clone().add(offset), 'XP', 100);
                     }
                }
                else {
                    if (Math.random() > 0.90) spawnDrop(e.position, 'ITEM', 0);
                    else spawnDrop(e.position, 'XP', e.type >= 3 ? 30 : 20);
                }
                dummy.position.set(0, -100, 0);
                if (stunIconsRef.current) stunIconsRef.current.setMatrixAt(i, dummy.matrix);
            } else {
                dummy.position.copy(e.position);
                const aestheticHeight = 2.0; 
                const aestheticWidth = 0.6;

                if (e.type === 0 && e.scale < 0.9) {
                    dummy.scale.set(e.scale, e.scale * 0.5, e.scale); 
                } else {
                    dummy.scale.set(e.scale * aestheticWidth, e.scale * aestheticHeight, e.scale * aestheticWidth);
                }

                const totalHeight = 1.0 * dummy.scale.y;
                if (e.type !== 2) {
                    const bob = Math.abs(Math.sin(state.clock.elapsedTime * 5 + i)) * 0.2;
                    dummy.position.y = (totalHeight / 2) + bob;
                } else {
                    dummy.position.y = totalHeight / 2;
                }
                dummy.lookAt(playerPosition);
            }
        } else {
            dummy.position.set(0, -100, 0);
            if (stunIconsRef.current) stunIconsRef.current.setMatrixAt(i, dummy.matrix);
        }

        dummy.updateMatrix();
        meshRef.current.setMatrixAt(i, dummy.matrix);
    }

    meshRef.current.instanceMatrix.needsUpdate = true;
    if (meshRef.current.instanceColor) meshRef.current.instanceColor.needsUpdate = true;
    if (stunIconsRef.current) stunIconsRef.current.instanceMatrix.needsUpdate = true;

    minimapThrottle.current += 1;
    if (minimapThrottle.current > 10) {
        minimapThrottle.current = 0;
        const activeEnemies = enemies.current.filter(e => e.active).map(e => ({ x: e.position.x, z: e.position.z, type: e.type }));
        updateMinimapEnemies(activeEnemies);
    }
  });

  return (
    <>
        <instancedMesh ref={meshRef} args={[undefined, undefined, MAX_ENEMIES]} frustumCulled={false}>
            <boxGeometry args={[1, 1, 1]} />
            <meshStandardMaterial vertexColors roughness={0.5} metalness={0.2} />
        </instancedMesh>
        <instancedMesh ref={stunIconsRef} args={[undefined, undefined, MAX_ENEMIES]} frustumCulled={false}>
            <torusGeometry args={[0.5, 0.1, 8, 16]} />
            <meshBasicMaterial color="#facc15" />
        </instancedMesh>
    </>
  );
};

import React, { useRef, useState } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import { Html } from '@react-three/drei';
import { Vector3, InstancedMesh, Mesh, Raycaster, Plane } from 'three';
import { useGameStore } from '../store';
import { COLORS, PLAYER_RADIUS, ARENA_SIZE } from '../constants';
import { BulletManager } from './BulletManager';
import { GameStatus, BulletData, EnemyData } from '../types';
import { SpatialHashGrid } from '../utils/SpatialHashGrid';

interface PlayerProps {
  bulletsDataRef: React.MutableRefObject<BulletData[]>;
  enemyBulletsDataRef: React.MutableRefObject<BulletData[]>;
  targetPosRef: React.MutableRefObject<Vector3>;
  // New props
  enemiesDataRef: React.MutableRefObject<EnemyData[]>;
  spatialGrid?: React.MutableRefObject<SpatialHashGrid>;
}

export const Player: React.FC<PlayerProps> = ({ bulletsDataRef, enemyBulletsDataRef, targetPosRef, enemiesDataRef, spatialGrid }) => {
  const meshRef = useRef<any>(null);
  const axeSpinRef = useRef<any>(null);

  const { stats, status, setPlayerPosition, skills, triggerSkillCooldown, tickCooldowns, takeDamage, equipment, useMana, triggerInvincibility, obstacles, crates, isInvincible, toggleInventory, breakCrate, hero, levelUpVisualTimer, health, mana, level, activeAbilityQ, activateRage, rageMode, skillLevels, activateEarthwall, activateWarVitality, activateSprint, reviveAnimTimer } = useGameStore();
  const { camera, scene, raycaster, pointer } = useThree();

  const [pos] = useState(new Vector3(0, 0, 0));
  const [velocity] = useState(new Vector3(0, 0, 0));
  const [keys, setKeys] = useState<{ [key: string]: boolean }>({});

  const groundPlane = new Plane(new Vector3(0, 1, 0), 0);

  const dashVelocity = useRef(new Vector3());
  const dashTime = useRef(0);
  const axeSpinTime = useRef(0);
  const axeDamageTimer = useRef(0);
  const arrowRainState = useRef({ active: false, wavesLeft: 0, timer: 0 });

  React.useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        if (e.code === 'Space') e.preventDefault(); 
        setKeys((k) => ({ ...k, [e.code]: true }));
        if (e.code === 'KeyI') toggleInventory();
    };
    const handleKeyUp = (e: KeyboardEvent) => setKeys((k) => ({ ...k, [e.code]: false }));
    const handleMouseDown = (e: MouseEvent) => {
        if (e.button === 2) setKeys((k) => ({ ...k, 'RightClick': true })); 
    };
    const handleMouseUp = (e: MouseEvent) => {
        if (e.button === 2) setKeys((k) => ({ ...k, 'RightClick': false }));
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    window.addEventListener('mousedown', handleMouseDown);
    window.addEventListener('mouseup', handleMouseUp);
    window.addEventListener('contextmenu', (e) => e.preventDefault());

    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
      window.removeEventListener('mousedown', handleMouseDown);
      window.removeEventListener('mouseup', handleMouseUp);
      window.removeEventListener('contextmenu', (e) => e.preventDefault());
    };
  }, [toggleInventory]);

  const spawnBullet = (type: any, speed: number, damageMult: number, overrides: Partial<BulletData> = {}) => {
      const bullet = bulletsDataRef.current.find(b => !b.active);
      if (bullet) {
          bullet.active = true;
          bullet.lifetime = overrides.lifetime || 3.0;
          let aimDir = new Vector3().subVectors(targetPosRef.current, pos).normalize();

          if (type === 'BLACKHOLE') {
              bullet.position.copy(pos).add(aimDir.clone().multiplyScalar(15.0)).add(new Vector3(0, 1.5, 0));
              bullet.velocity.set(0, 0, 0); 
          } else {
              bullet.position.copy(pos).add(new Vector3(0, 1.5, 0));
              bullet.velocity.copy(aimDir).multiplyScalar(speed);
          }

          bullet.type = type;
          bullet.pierce = overrides.pierce || 1;
          bullet.damageMultiplier = damageMult * stats.skillDamage * 2.0; 
          bullet.hitIds = [];
          if (overrides.knockback) bullet.knockback = overrides.knockback;
          if (overrides.effect) bullet.effect = overrides.effect;
          if (overrides.trailTimer !== undefined) bullet.trailTimer = overrides.trailTimer;
          if (overrides.maxPullCount) bullet.maxPullCount = overrides.maxPullCount;

          return bullet;
      }
      return null;
  };

  const handleAbility = (ability: string, isQ: boolean) => {
      if (useMana(30)) {
          triggerSkillCooldown(isQ ? 'q' : 'r');

          if (ability === 'RAGE') {
              activateRage();
          } else if (ability === 'PIERCING_SHOT') {
              spawnBullet('PIERCING_ARROW', 50, 2.5, { pierce: 99, knockback: 2.0, lifetime: 3.0 });
          } else if (ability === 'GRAVITY_SPELL') {
              const limit = 8 + (skillLevels.gravity * 1);
              spawnBullet('BLACKHOLE', 0, 5.0, { pierce: 99, lifetime: 2.6, trailTimer: 0.1, maxPullCount: limit }); 
          } else if (ability === 'ARROW_RAIN') {
              arrowRainState.current.active = true;
              arrowRainState.current.wavesLeft = 3;
              arrowRainState.current.timer = 0; 
          } else if (ability === 'FIREBALL') {
              spawnBullet('FIREBALL', 5, 2.0 * 0.63, { 
                  pierce: 100, 
                  lifetime: 5.0, 
                  effect: { type: 'BURN', duration: 5, value: stats.damage * 0.3 } 
              });
          } else if (ability === 'AXE_SPIN') {
              axeSpinTime.current = 3.0;
              axeDamageTimer.current = 0.2; 
          }
      }
  };

  const handleSkillE = () => {
      if (skillLevels.special <= 0) return;
      if (skills.e > 0) return;

      const manaCost = 20; 
      if (useMana(manaCost)) {
          triggerSkillCooldown('e');
          if (hero === 'BARBARIAN') {
              activateWarVitality();
          } else if (hero === 'WIZARD') {
              activateEarthwall(pos.clone());
          } else if (hero === 'ARCHER') {
              activateSprint();
          }
      }
  };

  useFrame((state, delta) => {
    if (status !== GameStatus.PLAYING) return;
    if (!meshRef.current) return;

    tickCooldowns(delta);

    raycaster.setFromCamera(pointer, camera);
    const target = new Vector3();
    raycaster.ray.intersectPlane(groundPlane, target);
    targetPosRef.current.copy(target); 

    const moveDir = new Vector3(0, 0, 0);
    if (keys['KeyW'] || keys['ArrowUp']) moveDir.z -= 1;
    if (keys['KeyS'] || keys['ArrowDown']) moveDir.z += 1;
    if (keys['KeyA'] || keys['ArrowLeft']) moveDir.x -= 1;
    if (keys['KeyD'] || keys['ArrowRight']) moveDir.x += 1;
    moveDir.normalize();

    if (keys['KeyQ'] && skills.q <= 0 && activeAbilityQ) {
        handleAbility(activeAbilityQ, true);
    }

    if ((keys['KeyR'] || keys['RightClick']) && skills.r <= 0) {
        const ability = equipment.weapon?.ability;
        if (ability) {
            handleAbility(ability, false);
        }
    }

    if (keys['KeyE']) {
        handleSkillE();
    }

    if (arrowRainState.current.active) {
        arrowRainState.current.timer -= delta;
        if (arrowRainState.current.timer <= 0) {
            const count = 12; 
            const angleOffset = (3 - arrowRainState.current.wavesLeft) * (Math.PI / 8); 

            for (let i = 0; i < count; i++) {
                const bullet = bulletsDataRef.current.find(b => !b.active);
                if (bullet) {
                    bullet.active = true;
                    bullet.lifetime = 1.0;
                    bullet.position.copy(pos).add(new Vector3(0, 1, 0));
                    const angle = (Math.PI * 2 * i) / count + angleOffset;
                    bullet.velocity.set(Math.cos(angle), 0, Math.sin(angle)).multiplyScalar(25);
                    bullet.type = 'ARROW';
                    bullet.pierce = 3; 
                    bullet.damageMultiplier = 1.5 * 0.63 * stats.skillDamage * 2.0; 
                    bullet.knockback = 3.0; 
                }
            }
            arrowRainState.current.wavesLeft--;
            arrowRainState.current.timer = 0.2; 
            if (arrowRainState.current.wavesLeft <= 0) arrowRainState.current.active = false;
        }
    }

    if (axeSpinTime.current > 0) {
        axeSpinTime.current -= delta;
        axeDamageTimer.current += delta;
        if (axeSpinRef.current) {
            axeSpinRef.current.visible = true;
            axeSpinRef.current.rotation.y += delta * 20; 
            const barrierRadius = 7.0; 
            const damageRange = 8.0;

            const tickRate = 0.2; 
            if (axeDamageTimer.current >= tickRate) {
                 const tickDamage = stats.damage * tickRate * 5 * stats.skillDamage * 2.0 * 0.63; 
                 axeDamageTimer.current = 0;
                 // Optimized: Use enemiesDataRef
                 const enemies = enemiesDataRef.current;
                 for (let i = 0; i < enemies.length; i++) {
                    const enemy = enemies[i];
                    if (!enemy.active) continue;
                    const dist = enemy.position.distanceTo(pos);
                    if (dist < damageRange) {
                        enemy.health -= tickDamage;
                        window.dispatchEvent(new CustomEvent('damage', { 
                            detail: { position: enemy.position, damage: tickDamage, isCrit: false, isPlayer: false } 
                        }));
                    }
                 }
            }
            // Push enemies away
            const enemies = enemiesDataRef.current;
            for (let i = 0; i < enemies.length; i++) {
                const enemy = enemies[i];
                if (!enemy.active) continue;
                const dist = enemy.position.distanceTo(pos);
                if (dist < barrierRadius) {
                        const pushDir = new Vector3().subVectors(enemy.position, pos).normalize();
                        enemy.position.copy(pos).add(pushDir.multiplyScalar(barrierRadius));
                }
            }
        }
    } else if (axeSpinRef.current) {
        axeSpinRef.current.visible = false;
    }

    if (keys['Space'] && skills.dash <= 0) {
        if (useMana(5)) {
            triggerSkillCooldown('dash');
            dashTime.current = 0.2; 
            dashVelocity.current.copy(moveDir.length() > 0 ? moveDir.normalize() : new Vector3(0, 0, -1).applyQuaternion(meshRef.current.quaternion));
            dashVelocity.current.multiplyScalar(40); 
            triggerInvincibility(0.2);
        }
    }

    if (dashTime.current > 0) {
        dashTime.current -= delta;
        velocity.copy(dashVelocity.current);
    } else {
        velocity.lerp(moveDir.multiplyScalar(stats.moveSpeed), delta * 8);
    }

    const proposedPos = pos.clone().add(velocity.clone().multiplyScalar(delta));
    proposedPos.y = 0;

    for (const obs of obstacles) {
        const dist = proposedPos.distanceTo(obs.position);
        const minDistance = obs.radius + 0.4; 
        if (dist < minDistance) {
            const dir = new Vector3().subVectors(proposedPos, obs.position).normalize();
            proposedPos.copy(obs.position).add(dir.multiplyScalar(minDistance));
        }
    }

    for (const crate of crates) {
        if (crate.active) {
            const dist = proposedPos.distanceTo(crate.position);
            const minDistance = 0.7 + 0.4;
            if (dist < minDistance) {
                breakCrate(crate.id);
            }
        }
    }

    const limit = (ARENA_SIZE / 2) - 2;
    if (proposedPos.length() > limit) {
        proposedPos.normalize().multiplyScalar(limit);
    }
    proposedPos.y = 0;

    pos.copy(proposedPos);
    meshRef.current.position.copy(pos);
    setPlayerPosition(pos.clone());

    meshRef.current.lookAt(targetPosRef.current);

    const enemyBullets = enemyBulletsDataRef.current;
    if (dashTime.current <= 0) { 
        for(let i = 0; i < enemyBullets.length; i++) {
            const b = enemyBullets[i];
            if (b.active && b.position.distanceTo(pos) < PLAYER_RADIUS + 0.5) { 
                // MODIFIED: Read bullet specific damage, default to 10 if not set
                const dmg = b.damage || 10;
                takeDamage(dmg);
                b.active = false;
                window.dispatchEvent(new CustomEvent('damage', { 
                    detail: { position: pos, damage: dmg, isCrit: false, isPlayer: true } 
                }));
            }
        }
    }

    const targetCamPos = new Vector3(pos.x, 35, pos.z + 28);
    camera.position.lerp(targetCamPos, delta * 4);
    camera.lookAt(pos.x, 0, pos.z);
  });

  const hpPercent = Math.max(0, health / stats.maxHealth) * 100;
  const mpPercent = Math.max(0, mana / stats.maxMana) * 100;

  return (
    <>
      <BulletManager 
          playerPos={pos} 
          targetPosRef={targetPosRef} 
          bulletsDataRef={bulletsDataRef}
          projectileType={equipment.weapon?.projectileType}
          enemiesDataRef={enemiesDataRef}
          spatialGrid={spatialGrid}
      />

      <group ref={meshRef} position={[0, 1, 0]}>

        <Html position={[0, -1.2, 0]} center style={{ pointerEvents: 'none' }} zIndexRange={[0, 0]}>
            <div className="flex items-center gap-2" style={{ opacity: 0.8 }}>
                <div className="w-8 h-8 rounded-full bg-slate-900 border-2 border-slate-500 flex items-center justify-center shadow-lg">
                    <span className="text-white font-bold text-sm">{level}</span>
                </div>
                <div className="flex flex-col gap-1 w-16">
                    <div className="h-1.5 w-full bg-slate-800 rounded-full overflow-hidden border border-slate-600">
                        <div className="h-full bg-red-500 transition-all duration-100" style={{ width: `${hpPercent}%` }} />
                    </div>
                    <div className="h-1.5 w-full bg-slate-800 rounded-full overflow-hidden border border-slate-600">
                        <div className="h-full bg-blue-500 transition-all duration-100" style={{ width: `${mpPercent}%` }} />
                    </div>
                </div>
            </div>
        </Html>

        {levelUpVisualTimer > 0 && (
            <>
                <Html position={[0, 2.5, 0]} center zIndexRange={[100, 0]}>
                    <div className="text-yellow-400 font-black text-2xl drop-shadow-[0_2px_2px_rgba(0,0,0,0.8)] animate-bounce whitespace-nowrap">
                        LEVEL UP!
                    </div>
                </Html>
                <mesh position={[0, 0.5, 0]} scale={[2, 4, 2]}>
                    <cylinderGeometry args={[0.5, 0.5, 1, 16]} />
                    <meshBasicMaterial color="#facc15" transparent opacity={levelUpVisualTimer * 0.5} depthWrite={false} side={2} />
                </mesh>
            </>
        )}

        {reviveAnimTimer > 0 && (
            <mesh position={[0, 0, 0]}>
                <cylinderGeometry args={[2, 2, 20, 16, 1, true]} />
                <meshBasicMaterial 
                    color="#fef3c7" 
                    transparent 
                    opacity={Math.min(1, reviveAnimTimer) * 0.6} 
                    depthWrite={false} 
                    side={2} 
                    blending={2} 
                />
            </mesh>
        )}

        {rageMode && (
            <mesh position={[0, 0.5, 0]}>
                <sphereGeometry args={[1.0, 16, 16]} />
                <meshBasicMaterial color="red" wireframe transparent opacity={0.3} />
            </mesh>
        )}

        <mesh visible={isInvincible}>
            <sphereGeometry args={[1.2, 16, 16]} />
            <meshStandardMaterial color="orange" transparent opacity={0.4} emissive="orange" emissiveIntensity={0.5} />
        </mesh>

        <group position={[0, 0, 0]}>
            <mesh castShadow receiveShadow position={[0, 0.5, 0]}>
                <capsuleGeometry args={[0.4, 1, 4, 8]} />
                <meshStandardMaterial 
                    color={rageMode ? 'red' : (levelUpVisualTimer > 0 ? '#facc15' : COLORS.player)} 
                    emissive={rageMode ? '#991b1b' : (levelUpVisualTimer > 0 ? '#facc15' : 'black')}
                    emissiveIntensity={rageMode ? 1 : levelUpVisualTimer}
                    roughness={0.4} metalness={0.6} 
                />
            </mesh>
            <mesh castShadow position={[0, 1.4, 0]}>
                <boxGeometry args={[0.5, 0.5, 0.5]} />
                <meshStandardMaterial color="#cbd5e1" metalness={0.8} roughness={0.2} />
            </mesh>
            <mesh position={[0.6, 0.5, 0.4]}>
                <boxGeometry args={[0.2, 0.2, 0.8]} />
                <meshStandardMaterial color="#94a3b8" />
            </mesh>
            <mesh position={[0, 0.6, -0.4]} rotation={[0.2, 0, 0]}>
                <boxGeometry args={[0.6, 1.2, 0.1]} />
                <meshStandardMaterial color="#1e40af" />
            </mesh>
        </group>

        <group ref={axeSpinRef} visible={false}>
            {[0, 1, 2, 3].map((i) => (
                <group key={i} rotation={[0, (i / 4) * Math.PI * 2, 0]}>
                    <mesh position={[7, 0, 0]}>
                        <boxGeometry args={[2.5, 0.25, 2.5]} /> 
                        <meshStandardMaterial color="#ef4444" emissive="#7f1d1d" emissiveIntensity={0.5} />
                    </mesh>
                </group>
            ))}
        </group>

        {hero === 'WIZARD' && (
            <group position={[0, 1.7, 0]}>
                <mesh position={[0, -0.1, 0]}>
                    <cylinderGeometry args={[0.6, 0.6, 0.05, 12]} />
                    <meshStandardMaterial color="#3b82f6" roughness={0.8} />
                </mesh>
                <mesh position={[0, 0.3, 0]}>
                    <coneGeometry args={[0.4, 0.8, 12]} />
                    <meshStandardMaterial color="#1e3a8a" roughness={0.8} />
                </mesh>
            </group>
        )}
      </group>
    </>
  );
};

