            { ...ITEMS_POOL.find(i => i.id === 'potion_mana')!, id: `start_mana_${Math.random()}`, quantity: 10 },
            { ...ITEMS_POOL.find(i => i.id === 'revive_ankh')!, id: `start_revive_${Math.random()}`, quantity: 1 },
