        isShopOpen: false,
        isCharacterSheetOpen: false,
        isCodexOpen: false,
        potionCooldown: 0,
        barrierCooldown: 0,
        isInvincible: false,
        invincibilityTimer: 0,
        levelUpVisualTimer: 0,
        reviveAnimTimer: 0,
        bossData: { active: false, name: '', hp: 0, maxHp: 0 },
        notifications: [],
        rageMode: false,
        rageTimer: 0,
        earthwall: { active: false, position: new Vector3(), timer: 0, radius: 10.0 },
        warVitalityTimer: 0,
        sprintTimer: 0,
        lastInventoryFullNotification: 0,
        maxInventorySlots: INVENTORY_LIMIT,
        materials: state.materials,
        petReviveCooldown: 0,
      });
  },

  addScore: (amount) => set((state) => ({ score: state.score + amount })),
  addGems: (amount) => set((state) => ({ gems: state.gems + amount })),

  addExperience: (amount) => {
    // ... same as before
    const { experience, experienceToNextLevel, level } = get();
    const finalAmount = (level >= 10 ? amount * 2 : amount) * 2; 
    let newExp = experience + finalAmount;

    if (newExp >= experienceToNextLevel) {
      const multiplier = level < 10 ? 1.35 : 1.10;
      const nextReq = Math.floor(experienceToNextLevel * multiplier);
      const currentBase = get().baseStats;
      const newBase = {
          ...currentBase,
          maxHealth: currentBase.maxHealth + 5, // HP Increase Halved from 10 to 5
          maxMana: currentBase.maxMana + 5,
          damage: currentBase.damage + 1,
          defense: currentBase.defense + 0.5
      };

      set({
        experience: newExp - experienceToNextLevel,
        experienceToNextLevel: nextReq,
        level: level + 1,
        skillPoints: get().skillPoints + 1,
        baseStats: newBase,
        stats: calculateStats(newBase, get().equipment, get().rageMode, get().sprintTimer > 0),
        health: get().health, 
        mana: get().mana, 
        levelUpVisualTimer: 1.0 
      });
    } else {
      set({ experience: newExp });
    }
  },

  takeDamage: (amount) => {
    const state = get();
    // BUG FIX: Prevent repeated calls if already dead or invalid state
    if (state.status !== GameStatus.PLAYING || state.isInvincible || state.health <= 0) return;

    // Dodge
    if (state.stats.dodge > 0 && Math.random() < state.stats.dodge) {
        return; 
    }

    if (state.skillLevels.barrier > 0 && state.barrierCooldown <= 0) {
         const barrierLevel = state.skillLevels.barrier;
         const duration = 1.0 + (barrierLevel * 0.2); 
         const cooldown = Math.max(5, 12 - barrierLevel); 
         get().triggerInvincibility(duration);
         const knockbackRadius = 10 + (barrierLevel * 2);
         const knockbackForce = 5 + (barrierLevel);
         window.dispatchEvent(new CustomEvent('barrier-trigger', {
             detail: { position: state.playerPosition, radius: knockbackRadius, force: knockbackForce }
         }));
         set({ barrierCooldown: cooldown });
         return; 
    }

    const reductionMultiplier = 100 / (100 + state.stats.defense);
    const actualDamage = Math.max(1, amount * reductionMultiplier);
    const newHealth = Math.max(0, state.health - actualDamage);

    window.dispatchEvent(new CustomEvent('damage', { 
        detail: { position: state.playerPosition, damage: actualDamage, isCrit: false, isPlayer: true } 
    }));

    if (newHealth <= 0) {
      // 1. Check Pet Revive
      if (state.equipment.pet && state.equipment.pet.petSkill === 'REVIVE' && state.petReviveCooldown <= 0) {
          set({
              health: state.stats.maxHealth * 0.5,
              petReviveCooldown: state.equipment.pet.petCooldown || 300,
              reviveAnimTimer: 2.0 // Trigger visual
          });
          get().triggerInvincibility(5.0); // 5s Invincibility
          get().addNotification("PHOENIX REVIVE!", COLORS.rarityLegendary, 'SYSTEM');
          return;
      }

      // 2. Check Inventory Revive Item
      const reviveIndex = state.inventory.findIndex(i => i.type === 'REVIVE');
      if (reviveIndex !== -1) {
          const reviveItem = state.inventory[reviveIndex];
          const newInv = [...state.inventory];
          if ((reviveItem.quantity || 1) > 1) {
              newInv[reviveIndex].quantity = (reviveItem.quantity || 1) - 1;
          } else {
              newInv.splice(reviveIndex, 1);
          }
          set({
              health: state.stats.maxHealth * 0.5,
              inventory: newInv,
              reviveAnimTimer: 2.0 // Trigger visual
          });
          get().triggerInvincibility(5.0); // 5s Invincibility
          get().addNotification("REVIVED BY GEM!", COLORS.rarityEpic, 'SYSTEM');
          return;
      }

      // UPDATE STATISTICS ON GAME OVER
      const newStats = { ...state.gameStats };
      newStats.totalRuns++;
      newStats.classRuns[state.hero]++;

      const currentTotalCP = calculateTotalCP(state.stats);
      if (currentTotalCP > newStats.highestCP) newStats.highestCP = currentTotalCP;

      if (state.wave > newStats.classHighestWave[state.hero]) {
          newStats.classHighestWave[state.hero] = state.wave;
      }

      if (state.wave > newStats.highestWave) {
          newStats.highestWave = state.wave;
          newStats.bestRunClass = state.hero;
      }

      set({ 
          health: 0, 
          status: GameStatus.GAME_OVER,
          recentRuns: [state.wave, ...state.recentRuns.slice(0, 4)],
          score: state.score + state.accumulatedWaveGold,
          gameStats: newStats
      });
    } else {
      set({ health: newHealth });
    }
  },

  // ... (rest of methods like breakCrate, damageCrate, useMana, heal, restoreMana, setPlayerPosition, setInvincible, triggerInvincibility, spawnDrop, handleInventoryFull, collectDrop, triggerSkillCooldown, activateRage, activateEarthwall, activateWarVitality, activateSprint, updatePassiveCooldowns, advanceWave, setBossData, tickCooldowns)

  breakCrate: (id) => {
    const { crates, spawnDrop } = get();
    const index = crates.findIndex(c => c.id === id);
    if (index === -1) return;
    const crate = crates[index];
    if (!crate.active) return;

    const newCrates = [...crates];
    newCrates[index] = { ...crate, active: false };
    set({ crates: newCrates });

    spawnDrop(crate.position, 'XP', 50);
    const r = Math.random();
    if (r > 0.85) {
        spawnDrop(crate.position.clone().add(new Vector3(1,0,0)), 'ITEM', 0);
    } else if (r > 0.5) {
        spawnDrop(crate.position.clone().add(new Vector3(0.5,0,0.5)), 'GOLD', 10);
    }
  },

  damageCrate: (id, amount) => {
      set((state) => {
          const crateIndex = state.crates.findIndex(c => c.id === id);
          if (crateIndex === -1) return { crates: state.crates };
          const newCrates = [...state.crates];
          const crate = { ...newCrates[crateIndex] };
          if (!crate.active) return { crates: state.crates };

          crate.hp -= amount;
          newCrates[crateIndex] = crate;
          return { crates: newCrates };
      });
      const state = get();
      const crate = state.crates.find(c => c.id === id);
      if (crate && crate.active && crate.hp <= 0) {
          get().breakCrate(id);
      }
  },

  useMana: (amount) => {
      const { mana, hero } = get();
      const actualCost = hero === 'WIZARD' ? Math.ceil(amount * 1.3) : amount;
      if (mana >= actualCost) {
          set({ mana: mana - actualCost });
          return true;
      }
      return false;
  },

  heal: (amount) => set((state) => ({ 
    health: Math.min(state.health + amount, state.stats.maxHealth) 
  })),

  restoreMana: (amount) => set((state) => ({ 
    mana: Math.min(state.mana + amount, state.stats.maxMana) 
  })),

  setPlayerPosition: (pos) => set({ playerPosition: pos }),
  setInvincible: (invincible) => set({ isInvincible: invincible }),

  triggerInvincibility: (duration) => set((state) => ({ 
      invincibilityTimer: Math.max(state.invincibilityTimer, duration),
      isInvincible: true 
  })),

  spawnDrop: (position, type, value, rarityOverride) => set((state) => {
      if (state.drops.length > 99) return { drops: state.drops };

      // Clamp spawn position to arena size (with slight buffer)
      const maxDist = (ARENA_SIZE / 2) - 2;
      const dist = position.length();
      if (dist > maxDist) {
          position.normalize().multiplyScalar(maxDist);
          position.y = 0; // Ensure on ground
      }

      let item = null;
      if (type === 'ITEM') {
          let pool = ITEMS_POOL.filter(i => i.type !== 'PET');
          if (rarityOverride) {
              pool = pool.filter(i => i.rarity === rarityOverride && i.type !== 'POTION' && i.type !== 'CORE');
              if (pool.length === 0) pool = ITEMS_POOL.filter(i => i.type !== 'POTION' && i.type !== 'CORE' && i.type !== 'PET');
          } else {
               const r = Math.random();
               if (r > 0.90) { pool = pool.filter(i => i.type === 'POTION'); } 
               else if (r > 0.60) { pool = pool.filter(i => i.type === 'CORE'); } 
               else { pool = pool.filter(i => (i.rarity === 'COMMON' || i.rarity === 'RARE') && i.type !== 'POTION' && i.type !== 'CORE'); }
          }

          if (pool.length > 0) {
              const hero = get().hero;
              const weightedPool: Item[] = [];
              pool.forEach(p => {
                  weightedPool.push(p); weightedPool.push(p); 
                  if (p.type === 'WEAPON' && p.classType === hero) { weightedPool.push(p); }
              });
              const template = weightedPool[Math.floor(Math.random() * weightedPool.length)];
              item = { ...template, id: Math.random().toString(), stats: { ...template.stats }, onHitEffect: template.onHitEffect }; 
              item.quantity = 1;
              if (item.type === 'WEAPON' || item.type === 'ARMOR' || item.type === 'ACCESSORY') {
                   const plusChance = Math.random();
                   let plus = 0;
                   if (plusChance > 0.95) plus = 3; else if (plusChance > 0.85) plus = 2; else if (plusChance > 0.60) plus = 1;
                   if (plus > 0) {
                       item.level += plus;
                       Object.keys(item.stats).forEach((k) => {
                           const key = k as keyof PlayerStats;
                           const v = item.stats[key]!; // Base Stats (Level 1)
                           const newVal = v * item.level; // Linear Scaling: Base * New Level
                           item.stats[key] = parseFloat(newVal.toFixed(2));
                       });
                   }
              }
          }
      }
      return { drops: [...state.drops, { id: Math.random(), position: position.clone(), type, value, item, active: true, rotation: Math.random() * Math.PI }] };
  }),

  handleInventoryFull: () => {
      const now = Date.now();
      const last = get().lastInventoryFullNotification;
      if (now - last > 10000) { 
          get().addNotification("INVENTORY FULL", "red", "SYSTEM");
          set({ lastInventoryFullNotification: now });
      }
  },

  collectDrop: (id) => set((state) => {
      const drop = state.drops.find(d => d.id === id);
      if (!drop) return { drops: state.drops };

      const newDrops = state.drops.filter(d => d.id !== id);
      const { addExperience, addScore, addGems, addNotification, equipment, level, equipItem } = get();

      if (drop.type === 'ITEM' && drop.item) {
          const item = drop.item;
          const isStackable = item.type === 'POTION' || item.type === 'CORE' || item.type === 'REVIVE';

          if (isStackable) {
              // Find existing stack with space
              const existingStack = state.inventory.find(i => i.name === item.name && (i.quantity || 1) < POTION_STACK_LIMIT);
              if (existingStack) {
                  existingStack.quantity = (existingStack.quantity || 1) + 1;
                  addNotification(`Looted ${item.name} (x1)`, COLORS.rarityCommon, 'ITEM');
                  return { drops: newDrops, inventory: [...state.inventory] };
              }
          }

          // Check inventory limit before adding new item/stack
          if (state.inventory.length >= state.maxInventorySlots) {
              get().handleInventoryFull();
              return { drops: state.drops };
          }

          const rarityColors: Record<string, string> = { 'COMMON': COLORS.rarityCommon, 'RARE': COLORS.rarityRare, 'EPIC': COLORS.rarityEpic, 'LEGENDARY': COLORS.rarityLegendary, 'MYTHIC': COLORS.rarityMythic };
          let action = undefined;
          if (item.type === 'WEAPON' || item.type === 'ARMOR' || item.type === 'ACCESSORY') {
              const slot = item.type.toLowerCase() as keyof typeof equipment;
              const currentEquip = equipment[slot];
              const newCP = calculateItemCP(item);
              const oldCP = currentEquip ? calculateItemCP(currentEquip) : 0;
              let reqLevel = 1;
              if (item.rarity === 'RARE') reqLevel = 5; if (item.rarity === 'EPIC') reqLevel = 10; if (item.rarity === 'LEGENDARY') reqLevel = 15; if (item.rarity === 'MYTHIC') reqLevel = 20;
              const classMatch = !item.classType || item.classType === state.hero;
              if (newCP > oldCP && level >= reqLevel && classMatch) { action = { label: 'EQUIP', onClick: () => get().equipItem(item) }; }
          }

          addNotification(`Looted ${item.name} ${item.level > 1 ? `+${item.level-1}` : ''}`, rarityColors[item.rarity], 'ITEM', action);
          return { drops: newDrops, inventory: [...state.inventory, { ...item, quantity: 1 }] };
      }

      if (drop.type === 'XP') { addExperience(drop.value); } 
      else if (drop.type === 'GOLD') { addScore(drop.value); } 
      else if (drop.type === 'GEM') { addGems(drop.value); } 

      return { drops: newDrops };
  }),

  triggerSkillCooldown: (skill) => set((state) => {
      const cooldown = state.skillMaxCooldowns[skill] * (1 - state.stats.cooldownReduction);
      return { skills: { ...state.skills, [skill]: cooldown } };
  }),

  activateRage: () => set((state) => {
      const newStats = calculateStats(state.baseStats, state.equipment, true, state.sprintTimer > 0);
      return { rageMode: true, rageTimer: 4.0, stats: newStats };
  }),

  activateEarthwall: (pos) => set((state) => ({ 
      earthwall: { active: true, position: pos, timer: 4.0, radius: 12.0 } // Increased radius to 12
  })),

  activateWarVitality: () => set((state) => ({ warVitalityTimer: 6.0 })),

  activateSprint: () => {
      const state = get();
      const newStats = calculateStats(state.baseStats, state.equipment, state.rageMode, true);
      set({ sprintTimer: 4.0, stats: newStats, invincibilityTimer: Math.max(state.invincibilityTimer, 4.0), isInvincible: true });
  },

  updatePassiveCooldowns: (partial) => set((state) => ({ passiveSkillState: { ...state.passiveSkillState, ...partial } })),

  advanceWave: () => {
      const upgrades = generateUpgradeOptions(get().hero);
      set((state) => ({ 
          wave: state.wave + 1, 
          waveTimer: 0,
          accumulatedWaveGold: state.accumulatedWaveGold + 100,
          status: GameStatus.LEVEL_UP,
          upgradeOptions: upgrades
      }));
  },

  setBossData: (data) => set(state => ({ bossData: { ...state.bossData, ...data } })),

  tickCooldowns: (delta) => {
      const state = get();
      const newSkills = {
          dash: Math.max(0, state.skills.dash - delta),
          q: Math.max(0, state.skills.q - delta),
          r: Math.max(0, state.skills.r - delta),
          e: Math.max(0, state.skills.e - delta),
      };

      let rageTimer = state.rageTimer;
      let rageMode = state.rageMode;
      let sprintTimer = state.sprintTimer;
      let stats = state.stats;

      // Update E Skill Buffs
      let earthwall = { ...state.earthwall };
      if (earthwall.active) {
          earthwall.timer -= delta;
          if (earthwall.timer <= 0) earthwall.active = false;
      }

      let warVitalityTimer = state.warVitalityTimer;
      if (warVitalityTimer > 0) {
          warVitalityTimer -= delta;
          // War Vitality: Regen 10 HP/sec
          const healAmt = 10 * delta;
          if (state.health < state.stats.maxHealth) {
              get().heal(healAmt);
          }
      }

      if (sprintTimer > 0) {
          sprintTimer -= delta;
          if (sprintTimer <= 0) {
              // Stats reset handled below
          }
      }

      // Check Stats Re-calc
      let recalc = false;
      if (rageMode) {
          rageTimer -= delta;
          if (rageTimer <= 0) {
              rageMode = false;
              rageTimer = 0;
              recalc = true;
          }
      }
      if (state.sprintTimer > 0 && sprintTimer <= 0) recalc = true;

      if (recalc) {
          stats = calculateStats(state.baseStats, state.equipment, rageMode, sprintTimer > 0);
      }

      const newBarrierCooldown = Math.max(0, state.barrierCooldown - delta);
      const newLevelUpTimer = Math.max(0, state.levelUpVisualTimer - delta);
      const newReviveAnimTimer = Math.max(0, state.reviveAnimTimer - delta); // Update revive anim
      const newPetReviveCooldown = Math.max(0, state.petReviveCooldown - delta);

      let newInvincibilityTimer = state.invincibilityTimer;
      let newIsInvincible = state.isInvincible;
      if (state.invincibilityTimer > 0) {
          newInvincibilityTimer -= delta;
          if (newInvincibilityTimer <= 0) {
              newInvincibilityTimer = 0;
              newIsInvincible = false;
          } else {
              newIsInvincible = true;
          }
      }

      const regenAmount = (state.stats.regen) * delta;
      const manaRegenAmount = state.stats.manaRegen * delta;
      const newHealth = Math.min(state.stats.maxHealth, state.health + regenAmount);
      const newMana = Math.min(state.stats.maxMana, state.mana + manaRegenAmount);

      let newPotionCD = Math.max(0, state.potionCooldown - delta);
      let newHealthAfterPot = newHealth;
      let newManaAfterPot = newMana;
      let inventory = state.inventory;

      if (newPotionCD <= 0) {
          // Updated Potion Logic using restoreAmount
          const hpThreshold = state.stats.maxHealth * 0.3;
          const manaThreshold = state.stats.maxMana * 0.3;
          let usedPotion = false;
          if (newHealth < hpThreshold) {
              const hpPotIndex = inventory.findIndex(i => i.type === 'POTION' && i.name === 'Health Potion');
              if (hpPotIndex !== -1) {
                  const pot = inventory[hpPotIndex];
                  newHealthAfterPot = Math.min(state.stats.maxHealth, newHealth + (pot.restoreAmount || 50));
                  usedPotion = true;
                  inventory = [...inventory];
                  if ((pot.quantity || 1) > 1) { inventory[hpPotIndex] = { ...pot, quantity: (pot.quantity || 1) - 1 }; } 
                  else { inventory.splice(hpPotIndex, 1); }
              }
          }
          if (!usedPotion && newMana < manaThreshold) {
               const manaPotIndex = inventory.findIndex(i => i.type === 'POTION' && i.name === 'Mana Potion');
               if (manaPotIndex !== -1) {
                  const pot = inventory[manaPotIndex];
                  newManaAfterPot = Math.min(state.stats.maxMana, newMana + (pot.restoreAmount || 50));
                  usedPotion = true;
                  inventory = [...inventory];
                  if ((pot.quantity || 1) > 1) { inventory[manaPotIndex] = { ...pot, quantity: (pot.quantity || 1) - 1 }; } 
                  else { inventory.splice(manaPotIndex, 1); }
               }
          }
          if (usedPotion) newPotionCD = 5; 
      }

      set({
          skills: newSkills,
          health: newHealthAfterPot,
          mana: newManaAfterPot,
          stats: stats,
          rageMode: rageMode,
          rageTimer: rageTimer,
          sprintTimer: Math.max(0, sprintTimer),
          earthwall: earthwall,
          warVitalityTimer: Math.max(0, warVitalityTimer),
          potionCooldown: newPotionCD,
          barrierCooldown: newBarrierCooldown,
          inventory: inventory,
          waveTimer: state.waveTimer + delta,
          invincibilityTimer: newInvincibilityTimer,
          isInvincible: newIsInvincible,
          levelUpVisualTimer: newLevelUpTimer,
          reviveAnimTimer: newReviveAnimTimer, // Set
          petReviveCooldown: newPetReviveCooldown,
      });
  },

  upgradeItem: (item) => {
      const state = get();
      if (item.level >= 10) {
          set({ actionResult: { type: 'UPGRADE', success: false, message: "Max Level Reached!" } });
          return { success: false, msg: "Max Level", newItem: item };
      }

      const core = state.inventory.find(i => i.type === 'CORE');
      const coreIndex = state.inventory.findIndex(i => i.type === 'CORE');
      const requiredCores = Math.ceil(item.level / 2);
      const goldCost = Math.floor(item.price * item.level * 0.5);

      if (state.score < goldCost) {
          set({ actionResult: { type: 'UPGRADE', success: false, message: "Not enough Gold!" } });
          return { success: false, msg: "Not enough Gold", newItem: item };
      }
      if (!core || (core.quantity || 1) < requiredCores) {
          set({ actionResult: { type: 'UPGRADE', success: false, message: `Need ${requiredCores} Cores` } });
          return { success: false, msg: `Need ${requiredCores} Cores`, newItem: item };
      }

      // Updated Success Rate Logic: 100% until +2, then -10% per level
      // Level 1 -> 2: (level is 1) 100%
      // Level 2 -> 3: (level is 2) 100%
      // Level 3 -> 4: (level is 3) 90%
      // Level 4 -> 5: (level is 4) 80%
      // Formula: if level < 3 return 100 else 100 - (level - 2) * 10
      let chance = 100;
      if (item.level >= 3) {
          chance = Math.max(10, 100 - ((item.level - 2) * 10));
      }

      const roll = Math.random() * 100;
      const success = roll < chance;

      const newInventory = [...state.inventory];
      const coreItem = newInventory[coreIndex];
      if ((coreItem.quantity || 1) > requiredCores) { coreItem.quantity = (coreItem.quantity || 1) - requiredCores; } else { newInventory.splice(coreIndex, 1); }
      set({ score: state.score - goldCost, inventory: newInventory });

      if (success) {
           let upgradedItem: Item = { ...item };
           const upgradeLogic = (i: Item) => {
              if (i === item) {
                  const updatedStats = { ...i.stats };
                  Object.keys(updatedStats).forEach(k => {
                      const key = k as keyof PlayerStats; 
                      const val = updatedStats[key]!;

                      // NEW LINEAR SCALING LOGIC: (Current / Level) * (Level + 1)
                      const lvl = Math.max(1, i.level);
                      const base = val / lvl;
                      const next = base * (lvl + 1);
                      updatedStats[key] = parseFloat(next.toFixed(2));
                  });
                  upgradedItem = { ...i, level: i.level + 1, stats: updatedStats };
                  return upgradedItem;
              }
              return i;
          };
          const updatedInventory = get().inventory.map(upgradeLogic);
          const updatedEquipment = {
              weapon: state.equipment.weapon ? upgradeLogic(state.equipment.weapon) : null,
              armor: state.equipment.armor ? upgradeLogic(state.equipment.armor) : null,
              accessory: state.equipment.accessory ? upgradeLogic(state.equipment.accessory) : null,
              pet: state.equipment.pet ? upgradeLogic(state.equipment.pet) : null,
          };
          const newStats = calculateStats(state.baseStats, updatedEquipment, state.rageMode, state.sprintTimer > 0);
          set({ inventory: updatedInventory, equipment: updatedEquipment, stats: newStats, actionResult: { type: 'UPGRADE', success: true, message: "Upgrade Successful!", item: upgradedItem } });
          return { success: true, msg: "Upgrade Successful!", newItem: upgradedItem };
      } else { 
          set({ actionResult: { type: 'UPGRADE', success: false, message: "Upgrade Failed..." } });
          return { success: false, msg: "Upgrade Failed...", newItem: item }; 
      }
  },

  resetGame: () => set({ status: GameStatus.MENU }),
  addNotification: (message, color = 'white', type = 'ITEM', action) => set(state => ({ notifications: [...state.notifications, { id: Math.random().toString(), message, color, type, action }] })),
  removeNotification: (id) => set(state => ({ notifications: state.notifications.filter(n => n.id !== id) })),

  updateMinimapEnemies: (enemies) => set({ minimapEnemies: enemies }), // Update action

  // ... (equipItem, unequipItem, autoEquip, buyItem, sellItem, etc. unchanged)
  equipItem: (item) => set((state) => {
      const req = RARITY_LEVEL_REQ[item.rarity] || 1;
      if (state.level < req) {
          get().addNotification(`Requires Level ${req}`, 'red', 'SYSTEM');
          return {};
      }

      let newInventory = state.inventory.filter(i => i.id !== item.id);
      let slot: 'weapon' | 'armor' | 'accessory' | 'pet' | null = null;
      if (item.type === 'WEAPON') slot = 'weapon';
      if (item.type === 'ARMOR') slot = 'armor';
      if (item.type === 'ACCESSORY') slot = 'accessory';
      if (item.type === 'PET') slot = 'pet';

      if (!slot) return {};

      let oldItem = state.equipment[slot];
      if (oldItem) {
          newInventory.push(oldItem);
      }

      const newEquipment = { ...state.equipment, [slot]: item };

      return {
          inventory: newInventory,
          equipment: newEquipment,
          stats: calculateStats(state.baseStats, newEquipment, state.rageMode, state.sprintTimer > 0)
      };
  }),

  unequipItem: (slot) => set((state) => {
      const item = state.equipment[slot];
      if (!item) return {};
      if (state.inventory.length >= state.maxInventorySlots) {
          get().handleInventoryFull();
          return {};
      }

      const newEquipment = { ...state.equipment, [slot]: null };
      return {
          equipment: newEquipment,
          inventory: [...state.inventory, item],
          stats: calculateStats(state.baseStats, newEquipment, state.rageMode, state.sprintTimer > 0)
      };
  }),

  autoEquip: () => {
      const state = get();
      const slots = ['weapon', 'armor', 'accessory', 'pet'] as const;
      let newEquipment = { ...state.equipment };
      let newInventory = [...state.inventory];
      let changed = false;

      slots.forEach(slot => {
          let type: ItemType = 'WEAPON';
          if (slot === 'armor') type = 'ARMOR';
          if (slot === 'accessory') type = 'ACCESSORY';
          if (slot === 'pet') type = 'PET';

          const candidates = newInventory.filter(i => {
              // Level req check
              const req = RARITY_LEVEL_REQ[i.rarity] || 1;
              if (state.level < req) return false;
              return i.type === type && (!i.classType || i.classType === state.hero);
          });
          if (candidates.length === 0) return;

          // Find candidate with highest CP
          const bestCandidate = candidates.reduce((prev, current) => {
              return calculateItemCP(current) > calculateItemCP(prev) ? current : prev;
          });

          const currentItem = newEquipment[slot];
          const currentCP = currentItem ? calculateItemCP(currentItem) : -1;

          if (calculateItemCP(bestCandidate) > currentCP) {
              changed = true;
              // Swap
              if (currentItem) {
                  newInventory.push(currentItem);
              }
              newEquipment[slot] = bestCandidate;
              // Remove best candidate from inventory
              newInventory = newInventory.filter(i => i.id !== bestCandidate.id);
          }
      });

      if (changed) {
          set({
              equipment: newEquipment,
              inventory: newInventory,
              stats: calculateStats(state.baseStats, newEquipment, state.rageMode, state.sprintTimer > 0)
          });
          get().addNotification("Auto Equipped Best Gear", COLORS.uiAccent, 'SYSTEM');
      } else {
          get().addNotification("Best gear already equipped", COLORS.uiPrimary, 'SYSTEM');
      }
  },

  buyItem: (item, quantity = 1) => {
      const state = get();
      if (state.score >= item.price * quantity) {
          if (state.inventory.length + quantity > state.maxInventorySlots && item.type !== 'POTION' && item.type !== 'CORE') {
              get().handleInventoryFull();
              return false;
          }

          let newInv = [...state.inventory];
          for(let i=0; i<quantity; i++) {
              const isStackable = item.type === 'POTION' || item.type === 'CORE';
              const existingStack = newInv.find(x => x.name === item.name && isStackable && (x.quantity || 1) < POTION_STACK_LIMIT);

              if (existingStack) {
                  existingStack.quantity = (existingStack.quantity || 1) + 1;
              } else {
                  newInv.push({ ...item, id: Math.random().toString(), quantity: 1 });
              }
          }

          set({ score: state.score - (item.price * quantity), inventory: newInv });
          get().addNotification(`Bought ${quantity}x ${item.name}`, 'yellow', 'SYSTEM');
          return true;
      }
      return false;
  },

  sellItem: (item) => set((state) => {
      const sellPrice = Math.floor(item.price * 0.3);
      const newInv = state.inventory.filter(i => i.id !== item.id);
      return { score: state.score + sellPrice, inventory: newInv };
  }),

  sellItems: (items) => set((state) => {
      let total = 0;
      const ids = new Set(items.map(i => i.id));
      const newInv = state.inventory.filter(i => {
          if (ids.has(i.id)) {
              total += Math.floor(i.price * 0.3);
              return false;
          }
          return true;
      });
      return { score: state.score + total, inventory: newInv };
  }),

  massSell: (rarity) => set((state) => {
      let total = 0;
      let count = 0;
      const newInv = state.inventory.filter(i => {
          if (i.rarity === rarity && i.type !== 'POTION' && i.type !== 'CORE' && i.type !== 'REVIVE') {
              total += Math.floor(i.price * 0.3);
              count++;
              return false;
          }
          return true;
      });
      get().addNotification(`Sold ${count} ${rarity} items for ${total} G`, 'yellow', 'SYSTEM');
      return { score: state.score + total, inventory: newInv };
  }),

  recycleItem: (item) => set((state) => {
      const newInv = state.inventory.filter(i => i.id !== item.id);
      const mat = item.rarity;
      return { 
          inventory: newInv, 
          materials: { ...state.materials, [mat]: state.materials[mat] + 1 } 
      };
  }),

  massRecycle: (rarity) => set((state) => {
      let count = 0;
      const newInv = state.inventory.filter(i => {
          if (i.rarity === rarity && i.type !== 'POTION' && i.type !== 'CORE' && i.type !== 'REVIVE') {
              count++;
              return false;
          }
          return true;
      });
      return {
          inventory: newInv,
          materials: { ...state.materials, [rarity]: state.materials[rarity] + count }
      };
  }),

  combineMaterials: (rarity) => set((state) => {
      const have = state.materials[rarity];
      if (have < 10) return {};

      let nextRarity: Rarity | null = null;
      if (rarity === 'COMMON') nextRarity = 'RARE';
      if (rarity === 'RARE') nextRarity = 'EPIC';
      if (rarity === 'EPIC') nextRarity = 'LEGENDARY';
      if (rarity === 'LEGENDARY') nextRarity = 'MYTHIC';

      if (!nextRarity) return {};

      return {
          materials: {
              ...state.materials,
              [rarity]: have - 10,
              [nextRarity]: state.materials[nextRarity] + 1
          }
      };
  }),

  craftItem: (rarity) => {
      const state = get();
      if (state.materials[rarity] < 3) {
          set({ actionResult: { type: 'CRAFT', success: false, message: `Need 3 ${rarity} Materials` } });
          return false;
      }

      let pool = ITEMS_POOL.filter(i => i.rarity === rarity && i.type !== 'POTION' && i.type !== 'CORE');
      if (pool.length === 0) return false;

      const hero = state.hero;
      const weightedPool: Item[] = [];
      pool.forEach(p => {
          weightedPool.push(p);
          if (p.type === 'WEAPON' && p.classType === hero) weightedPool.push(p); 
      });

      const template = weightedPool[Math.floor(Math.random() * weightedPool.length)];
      const item = { ...template, id: Math.random().toString(), quantity: 1 };

      set({ 
          materials: { ...state.materials, [rarity]: state.materials[rarity] - 3 },
          inventory: [...state.inventory, item],
          actionResult: { type: 'CRAFT', success: true, message: `Crafted ${item.name}!`, item }
      });
      get().addNotification(`Crafted ${item.name}!`, COLORS.uiAccent, 'ITEM');
      return true;
  },

  buyInventorySlots: () => {
      const state = get();
      const cost = 1000 * (Math.floor((state.maxInventorySlots - INVENTORY_LIMIT) / 5) + 1);
      if (state.score >= cost) {
          set({ score: state.score - cost, maxInventorySlots: state.maxInventorySlots + 5 });
          return true;
      }
      return false;
  },

  performSummon: (amount) => {
      const state = get();
      if (state.inventory.length + amount > state.maxInventorySlots) {
          set({ actionResult: { type: 'CRAFT', success: false, message: "Inventory Full!" } });
          get().addNotification("Inventory Full!", "red", "SYSTEM");
          return false;
      }

      const cost = amount === 1 ? 100 : 900;
      if (state.gems < cost) return false;

      const results: Item[] = [];
      for(let i=0; i<amount; i++) {
          const r = Math.random();
          let rarity: Rarity = 'COMMON';

          // Updated Summon Probability (50% rarer high tier)
          // Old: M 1%, L 4%, E 15%, R 30%
          // New: M 0.5%, L 2%, E 7.5%, R 20%
          if (r > 0.995) rarity = 'MYTHIC';
          else if (r > 0.975) rarity = 'LEGENDARY';
          else if (r > 0.90) rarity = 'EPIC';
          else if (r > 0.70) rarity = 'RARE';

          let pool = [...ITEMS_POOL, ...PETS_POOL].filter(it => it.rarity === rarity);
          if (pool.length === 0) pool = ITEMS_POOL;

          const template = pool[Math.floor(Math.random() * pool.length)];
          results.push({ ...template, id: Math.random().toString(), quantity: 1 });
      }

      set({ 
          gems: state.gems - cost,
          gachaResults: results,
          status: GameStatus.GACHA_REVEAL,
          inventory: [...state.inventory, ...results]
      });
      return true;
  },

  clearGachaResults: () => set({ status: GameStatus.PLAYING, gachaResults: [] }),

  upgradeSkill: (skill) => set((state) => {
      const currentLevel = state.skillLevels[skill];
      let cost = skill === 'special' ? 5 : (currentLevel === 0 ? 3 : currentLevel + 1);

      // New Regen Skill Cost Logic
      if (skill === 'regen') {
          cost = currentLevel === 0 ? 6 : 5;
      }

      if (state.skillPoints >= cost) {
          const newLevels = { ...state.skillLevels, [skill]: currentLevel + 1 };

          let newActiveQ = state.activeAbilityQ;
          if (skill === 'piercing') newActiveQ = 'PIERCING_SHOT';
          if (skill === 'gravity') newActiveQ = 'GRAVITY_SPELL';
          if (skill === 'rage') newActiveQ = 'RAGE';

          return {
              skillPoints: state.skillPoints - cost,
              skillLevels: newLevels,
              activeAbilityQ: newActiveQ
          };
      }
      return {};
  }),

  applyUpgrade: (upgrade: Upgrade) => set((state) => {
      const newBase = { ...state.baseStats };
      let newSkillLevels = { ...state.skillLevels };
      const newPassiveState = { ...state.passiveSkillState };

      if (upgrade.type === 'HEALTH') newBase.maxHealth += upgrade.value;
      if (upgrade.type === 'MAX_MANA') newBase.maxMana += upgrade.value;
      if (upgrade.type === 'DEFENSE') newBase.defense += upgrade.value;
      if (upgrade.type === 'SPEED') newBase.moveSpeed += upgrade.value; 
      if (upgrade.type === 'DAMAGE') newBase.damage = Math.ceil(newBase.damage * (1 + upgrade.value)); 
      if (upgrade.type === 'FIRE_RATE') newBase.fireRate += upgrade.value;
      if (upgrade.type === 'MULTISHOT') newBase.multishot += upgrade.value;
      if (upgrade.type === 'CRIT_RATE') newBase.critRate += upgrade.value;
      if (upgrade.type === 'CRIT_DAMAGE') newBase.critDamage += upgrade.value;
      if (upgrade.type === 'DASH_COOLDOWN') newBase.dashCooldown -= 0.5;

      if (upgrade.type.startsWith('SKILL_')) {
          let key: keyof SkillLevels | null = null;
          if (upgrade.type === 'SKILL_ORBITAL') key = 'orbital';
          if (upgrade.type === 'SKILL_THUNDER') key = 'thunder';
          if (upgrade.type === 'SKILL_REGEN') key = 'regen';
          if (upgrade.type === 'SKILL_MAGNET') key = 'magnet';
          if (upgrade.type === 'SKILL_DASH') key = 'dash';
          if (upgrade.type === 'SKILL_WEAPON') key = 'weapon';
          if (upgrade.type === 'SKILL_BARRIER') key = 'barrier';
          if (upgrade.type === 'SKILL_STORM') key = 'storm';

          if (upgrade.type === 'SKILL_PIERCING') key = 'piercing';
          if (upgrade.type === 'SKILL_BURNING') key = 'burning';
          if (upgrade.type === 'SKILL_FREEZING') key = 'freezing';

          if (upgrade.type === 'SKILL_GRAVITY') key = 'gravity';
          if (upgrade.type === 'SKILL_FREEZE_SPELL') key = 'freezeSpell';

          if (upgrade.type === 'SKILL_RAGE') key = 'rage';
          if (upgrade.type === 'SKILL_STAMP') key = 'stamp';

          if (key) {
              newSkillLevels[key]++;
          }
      }

      let newActiveQ = state.activeAbilityQ;
      if (upgrade.type === 'SKILL_PIERCING' && !newActiveQ) newActiveQ = 'PIERCING_SHOT';
      if (upgrade.type === 'SKILL_GRAVITY' && !newActiveQ) newActiveQ = 'GRAVITY_SPELL';
      if (upgrade.type === 'SKILL_RAGE' && !newActiveQ) newActiveQ = 'RAGE';

      return {
          baseStats: newBase,
          stats: calculateStats(newBase, state.equipment, state.rageMode, state.sprintTimer > 0),
          skillLevels: newSkillLevels,
          passiveSkillState: newPassiveState,
          activeAbilityQ: newActiveQ
      };
  }),

  selectUpgrade: (upgrade: Upgrade) => {
      get().applyUpgrade(upgrade);
      set({ status: GameStatus.PLAYING });
  }

}));

import React, { useRef, useState } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import { Html } from '@react-three/drei';
import { Vector3, InstancedMesh, Mesh, Raycaster, Plane } from 'three';
import { useGameStore } from '../store';
import { COLORS, PLAYER_RADIUS, ARENA_SIZE } from '../constants';
import { BulletManager } from './BulletManager';
import { GameStatus, BulletData, EnemyData } from '../types';
import { SpatialHashGrid } from '../utils/SpatialHashGrid';

interface PlayerProps {
  bulletsDataRef: React.MutableRefObject<BulletData[]>;
  enemyBulletsDataRef: React.MutableRefObject<BulletData[]>;
  targetPosRef: React.MutableRefObject<Vector3>;
  // New props
  enemiesDataRef: React.MutableRefObject<EnemyData[]>;
  spatialGrid?: React.MutableRefObject<SpatialHashGrid>;
}

export const Player: React.FC<PlayerProps> = ({ bulletsDataRef, enemyBulletsDataRef, targetPosRef, enemiesDataRef, spatialGrid }) => {
  const meshRef = useRef<any>(null);
  const axeSpinRef = useRef<any>(null);

  const { stats, status, setPlayerPosition, skills, triggerSkillCooldown, tickCooldowns, takeDamage, equipment, useMana, triggerInvincibility, obstacles, crates, isInvincible, toggleInventory, breakCrate, hero, levelUpVisualTimer, health, mana, level, activeAbilityQ, activateRage, rageMode, skillLevels, activateEarthwall, activateWarVitality, activateSprint, reviveAnimTimer } = useGameStore();
  const { camera, scene, raycaster, pointer } = useThree();

  const [pos] = useState(new Vector3(0, 0, 0));
  const [velocity] = useState(new Vector3(0, 0, 0));
  const [keys, setKeys] = useState<{ [key: string]: boolean }>({});

  const groundPlane = new Plane(new Vector3(0, 1, 0), 0);

  const dashVelocity = useRef(new Vector3());
  const dashTime = useRef(0);
  const axeSpinTime = useRef(0);
  const axeDamageTimer = useRef(0);
  const arrowRainState = useRef({ active: false, wavesLeft: 0, timer: 0 });

  React.useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        if (e.code === 'Space') e.preventDefault(); 
        setKeys((k) => ({ ...k, [e.code]: true }));
        if (e.code === 'KeyI') toggleInventory();
    };
    const handleKeyUp = (e: KeyboardEvent) => setKeys((k) => ({ ...k, [e.code]: false }));
    const handleMouseDown = (e: MouseEvent) => {
        if (e.button === 2) setKeys((k) => ({ ...k, 'RightClick': true })); 
    };
    const handleMouseUp = (e: MouseEvent) => {
        if (e.button === 2) setKeys((k) => ({ ...k, 'RightClick': false }));
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    window.addEventListener('mousedown', handleMouseDown);
    window.addEventListener('mouseup', handleMouseUp);
    window.addEventListener('contextmenu', (e) => e.preventDefault());

    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
      window.removeEventListener('mousedown', handleMouseDown);
      window.removeEventListener('mouseup', handleMouseUp);
      window.removeEventListener('contextmenu', (e) => e.preventDefault());
    };
  }, [toggleInventory]);

  const spawnBullet = (type: any, speed: number, damageMult: number, overrides: Partial<BulletData> = {}) => {
      const bullet = bulletsDataRef.current.find(b => !b.active);
      if (bullet) {
          bullet.active = true;
          bullet.lifetime = overrides.lifetime || 3.0;
          let aimDir = new Vector3().subVectors(targetPosRef.current, pos).normalize();

          if (type === 'BLACKHOLE') {
              bullet.position.copy(pos).add(aimDir.clone().multiplyScalar(15.0)).add(new Vector3(0, 1.5, 0));
              bullet.velocity.set(0, 0, 0); 
          } else {
              bullet.position.copy(pos).add(new Vector3(0, 1.5, 0));
              bullet.velocity.copy(aimDir).multiplyScalar(speed);
          }

          bullet.type = type;
          bullet.pierce = overrides.pierce || 1;
          bullet.damageMultiplier = damageMult * stats.skillDamage * 2.0; 
          bullet.hitIds = [];
          if (overrides.knockback) bullet.knockback = overrides.knockback;
          if (overrides.effect) bullet.effect = overrides.effect;
          if (overrides.trailTimer !== undefined) bullet.trailTimer = overrides.trailTimer;
          if (overrides.maxPullCount) bullet.maxPullCount = overrides.maxPullCount;

          return bullet;
      }
      return null;
  };

  const handleAbility = (ability: string, isQ: boolean) => {
      if (useMana(30)) {
          triggerSkillCooldown(isQ ? 'q' : 'r');

          if (ability === 'RAGE') {
              activateRage();
          } else if (ability === 'PIERCING_SHOT') {
              // UPDATED: 30% less damage (1.75 multiplier vs 2.5), 2x knockback (4.0)
              spawnBullet('PIERCING_ARROW', 50, 1.75, { pierce: 99, knockback: 4.0, lifetime: 3.0 });
          } else if (ability === 'GRAVITY_SPELL') {
              const limit = 8 + (skillLevels.gravity * 1);
              spawnBullet('BLACKHOLE', 0, 5.0, { pierce: 99, lifetime: 2.6, trailTimer: 0.1, maxPullCount: limit }); 
          } else if (ability === 'ARROW_RAIN') {
              arrowRainState.current.active = true;
              arrowRainState.current.wavesLeft = 3;
              arrowRainState.current.timer = 0; 
          } else if (ability === 'FIREBALL') {
              spawnBullet('FIREBALL', 5, 2.0 * 0.63, { 
                  pierce: 100, 
                  lifetime: 5.0, 
                  effect: { type: 'BURN', duration: 5, value: stats.damage * 0.3 } 
              });
          } else if (ability === 'AXE_SPIN') {
              axeSpinTime.current = 3.0;
              axeDamageTimer.current = 0.2; 
          }
      }
  };

  const handleSkillE = () => {
      if (skillLevels.special <= 0) return;
      if (skills.e > 0) return;

      const manaCost = 20; 
      if (useMana(manaCost)) {
          triggerSkillCooldown('e');
          if (hero === 'BARBARIAN') {
              activateWarVitality();
          } else if (hero === 'WIZARD') {
              activateEarthwall(pos.clone());
          } else if (hero === 'ARCHER') {
              activateSprint();
          }
      }
  };

  useFrame((state, delta) => {
    if (status !== GameStatus.PLAYING) return;
    if (!meshRef.current) return;

    tickCooldowns(delta);

    raycaster.setFromCamera(pointer, camera);
    const target = new Vector3();
    raycaster.ray.intersectPlane(groundPlane, target);
    targetPosRef.current.copy(target); 

    const moveDir = new Vector3(0, 0, 0);
    if (keys['KeyW'] || keys['ArrowUp']) moveDir.z -= 1;
    if (keys['KeyS'] || keys['ArrowDown']) moveDir.z += 1;
    if (keys['KeyA'] || keys['ArrowLeft']) moveDir.x -= 1;
    if (keys['KeyD'] || keys['ArrowRight']) moveDir.x += 1;
    moveDir.normalize();

    if (keys['KeyQ'] && skills.q <= 0 && activeAbilityQ) {
        handleAbility(activeAbilityQ, true);
    }

    if ((keys['KeyR'] || keys['RightClick']) && skills.r <= 0) {
        const ability = equipment.weapon?.ability;
        if (ability) {
            handleAbility(ability, false);
        }
    }

    if (keys['KeyE']) {
        handleSkillE();
    }

    if (arrowRainState.current.active) {
        arrowRainState.current.timer -= delta;
        if (arrowRainState.current.timer <= 0) {
            const count = 12; 
            const angleOffset = (3 - arrowRainState.current.wavesLeft) * (Math.PI / 8); 

            for (let i = 0; i < count; i++) {
                const bullet = bulletsDataRef.current.find(b => !b.active);
                if (bullet) {
                    bullet.active = true;
                    bullet.lifetime = 1.0;
                    bullet.position.copy(pos).add(new Vector3(0, 1, 0));
                    const angle = (Math.PI * 2 * i) / count + angleOffset;
                    bullet.velocity.set(Math.cos(angle), 0, Math.sin(angle)).multiplyScalar(25);
                    bullet.type = 'ARROW';
                    bullet.pierce = 3; 
                    bullet.damageMultiplier = 1.5 * 0.63 * stats.skillDamage * 2.0; 
                    bullet.knockback = 3.0; 
                }
            }
            arrowRainState.current.wavesLeft--;
            arrowRainState.current.timer = 0.2; 
            if (arrowRainState.current.wavesLeft <= 0) arrowRainState.current.active = false;
        }
    }

    if (axeSpinTime.current > 0) {
        axeSpinTime.current -= delta;
        axeDamageTimer.current += delta;
        if (axeSpinRef.current) {
            axeSpinRef.current.visible = true;
            axeSpinRef.current.rotation.y += delta * 20; 
            const barrierRadius = 7.0; 
            const damageRange = 8.0;

            const tickRate = 0.2; 
            if (axeDamageTimer.current >= tickRate) {
                 const tickDamage = stats.damage * tickRate * 5 * stats.skillDamage * 2.0 * 0.63; 
                 axeDamageTimer.current = 0;
                 // Optimized: Use enemiesDataRef
                 const enemies = enemiesDataRef.current;
                 for (let i = 0; i < enemies.length; i++) {
                    const enemy = enemies[i];
                    if (!enemy.active) continue;
                    const dist = enemy.position.distanceTo(pos);
                    if (dist < damageRange) {
                        enemy.health -= tickDamage;
                        window.dispatchEvent(new CustomEvent('damage', { 
                            detail: { position: enemy.position, damage: tickDamage, isCrit: false, isPlayer: false } 
                        }));
                    }
                 }
            }
            // Push enemies away
            const enemies = enemiesDataRef.current;
            for (let i = 0; i < enemies.length; i++) {
                const enemy = enemies[i];
                if (!enemy.active) continue;
                const dist = enemy.position.distanceTo(pos);
                if (dist < barrierRadius) {
                        const pushDir = new Vector3().subVectors(enemy.position, pos).normalize();
                        enemy.position.copy(pos).add(pushDir.multiplyScalar(barrierRadius));
                }
            }
        }
    } else if (axeSpinRef.current) {
        axeSpinRef.current.visible = false;
    }

    if (keys['Space'] && skills.dash <= 0) {
        if (useMana(5)) {
            triggerSkillCooldown('dash');
            dashTime.current = 0.2; 
            dashVelocity.current.copy(moveDir.length() > 0 ? moveDir.normalize() : new Vector3(0, 0, -1).applyQuaternion(meshRef.current.quaternion));
            dashVelocity.current.multiplyScalar(40); 
            triggerInvincibility(0.2);
        }
    }

    if (dashTime.current > 0) {
        dashTime.current -= delta;
        velocity.copy(dashVelocity.current);
    } else {
        velocity.lerp(moveDir.multiplyScalar(stats.moveSpeed), delta * 8);
    }

    const proposedPos = pos.clone().add(velocity.clone().multiplyScalar(delta));
    proposedPos.y = 0;

    for (const obs of obstacles) {
        const dist = proposedPos.distanceTo(obs.position);
        const minDistance = obs.radius + 0.4; 
        if (dist < minDistance) {
            const dir = new Vector3().subVectors(proposedPos, obs.position).normalize();
            proposedPos.copy(obs.position).add(dir.multiplyScalar(minDistance));
        }
    }

    for (const crate of crates) {
        if (crate.active) {
            const dist = proposedPos.distanceTo(crate.position);
            const minDistance = 0.7 + 0.4;
            if (dist < minDistance) {
                breakCrate(crate.id);
            }
        }
    }

    const limit = (ARENA_SIZE / 2) - 2;
    if (proposedPos.length() > limit) {
        proposedPos.normalize().multiplyScalar(limit);
    }
    proposedPos.y = 0;

    pos.copy(proposedPos);
    meshRef.current.position.copy(pos);
    setPlayerPosition(pos.clone());

    meshRef.current.lookAt(targetPosRef.current);

    const enemyBullets = enemyBulletsDataRef.current;
    if (dashTime.current <= 0) { 
        for(let i = 0; i < enemyBullets.length; i++) {
            const b = enemyBullets[i];
            if (b.active && b.position.distanceTo(pos) < PLAYER_RADIUS + 0.5) { 
                // UPDATED: Read bullet specific damage, default to 10 if not set
                const dmg = b.damage || 10;
                takeDamage(dmg);
                b.active = false;
                window.dispatchEvent(new CustomEvent('damage', { 
                    detail: { position: pos, damage: dmg, isCrit: false, isPlayer: true } 
                }));
            }
        }
    }

    const targetCamPos = new Vector3(pos.x, 35, pos.z + 28);
    camera.position.lerp(targetCamPos, delta * 4);
    camera.lookAt(pos.x, 0, pos.z);
  });

  const hpPercent = Math.max(0, health / stats.maxHealth) * 100;
  const mpPercent = Math.max(0, mana / stats.maxMana) * 100;

  return (
    <>
      <BulletManager 
          playerPos={pos} 
          targetPosRef={targetPosRef} 
          bulletsDataRef={bulletsDataRef}
          projectileType={equipment.weapon?.projectileType}
          enemiesDataRef={enemiesDataRef}
          spatialGrid={spatialGrid}
      />

      <group ref={meshRef} position={[0, 1, 0]}>

        <Html position={[0, -1.2, 0]} center style={{ pointerEvents: 'none' }} zIndexRange={[0, 0]}>
            <div className="flex items-center gap-2" style={{ opacity: 0.8 }}>
                <div className="w-8 h-8 rounded-full bg-slate-900 border-2 border-slate-500 flex items-center justify-center shadow-lg">
                    <span className="text-white font-bold text-sm">{level}</span>
                </div>
                <div className="flex flex-col gap-1 w-16">
                    <div className="h-1.5 w-full bg-slate-800 rounded-full overflow-hidden border border-slate-600">
                        <div className="h-full bg-red-500 transition-all duration-100" style={{ width: `${hpPercent}%` }} />
                    </div>
                    <div className="h-1.5 w-full bg-slate-800 rounded-full overflow-hidden border border-slate-600">
                        <div className="h-full bg-blue-500 transition-all duration-100" style={{ width: `${mpPercent}%` }} />
                    </div>
                </div>
            </div>
        </Html>

        {levelUpVisualTimer > 0 && (
            <>
                <Html position={[0, 2.5, 0]} center zIndexRange={[100, 0]}>
                    <div className="text-yellow-400 font-black text-2xl drop-shadow-[0_2px_2px_rgba(0,0,0,0.8)] animate-bounce whitespace-nowrap">
                        LEVEL UP!
                    </div>
                </Html>
                <mesh position={[0, 0.5, 0]} scale={[2, 4, 2]}>
                    <cylinderGeometry args={[0.5, 0.5, 1, 16]} />
                    <meshBasicMaterial color="#facc15" transparent opacity={levelUpVisualTimer * 0.5} depthWrite={false} side={2} />
                </mesh>
            </>
        )}

        {reviveAnimTimer > 0 && (
            <mesh position={[0, 0, 0]}>
                <cylinderGeometry args={[2, 2, 20, 16, 1, true]} />
                <meshBasicMaterial 
                    color="#fef3c7" 
                    transparent 
                    opacity={Math.min(1, reviveAnimTimer) * 0.6} 
                    depthWrite={false} 
                    side={2} 
                    blending={2} 
                />
            </mesh>
        )}

        {rageMode && (
            <mesh position={[0, 0.5, 0]}>
                <sphereGeometry args={[1.0, 16, 16]} />
                <meshBasicMaterial color="red" wireframe transparent opacity={0.3} />
            </mesh>
        )}

        <mesh visible={isInvincible}>
            <sphereGeometry args={[1.2, 16, 16]} />
            <meshStandardMaterial color="orange" transparent opacity={0.4} emissive="orange" emissiveIntensity={0.5} />
        </mesh>

        <group position={[0, 0, 0]}>
            <mesh castShadow receiveShadow position={[0, 0.5, 0]}>
                <capsuleGeometry args={[0.4, 1, 4, 8]} />
                <meshStandardMaterial 
                    color={rageMode ? 'red' : (levelUpVisualTimer > 0 ? '#facc15' : COLORS.player)} 
                    emissive={rageMode ? '#991b1b' : (levelUpVisualTimer > 0 ? '#facc15' : 'black')}
                    emissiveIntensity={rageMode ? 1 : levelUpVisualTimer}
                    roughness={0.4} metalness={0.6} 
                />
            </mesh>
            <mesh castShadow position={[0, 1.4, 0]}>
                <boxGeometry args={[0.5, 0.5, 0.5]} />
                <meshStandardMaterial color="#cbd5e1" metalness={0.8} roughness={0.2} />
            </mesh>
            <mesh position={[0.6, 0.5, 0.4]}>
                <boxGeometry args={[0.2, 0.2, 0.8]} />
                <meshStandardMaterial color="#94a3b8" />
            </mesh>
            <mesh position={[0, 0.6, -0.4]} rotation={[0.2, 0, 0]}>
                <boxGeometry args={[0.6, 1.2, 0.1]} />
                <meshStandardMaterial color="#1e40af" />
            </mesh>
        </group>

        <group ref={axeSpinRef} visible={false}>
            {[0, 1, 2, 3].map((i) => (
                <group key={i} rotation={[0, (i / 4) * Math.PI * 2, 0]}>
                    <mesh position={[7, 0, 0]}>
                        <boxGeometry args={[2.5, 0.25, 2.5]} /> 
                        <meshStandardMaterial color="#ef4444" emissive="#7f1d1d" emissiveIntensity={0.5} />
                    </mesh>
                </group>
            ))}
        </group>

        {hero === 'WIZARD' && (
            <group position={[0, 1.7, 0]}>
                <mesh position={[0, -0.1, 0]}>
                    <cylinderGeometry args={[0.6, 0.6, 0.05, 12]} />
                    <meshStandardMaterial color="#3b82f6" roughness={0.8} />
                </mesh>
                <mesh position={[0, 0.3, 0]}>
                    <coneGeometry args={[0.4, 0.8, 12]} />
                    <meshStandardMaterial color="#1e3a8a" roughness={0.8} />
                </mesh>
            </group>
        )}
      </group>
    </>
  );
};

import React, { useRef, useState } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import { InstancedMesh, Object3D, Vector3, Line, Mesh } from 'three';
import { useGameStore } from '../store';
import { GameStatus, BulletData, EnemyData } from '../types';
import { COLORS } from '../constants';

const dummy = new Object3D();

interface SkillManagerProps {
    enemyBulletsDataRef: React.MutableRefObject<BulletData[]>;
    bulletsDataRef: React.MutableRefObject<BulletData[]>;
    targetPosRef: React.MutableRefObject<Vector3>;
    enemiesDataRef?: React.MutableRefObject<EnemyData[]>;
}

export const SkillManager: React.FC<SkillManagerProps> = ({ enemyBulletsDataRef, bulletsDataRef, targetPosRef, enemiesDataRef }) => {
  const { skillLevels, playerPosition, status, stats, heal, takeDamage, updatePassiveCooldowns, useMana } = useGameStore();
  const { scene } = useThree();

  const orbitalState = useRef(2); 
  const orbitalTimer = useRef(2.0); 
  const orbitalRef = useRef<InstancedMesh>(null);
  const orbitalBlades = useRef<{ active: boolean, pos: Vector3, vel: Vector3 }[]>([]);
  const orbitalDamageTimer = useRef(0);

  const thunderTimer = useRef(0);
  const [thunderPositions, setThunderPositions] = useState<Vector3[]>([]);
  const thunderVisualTimer = useRef(0);

  const burningTimer = useRef(0);
  const freezingTimer = useRef(0);

  const blizzardTimer = useRef(0);

  const stampTimer = useRef(0);
  const stampStage = useRef(0); 
  const stampSequenceTimer = useRef(0); 
  const stampVisualRef = useRef<Mesh>(null);
  const stampVisualTimer = useRef(0);

  const blizzardVisualRef = useRef<Mesh>(null);
  const blizzardVisualTimer = useRef(0);

  const stormTimer = useRef(0);

  const spawnBullet = (type: any, speed: number, damageMult: number, overrides: Partial<BulletData> = {}, dir: Vector3) => {
      const bullet = bulletsDataRef.current.find(b => !b.active);
      if (bullet) {
          bullet.active = true;
          bullet.lifetime = overrides.lifetime || 3.0;
          bullet.position.copy(playerPosition).add(new Vector3(0, 1.5, 0));

          bullet.velocity.copy(dir).multiplyScalar(speed);
          bullet.type = type;
          bullet.pierce = overrides.pierce || 1;
          bullet.damageMultiplier = damageMult * stats.skillDamage * 2.0; 
          bullet.hitIds = [];
          if (overrides.knockback) bullet.knockback = overrides.knockback;
          if (overrides.effect) bullet.effect = overrides.effect;
          if (overrides.trailTimer !== undefined) bullet.trailTimer = overrides.trailTimer;
          if (overrides.bouncesLeft) bullet.bouncesLeft = overrides.bouncesLeft;
      }
  };

  const performStomp = (stage: number) => {
      stampVisualTimer.current = 0.5;

      const enemies = enemiesDataRef ? enemiesDataRef.current : [];
      for (let i = 0; i < enemies.length; i++) {
          const enemy = enemies[i];
          if (enemy.active && enemy.position.distanceTo(playerPosition) < 16.0) { 
              const dmg = stats.damage * 1.5 * stats.skillDamage;
              enemy.health -= dmg;

              if (stage === 1) {
                  enemy.freezeTimer = 2.0; 
              } else if (stage === 2) {
                  const dir = new Vector3().subVectors(enemy.position, playerPosition).normalize();
                  enemy.position.add(dir.multiplyScalar(5.0));
              }

              window.dispatchEvent(new CustomEvent('damage', { 
                  detail: { position: enemy.position, damage: dmg, isCrit: false, damageType: 'PHYSICAL' } 
              }));
          }
      }
  };

  useFrame((state, delta) => {
    if (status !== GameStatus.PLAYING) return;

    const time = state.clock.getElapsedTime();

    if (skillLevels.burning > 0) {
        burningTimer.current += delta;
        const maxCd = Math.max(2.0, 8.0 - (skillLevels.burning * 0.5));
        updatePassiveCooldowns({ burningCooldown: maxCd - burningTimer.current, burningMaxCooldown: maxCd });

        if (burningTimer.current >= maxCd) {
            if (useMana(5)) {
                burningTimer.current = 0;
                const baseDir = new Vector3().subVectors(targetPosRef.current, playerPosition).normalize(); 
                // UPDATED: 50% less damage for burning arrow (was 1.05)
                const damageMult = 0.525;
                const spread = 0.5;
                for(let i=-1; i<=1; i++) {
                    const dir = baseDir.clone().applyAxisAngle(new Vector3(0,1,0), i * spread);
                    spawnBullet('BURNING_ARROW', 30, damageMult, { 
                        pierce: 5, 
                        effect: { type: 'BURN', duration: 4, value: stats.damage * 0.3 } 
                    }, dir);
                }
            } else {
                burningTimer.current = maxCd;
            }
        }
    }

    if (skillLevels.freezing > 0) {
        freezingTimer.current += delta;
        const maxCd = Math.max(2.0, 7.0 - (skillLevels.freezing * 0.5));
        updatePassiveCooldowns({ freezingCooldown: maxCd - freezingTimer.current, freezingMaxCooldown: maxCd });

        if (freezingTimer.current >= maxCd) {
            if (useMana(5)) {
                freezingTimer.current = 0;
                const baseDir = new Vector3().subVectors(targetPosRef.current, playerPosition).normalize();
                const spread = 0.5;
                for(let i=-1; i<=1; i++) {
                    const dir = baseDir.clone().applyAxisAngle(new Vector3(0,1,0), i * spread);
                    spawnBullet('FREEZING_ARROW', 30, 0.75, { 
                        pierce: 5, 
                        effect: { type: 'FREEZE', duration: 1.5 } 
                    }, dir);
                }
            } else {
                freezingTimer.current = maxCd;
            }
        }
    }

    if (skillLevels.freezeSpell > 0) {
        blizzardTimer.current += delta;
        const maxCd = Math.max(7.0, 14.0 - (skillLevels.freezeSpell * 0.2));
        updatePassiveCooldowns({ blizzardCooldown: maxCd - blizzardTimer.current, blizzardMaxCooldown: maxCd });

        if (blizzardTimer.current >= maxCd) {
            if (useMana(15)) {
                blizzardTimer.current = 0;
                blizzardVisualTimer.current = 1.5; 

                const enemies = enemiesDataRef ? enemiesDataRef.current : [];
                for (let i = 0; i < enemies.length; i++) {
                    const enemy = enemies[i];
                    if (enemy.active && enemy.position.distanceTo(playerPosition) < 27.0) {
                        enemy.freezeTimer = 5.1; 
                        const dmg = stats.damage * 0.75 * stats.skillDamage; 
                        enemy.health -= dmg;
                        window.dispatchEvent(new CustomEvent('damage', { 
                            detail: { position: enemy.position, damage: dmg, isCrit: false, damageType: 'ICE' } 
                        }));
                    }
                }
            } else {
                blizzardTimer.current = maxCd;
            }
        }
    }

    if (skillLevels.storm > 0) {
        stormTimer.current += delta;
        const maxCd = Math.max(5.0, 15.0 - (skillLevels.storm * 0.2)); 
        updatePassiveCooldowns({ stormCooldown: maxCd - stormTimer.current, stormMaxCooldown: maxCd });

        if (stormTimer.current >= maxCd) {
            stormTimer.current = 0;
            const dir = new Vector3().subVectors(targetPosRef.current, playerPosition).normalize();
            spawnBullet('STORM', 4, 1.5, { 
                pierce: 99, 
                lifetime: 10.0, 
                knockback: 1.0,
                bouncesLeft: 6
            }, dir);
        }
    }

    if (skillLevels.stamp > 0) {
        if (stampStage.current === 0) {
            stampTimer.current += delta;
            const maxCd = Math.max(4.0, 12.0 - (skillLevels.stamp * 0.5));
            updatePassiveCooldowns({ stampCooldown: maxCd - stampTimer.current, stampMaxCooldown: maxCd });

            if (stampTimer.current >= maxCd) {
                if (useMana(15)) {
                    stampStage.current = 1;
                    stampSequenceTimer.current = 0;
                    performStomp(1); 
                }
            }
        } else if (stampStage.current === 1) {
            stampSequenceTimer.current += delta;
            if (stampSequenceTimer.current >= 0.5) { 
                performStomp(2); 
                stampStage.current = 0;
                stampTimer.current = 0; 
            }
        }
    }

    if (skillLevels.orbital > 0) {
        const count = 2 + skillLevels.orbital; 
        const damage = stats.damage * 1.5 * (1 + (skillLevels.orbital * 0.1)); 

        if (orbitalBlades.current.length !== count) {
            orbitalBlades.current = new Array(count).fill(0).map(() => ({ active: true, pos: new Vector3(), vel: new Vector3() }));
        }

        if (orbitalState.current === 2) {
            orbitalTimer.current += delta;
            updatePassiveCooldowns({ orbitalCooldown: 2 - orbitalTimer.current, orbitalMaxCooldown: 2 });

            for (let i = 0; i < 20; i++) {
                dummy.position.set(0, -100, 0);
                dummy.updateMatrix();
                orbitalRef.current?.setMatrixAt(i, dummy.matrix);
            }

            if (orbitalTimer.current > 2.0) {
                orbitalState.current = 0;
                orbitalTimer.current = 0;
                orbitalDamageTimer.current = 0.2; 
            }
        } else if (orbitalState.current === 0) {
            orbitalTimer.current += delta;
            orbitalDamageTimer.current += delta;
            updatePassiveCooldowns({ orbitalCooldown: 4 - orbitalTimer.current, orbitalMaxCooldown: 4 });

            const radius = 4.0;
            const speed = 3.0;

            for (let i = 0; i < count; i++) {
                const angle = (time * speed) + (i * ((Math.PI * 2) / count));
                orbitalBlades.current[i].active = true;
                orbitalBlades.current[i].pos.set(
                    playerPosition.x + Math.cos(angle) * radius,
                    1.0,
                    playerPosition.z + Math.sin(angle) * radius
                );

                dummy.position.copy(orbitalBlades.current[i].pos);
                dummy.rotation.set(0, -angle, 0);
                dummy.scale.set(3.0, 3.0, 3.0); 
                dummy.updateMatrix();
                orbitalRef.current?.setMatrixAt(i, dummy.matrix);

                const enemyBullets = enemyBulletsDataRef.current;
                const bladeRadius = 1.0;
                for (let b = 0; b < enemyBullets.length; b++) {
                    const bullet = enemyBullets[b];
                    if (bullet.active && bullet.position.distanceTo(orbitalBlades.current[i].pos) < bladeRadius) {
                        bullet.active = false;
                    }
                }
            }

            const tickRate = 0.2;
            if (orbitalDamageTimer.current >= tickRate) {
                const tickDamage = damage * tickRate * 5; 
                orbitalDamageTimer.current = 0;

                const enemies = enemiesDataRef ? enemiesDataRef.current : [];
                for (let i = 0; i < count; i++) {
                    const bladePos = orbitalBlades.current[i].pos;
                    for (let e = 0; e < enemies.length; e++) {
                        if (enemies[e].active && enemies[e].position.distanceTo(bladePos) < 2.0) {
                                enemies[e].health -= tickDamage;
                                window.dispatchEvent(new CustomEvent('damage', { 
                                detail: { position: enemies[e].position, damage: tickDamage, isCrit: false, damageType: 'PHYSICAL' } 
                                }));
                        }
                    }
                }
            }

            if (orbitalTimer.current > 4.0) {
                orbitalState.current = 1;
                orbitalTimer.current = 0;

                const enemies = enemiesDataRef ? enemiesDataRef.current : [];

                for(let i=0; i<count; i++) {
                    let target = null;
                    let minDist = 50;

                    for(const e of enemies) {
                         if (!e.active) continue;
                         const d = e.position.distanceTo(playerPosition);
                         if (d < minDist) {
                             minDist = d;
                             target = e.position;
                         }
                    }

                    const dir = new Vector3();
                    if (target) {
                        dir.subVectors(target, orbitalBlades.current[i].pos).normalize();
                    } else {
                        dir.subVectors(orbitalBlades.current[i].pos, playerPosition).normalize();
                    }
                    orbitalBlades.current[i].vel.copy(dir).multiplyScalar(20);
                }
            }

        } else if (orbitalState.current === 1) {
            let activeCount = 0;
            for (let i = 0; i < count; i++) {
                const blade = orbitalBlades.current[i];
                if (blade.active) {
                    blade.pos.add(blade.vel.clone().multiplyScalar(delta));

                    const enemyBullets = enemyBulletsDataRef.current;
                    for (let b = 0; b < enemyBullets.length; b++) {
                        const bullet = enemyBullets[b];
                        if (bullet.active && bullet.position.distanceTo(blade.pos) < 1.5) {
                            bullet.active = false;
                        }
                    }

                    const enemies = enemiesDataRef ? enemiesDataRef.current : [];
                    for (let e = 0; e < enemies.length; e++) {
                        if (enemies[e].active && enemies[e].position.distanceTo(blade.pos) < 1.5) {
                                enemies[e].health -= damage * 5;
                                blade.active = false; 
                                window.dispatchEvent(new CustomEvent('damage', { 
                                detail: { position: enemies[e].position, damage: damage * 5, isCrit: false, damageType: 'PHYSICAL' } 
                                }));
                        }
                    }

                    if (blade.pos.distanceTo(playerPosition) > 50) blade.active = false;

                    if (blade.active) {
                         dummy.position.copy(blade.pos);
                         dummy.rotation.set(0, time * 10, 0);
                         dummy.scale.set(3.0, 3.0, 3.0); 
                         dummy.updateMatrix();
                         orbitalRef.current?.setMatrixAt(i, dummy.matrix);
                         activeCount++;
                    } else {
                         dummy.position.set(0, -100, 0);
                         dummy.updateMatrix();
                         orbitalRef.current?.setMatrixAt(i, dummy.matrix);
                    }
                } else {
                     dummy.position.set(0, -100, 0);
                     dummy.updateMatrix();
                     orbitalRef.current?.setMatrixAt(i, dummy.matrix);
                }
            }

            if (activeCount === 0 || orbitalTimer.current > 2.0) {
                orbitalState.current = 2;
                orbitalTimer.current = 0;
            }
            orbitalTimer.current += delta;
        }

        orbitalRef.current!.instanceMatrix.needsUpdate = true;
    } else {
        if (orbitalRef.current) orbitalRef.current.visible = false;
    }

    if (skillLevels.thunder > 0) {
        thunderTimer.current += delta;
        // UPDATED: Cooldown 7s (was 2s)
        const maxCd = 7.0;
        updatePassiveCooldowns({ thunderCooldown: maxCd - thunderTimer.current, thunderMaxCooldown: maxCd });

        if (thunderTimer.current > maxCd) { 
            const enemies = enemiesDataRef ? enemiesDataRef.current : [];
            const activeEnemies: any[] = [];
            for(const e of enemies) {
                if (e.active && e.position.distanceTo(playerPosition) < 40) {
                    activeEnemies.push(e);
                }
            }

            if (activeEnemies.length > 0) {
                if (useMana(5)) {
                    thunderTimer.current = 0;
                    // UPDATED: Starts at 1 target (Level 1)
                    const hitCount = skillLevels.thunder; 
                    const hits: Vector3[] = [];

                    for(let i=0; i<hitCount; i++) {
                            if (activeEnemies.length === 0) break;
                            const idx = Math.floor(Math.random() * activeEnemies.length);
                            const target = activeEnemies[idx];

                            const isCrit = Math.random() < stats.critRate;
                            // UPDATED: 50% less damage (base 0.75 vs 1.5)
                            const baseDmg = stats.damage * 0.75 * (1 + (skillLevels.thunder * 0.1)); 
                            const dmg = baseDmg * (isCrit ? stats.critDamage : 1);

                            target.health -= dmg;

                            window.dispatchEvent(new CustomEvent('damage', { 
                            detail: { position: target.position, damage: dmg, isCrit, damageType: 'MAGIC' } 
                            }));

                            hits.push(target.position.clone());
                            activeEnemies.splice(idx, 1);
                    }

                    setThunderPositions(hits);
                    thunderVisualTimer.current = 0.25;
                } else {
                    thunderTimer.current = maxCd; 
                }
            }
        }
    }

    if (thunderVisualTimer.current > 0) {
        thunderVisualTimer.current -= delta;
        if (thunderVisualTimer.current <= 0) setThunderPositions([]);
    }

    if (blizzardVisualTimer.current > 0) {
        blizzardVisualTimer.current -= delta;
        if (blizzardVisualRef.current) {
            blizzardVisualRef.current.visible = true;
            blizzardVisualRef.current.position.copy(playerPosition).add(new Vector3(0, 0.1, 0));
            blizzardVisualRef.current.scale.setScalar(1 + (1.5 - blizzardVisualTimer.current) * 20);
            blizzardVisualRef.current.material.opacity = (blizzardVisualTimer.current / 1.5) * 0.5;
        }
    } else if (blizzardVisualRef.current) blizzardVisualRef.current.visible = false;

    if (stampVisualTimer.current > 0) {
        stampVisualTimer.current -= delta;
        if (stampVisualRef.current) {
            stampVisualRef.current.visible = true;
            stampVisualRef.current.position.copy(playerPosition).add(new Vector3(0, 0.1, 0));
            const scaleBase = stampStage.current === 1 ? 30 : 50; 
            stampVisualRef.current.scale.setScalar(1 + (0.5 - stampVisualTimer.current) * scaleBase);
            stampVisualRef.current.material.opacity = stampVisualTimer.current * 0.8;
        }
    } else if (stampVisualRef.current) stampVisualRef.current.visible = false;

  });

  return (
    <>
      <instancedMesh ref={orbitalRef} args={[undefined, undefined, 20]} frustumCulled={false} visible={skillLevels.orbital > 0}>
        <octahedronGeometry args={[0.4, 0]} />
        <meshStandardMaterial color="#0ea5e9" emissive="#0ea5e9" emissiveIntensity={2} />
      </instancedMesh>

      {thunderPositions.map((pos, i) => (
          <mesh key={i} position={pos}>
              <cylinderGeometry args={[0.1, 0.1, 30, 8]} />
              <meshBasicMaterial color="yellow" transparent opacity={0.8} />
          </mesh>
      ))}

      <mesh ref={blizzardVisualRef} rotation={[-Math.PI/2, 0, 0]} visible={false}>
           <circleGeometry args={[1, 32]} />
           <meshStandardMaterial color="#0ea5e9" transparent opacity={0.5} emissive="#0ea5e9" />
      </mesh>

      <mesh ref={stampVisualRef} rotation={[-Math.PI/2, 0, 0]} visible={false}>
           <ringGeometry args={[0.8, 1, 32]} />
           <meshStandardMaterial color="#f97316" transparent opacity={0.6} emissive="#f97316" />
      </mesh>
    </>
  );
};

import React, { useRef, useEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import { InstancedMesh, Object3D, Vector3, Color } from 'three';
import { useGameStore } from '../store';
import { ARENA_SIZE, COLORS } from '../constants';
import { GameStatus, EnemyData, BulletData } from '../types';
import { SpatialHashGrid } from '../utils/SpatialHashGrid';

const MAX_ENEMIES = 400;

const dummy = new Object3D();
const tempVec = new Vector3();
const tempColor = new Color();
const pushDir = new Vector3();

// Enemy Types Map
// 0: Basic
// 1: Elite (Melee)
// 2: Boss
// 3: Ranged (Fast)
// 4: Speedy (New)
// 5: Elite Shooter (New)
// 6: Ranged (Slow)

interface EnemyManagerProps {
  bulletsDataRef: React.MutableRefObject<BulletData[]>;
  enemyBulletsDataRef: React.MutableRefObject<BulletData[]>;
  enemiesDataRef: React.MutableRefObject<EnemyData[]>;
  spatialGrid: React.MutableRefObject<SpatialHashGrid>;
}

export const EnemyManager: React.FC<EnemyManagerProps> = ({ bulletsDataRef, enemyBulletsDataRef, enemiesDataRef, spatialGrid }) => {
  const meshRef = useRef<InstancedMesh>(null);
  const stunIconsRef = useRef<InstancedMesh>(null);
  const { playerPosition, addScore, takeDamage, status, level, stats, spawnDrop, wave, waveTimer, advanceWave, addNotification, setBossData, earthwall, updateMinimapEnemies, obstacles } = useGameStore();

  const enemies = enemiesDataRef;

  const spawnTimer = useRef(0);
  const dotTicker = useRef(0);
  const waveState = useRef({ wave: 1, bossSpawned: false, eliteSpawned: false });
  const minimapThrottle = useRef(0); 

  useEffect(() => {
    const handleBarrier = (e: CustomEvent) => {
        const { position, radius, force } = e.detail;
        enemies.current.forEach(enemy => {
            if (enemy.active) {
                const dist = enemy.position.distanceTo(position);
                if (dist < radius) {
                    const dir = new Vector3().subVectors(enemy.position, position).normalize();
                    enemy.position.add(dir.multiplyScalar(force));
                    enemy.freezeTimer = 0.5;
                }
            }
        });
    };
    window.addEventListener('barrier-trigger', handleBarrier as EventListener);
    return () => window.removeEventListener('barrier-trigger', handleBarrier as EventListener);
  }, []);

  useFrame((state, delta) => {
    if (status !== GameStatus.PLAYING) return;
    if (!meshRef.current) return;

    spatialGrid.current.clear();
    const activeBullets = bulletsDataRef.current;

    activeBullets.forEach(b => { 
        if(b.active && b.type === 'BLACKHOLE') {
            b.currentPullCount = 0; 
        }
    });

    if (!meshRef.current.userData.enemies) {
        meshRef.current.userData.enemies = enemies.current;
    }

    if (waveTimer > 30) {
        advanceWave();
    }

    if (wave !== waveState.current.wave) {
        waveState.current.wave = wave;
        waveState.current.bossSpawned = false;
        waveState.current.eliteSpawned = false;
    }

    spawnTimer.current += delta;
    const spawnRate = Math.max(0.05, 0.8 - (level * 0.02) - (wave * 0.05));

    if (spawnTimer.current > spawnRate) {
        spawnTimer.current = 0;
        const enemy = enemies.current.find(e => !e.active);
        if (enemy) {
            enemy.active = true;
            enemy.burnTimer = 0;
            enemy.poisonTimer = 0;
            enemy.freezeTimer = 0;
            enemy.slowTimer = 0;
            enemy.slowFactor = 0;
            enemy.bossPattern = 0;
            enemy.bossTimer = 0;
            enemy.bossAngle = 0;

            let angle, dist, spawnPos;
            do {
                angle = Math.random() * Math.PI * 2;
                dist = (ARENA_SIZE / 2) - 5;
                spawnPos = new Vector3(Math.cos(angle) * dist, 0, Math.sin(angle) * dist);
            } while (spawnPos.distanceTo(playerPosition) < 20);

            enemy.position.copy(spawnPos);

            const hpMult = 1 + (wave * 0.5) + (level * 0.1);
            // UPDATED: Speed progression 50% slower (0.025 instead of 0.05)
            const speedMult = 1 + (wave * 0.025);
            const globalHpReduction = 0.4;
            const r = Math.random();

            let isBoss = false;

            if (wave % 10 === 0 && !waveState.current.bossSpawned) {
                isBoss = true;
                waveState.current.bossSpawned = true;
                const bossName = wave % 20 === 0 ? "VOID REAPER" : "ABYSS LORD";
                addNotification(`⚠️ ${bossName} APPEARED ⚠️`, COLORS.enemyBoss, 'BOSS');
                setBossData({ active: true, name: bossName, hp: 1, maxHp: 1 });

                enemy.type = 2; 
                // UPDATED: Boss HP 20% less
                enemy.health = (2000 + (level * 250) + (wave * 100)) * hpMult * globalHpReduction * 0.8;
                enemy.speed = (2.5 + (level * 0.1)) * speedMult;
                enemy.radius = 2.5;
                enemy.scale = 3.0; 
                setBossData({ hp: enemy.health, maxHp: enemy.health });

            } else {
                // UPDATED: Elite Monster Logic (Spawn at any wave, 2x more spawn)
                // Old chance was mainly tied to wave. New chance is flat random increased by wave.
                const isElite = (r < (0.05 + (wave * 0.01))) || (wave % 5 === 0 && !waveState.current.eliteSpawned);

                if (wave % 5 === 0 && !waveState.current.eliteSpawned) {
                     waveState.current.eliteSpawned = true;
                     addNotification("⚠️ ELITE SQUAD", COLORS.enemyElite, 'BOSS');
                }

                if (isElite) {
                    if (Math.random() > 0.7) {
                        // UPDATED: New Elite Shooter (Type 5)
                        enemy.type = 5; 
                        enemy.health = (120 + (level * 15)) * hpMult * globalHpReduction;
                        enemy.speed = (3.5 + (level * 0.1)) * speedMult;
                        enemy.radius = 1.8;
                        enemy.scale = 1.6;
                    } else {
                        // Standard Elite (Type 1)
                        enemy.type = 1; 
                        enemy.health = (150 + (level * 20)) * hpMult * globalHpReduction;
                        enemy.speed = (4 + (level * 0.1)) * speedMult;
                        enemy.radius = 1.5;
                        enemy.scale = 1.5; 
                    }
                } 
                // UPDATED: Ranged Spawn Logic (50% less)
                // Original chance was roughly > 0.85 (15%). Reducing to ~7.5% (> 0.925)
                // Split between Type 3 (Fast) and Type 6 (Slow)
                else if (wave >= 3 && r > 0.925) { 
                    if (Math.random() > 0.5) {
                        enemy.type = 3; // Normal Ranged
                        enemy.health = (15 + (level * 5)) * hpMult * globalHpReduction;
                        enemy.speed = 3.0 * speedMult;
                        enemy.radius = 0.8;
                        enemy.scale = 1.0; 
                    } else {
                        // UPDATED: Slow Ranged (Type 6)
                        enemy.type = 6;
                        enemy.health = (20 + (level * 6)) * hpMult * globalHpReduction;
                        enemy.speed = 2.0 * speedMult;
                        enemy.radius = 0.8;
                        enemy.scale = 1.1;
                    }
                } 
                // UPDATED: Speedy Monster (Type 4) - 50% HP, 2x Speed
                else if (wave >= 2 && r > 0.85) { 
                    enemy.type = 4;
                    const baseHp = (10 + (level * 4)) * hpMult * globalHpReduction;
                    enemy.health = baseHp * 0.5;
                    const baseSpeed = (4 + (level * 0.15)) * speedMult;
                    enemy.speed = baseSpeed * 2.0;
                    enemy.radius = 0.6;
                    enemy.scale = 0.8;
                }
                // Basic Enemy (Type 0)
                else {
                    enemy.type = 0; 
                    enemy.health = (10 + (level * 4)) * hpMult * globalHpReduction;
                    enemy.speed = (4 + (level * 0.15)) * speedMult;
                    enemy.radius = 0.6;
                    enemy.scale = 1.0;
                }
            }
            enemy.maxHealth = enemy.health;
        }
    }

    dotTicker.current += delta;
    const shouldTickDoT = dotTicker.current > 0.5;
    if (shouldTickDoT) dotTicker.current = 0;

    const time = state.clock.getElapsedTime();

    for (let i = 0; i < MAX_ENEMIES; i++) {
        const e = enemies.current[i];
        if (e.active) {
            spatialGrid.current.add(i, e.position.x, e.position.z);

            const distToPlayer = e.position.distanceTo(playerPosition);
            let currentSpeed = e.speed;
            let canMove = true;

            if (e.type === 2) {
                 const currentBossData = useGameStore.getState().bossData;
                 if (Math.abs(currentBossData.hp - e.health) > 5) {
                     setBossData({ hp: e.health });
                 }
            }

            // DoT Logic
            if (e.burnTimer && e.burnTimer > 0) {
                e.burnTimer -= delta;
                if (shouldTickDoT) {
                    const dmg = (e.burnDamage || 5) * 0.5;
                    e.health -= dmg;
                    window.dispatchEvent(new CustomEvent('damage', { detail: { position: e.position, damage: dmg, isDoT: true, damageType: 'FIRE' } }));
                }
            }
            if (e.poisonTimer && e.poisonTimer > 0) {
                e.poisonTimer -= delta;
                if (shouldTickDoT) {
                    const dmg = (e.poisonDamage || 3) * 0.5;
                    e.health -= dmg;
                    window.dispatchEvent(new CustomEvent('damage', { detail: { position: e.position, damage: dmg, isDoT: true, damageType: 'POISON' } }));
                }
            }

            if (e.freezeTimer && e.freezeTimer > 0) {
                e.freezeTimer -= delta;
                canMove = false;
                if (stunIconsRef.current) {
                    dummy.position.copy(e.position).add(tempVec.set(0, (e.scale * 1.8) + 0.5, 0)); 
                    dummy.rotation.set(time * 5, time * 3, 0);
                    dummy.scale.set(0.5, 0.5, 0.5);
                    dummy.updateMatrix();
                    stunIconsRef.current.setMatrixAt(i, dummy.matrix);
                } 
            } else {
                if (stunIconsRef.current) {
                    dummy.position.set(0, -100, 0);
                    dummy.updateMatrix();
                    stunIconsRef.current.setMatrixAt(i, dummy.matrix);
                }
            }

            if (e.slowTimer && e.slowTimer > 0) {
                e.slowTimer -= delta;
                currentSpeed *= (1 - (e.slowFactor || 0.5));
            }

            // --- COLOR LOGIC ---
            if (e.freezeTimer && e.freezeTimer > 0) tempColor.set('#3b82f6');
            else if (e.burnTimer && e.burnTimer > 0) tempColor.set('#ef4444');
            else {
                if (e.type === 2) tempColor.set(COLORS.enemyBoss);
                else if (e.type === 3) tempColor.set(COLORS.enemyShooter);
                else if (e.type === 4) tempColor.set(COLORS.enemySpeedy); // New Color
                else if (e.type === 5) tempColor.set(COLORS.enemyEliteShooter); // New Color
                else if (e.type === 6) tempColor.set(COLORS.enemySlowShooter); // New Color
                else if (e.type === 1) {
                     if (e.scale > 1.4) tempColor.set(COLORS.enemyElite);
                     else tempColor.set(COLORS.enemyOrc);
                }
                else tempColor.set(COLORS.enemySlime);

                if (e.poisonTimer && e.poisonTimer > 0) tempColor.lerp(new Color('#4ade80'), 0.5);
            }

            meshRef.current.setColorAt(i, tempColor);

            if (canMove) {
                let moved = false;
                // Blackhole & Earthwall logic ...
                for(let b=0; b < activeBullets.length; b++) {
                    const bullet = activeBullets[b];
                    if (bullet.active && bullet.type === 'BLACKHOLE') {
                        const max = bullet.maxPullCount || 8;
                        const current = bullet.currentPullCount || 0;
                        if (current < max && e.position.distanceTo(bullet.position) < 15.0) {
                            pushDir.subVectors(bullet.position, e.position).normalize();
                            e.position.add(pushDir.multiplyScalar(currentSpeed * 2.0 * delta));
                            moved = true;
                            bullet.currentPullCount = current + 1;
                        }
                    }
                }
                if (earthwall.active) {
                    const distToWall = e.position.distanceTo(earthwall.position);
                    if (distToWall < earthwall.radius + e.radius) {
                        pushDir.subVectors(e.position, earthwall.position).normalize();
                        if (pushDir.lengthSq() === 0) pushDir.set(1, 0, 0);
                        e.position.copy(earthwall.position).add(pushDir.multiplyScalar(earthwall.radius + e.radius));
                        moved = true; 
                    }
                }

                if (!moved) {
                    const nextPos = e.position.clone();
                    // Shooters keep distance
                    if ((e.type === 3 || e.type === 5 || e.type === 6) && distToPlayer > 15) { 
                         tempVec.subVectors(playerPosition, e.position).normalize();
                         nextPos.add(tempVec.multiplyScalar(currentSpeed * delta));
                    } else if (e.type === 2 && distToPlayer > 10) { // Boss keeps slight distance
                         tempVec.subVectors(playerPosition, e.position).normalize();
                         nextPos.add(tempVec.multiplyScalar(currentSpeed * delta));
                    } else if (e.type !== 3 && e.type !== 5 && e.type !== 6 && e.type !== 2) {
                         tempVec.subVectors(playerPosition, e.position).normalize();
                         nextPos.add(tempVec.multiplyScalar(currentSpeed * delta));
                    }

                    for(const obs of obstacles) {
                        const distToObs = nextPos.distanceTo(obs.position);
                        const minDist = obs.radius + e.radius;
                        if (distToObs < minDist) {
                            pushDir.subVectors(nextPos, obs.position).normalize();
                            nextPos.copy(obs.position).add(pushDir.multiplyScalar(minDist));
                        }
                    }
                    e.position.copy(nextPos);
                }
            }

            // --- SHOOTING LOGIC ---
            e.stateTimer = (e.stateTimer || 0) + delta;

            // BOSS AI (Bullet Hell)
            if (e.type === 2 && canMove) {
                // Cycle Patterns every 5 seconds
                e.bossTimer = (e.bossTimer || 0) + delta;
                if (e.bossTimer > 5.0) {
                    e.bossTimer = 0;
                    e.bossPattern = ((e.bossPattern || 0) + 1) % 3;
                }

                const pattern = e.bossPattern || 0;

                // Pattern 0: Spiral
                if (pattern === 0) {
                    if (e.stateTimer > 0.05) { // Rapid fire
                        e.stateTimer = 0;
                        e.bossAngle = (e.bossAngle || 0) + 0.3;
                        const bullet = enemyBulletsDataRef.current.find(b => !b.active);
                        if (bullet) {
                            bullet.active = true;
                            bullet.lifetime = 4.0;
                            bullet.damage = 15; // Moderate dmg
                            bullet.position.copy(e.position).add(new Vector3(0, 1.5, 0));
                            bullet.velocity.set(Math.cos(e.bossAngle), 0, Math.sin(e.bossAngle)).multiplyScalar(10);
                        }
                    }
                } 
                // Pattern 1: Nova (Bursts)
                else if (pattern === 1) {
                     if (e.stateTimer > 0.8) {
                        e.stateTimer = 0;
                        for(let k=0; k<12; k++) {
                            const bullet = enemyBulletsDataRef.current.find(b => !b.active);
                            if (bullet) {
                                bullet.active = true;
                                bullet.lifetime = 4.0;
                                bullet.damage = 15;
                                bullet.position.copy(e.position).add(new Vector3(0, 1.5, 0));
                                const a = (Math.PI * 2 * k) / 12;
                                bullet.velocity.set(Math.cos(a), 0, Math.sin(a)).multiplyScalar(8);
                            }
                        }
                     }
                }
                // Pattern 2: Targeted Stream
                else if (pattern === 2) {
                    if (e.stateTimer > 0.15) {
                        e.stateTimer = 0;
                        const bullet = enemyBulletsDataRef.current.find(b => !b.active);
                        if (bullet) {
                            bullet.active = true;
                            bullet.lifetime = 4.0;
                            bullet.damage = 20; // High dmg
                            bullet.position.copy(e.position).add(new Vector3(0, 1.5, 0));

                            tempVec.subVectors(playerPosition, e.position).normalize();
                            // Slight spread
                            const spread = (Math.random() - 0.5) * 0.3;
                            tempVec.applyAxisAngle(new Vector3(0,1,0), spread);
                            bullet.velocity.copy(tempVec).multiplyScalar(14);
                        }
                    }
                }
            }
            // Standard Shooters
            else if ((e.type === 3 || e.type === 5 || e.type === 6) && canMove) {
                // Fire rate check
                const fireRate = e.type === 5 ? 1.5 : (e.type === 6 ? 3.0 : 2.0); // Elite faster, Slow slower

                if (e.stateTimer > fireRate && distToPlayer < 25) {
                    e.stateTimer = 0;

                    // Type 5: Elite Shooter (Spread)
                    if (e.type === 5) {
                        const baseDir = new Vector3().subVectors(playerPosition, e.position).normalize();
                        for(let k=-1; k<=1; k++) {
                             const bullet = enemyBulletsDataRef.current.find(b => !b.active);
                             if (bullet) {
                                bullet.active = true;
                                bullet.lifetime = 3.0;
                                bullet.damage = 10;
                                bullet.position.copy(e.position).add(new Vector3(0, 1, 0));
                                const dir = baseDir.clone().applyAxisAngle(new Vector3(0,1,0), k * 0.3);
                                bullet.velocity.copy(dir).multiplyScalar(12);
                             }
                        }
                    }
                    // Type 6: Slow Shooter (50% Dmg, Slow speed)
                    else if (e.type === 6) {
                        const bullet = enemyBulletsDataRef.current.find(b => !b.active);
                        if (bullet) {
                            bullet.active = true;
                            bullet.lifetime = 6.0; // Longer life for slow bullets
                            bullet.damage = 5; // 50% dmg
                            bullet.position.copy(e.position).add(new Vector3(0, 1, 0));
                            pushDir.subVectors(playerPosition, e.position).normalize();
                            bullet.velocity.copy(pushDir).multiplyScalar(6); // Very slow
                        }
                    }
                    // Type 3: Normal Shooter
                    else {
                        const bullet = enemyBulletsDataRef.current.find(b => !b.active);
                        if (bullet) {
                            bullet.active = true;
                            bullet.lifetime = 3.0;
                            bullet.damage = 10;
                            bullet.position.copy(e.position).add(new Vector3(0, 1, 0));
                            pushDir.subVectors(playerPosition, e.position).normalize();
                            bullet.velocity.copy(pushDir).multiplyScalar(15);
                        }
                    }
                }
            }

            // Collision Damage (Melee)
            if (e.type !== 3 && e.type !== 5 && e.type !== 6 && distToPlayer < e.radius + 0.5 && canMove) {
                const dmg = (e.type === 2 ? 30 : 10) * (1 + wave * 0.1); 
                takeDamage(dmg * delta);
            }

            if (e.health <= 0) {
                e.active = false;

                let goldDrops = 0;
                if (e.type === 2) goldDrops = 10; 
                else if (e.type === 1 || e.type === 5) goldDrops = 3; 
                else if (Math.random() < 0.5) goldDrops = 1; 

                for(let g=0; g<goldDrops; g++) {
                    const offset = tempVec.set((Math.random()-0.5), 0, (Math.random()-0.5));
                    spawnDrop(e.position.clone().add(offset), 'GOLD', 10);
                }

                addScore(0); 

                if (e.type === 2) { // Boss Death
                    setBossData({ active: false });
                    const roll = Math.random();
                    let dropped = false;
                    if (wave >= 60 && roll < Math.min(0.20, (wave - 50) * 0.01)) { spawnDrop(e.position, 'ITEM', 0, 'MYTHIC'); dropped = true; }
                    if (!dropped && wave >= 30 && Math.random() < Math.min(0.50, (wave - 20) * 0.02)) { spawnDrop(e.position, 'ITEM', 0, 'LEGENDARY'); dropped = true; }
                    if (!dropped) spawnDrop(e.position, 'ITEM', 0, 'EPIC');
                    spawnDrop(e.position.clone().add(tempVec.set(1,0,0)), 'XP', 1000); 
                } 
                else if (e.type === 1 || e.type === 5) { // Elite Death
                     if (Math.random() > 0.5) spawnDrop(e.position, 'ITEM', 0); 
                     for(let k=0; k<5; k++) {
                         const offset = tempVec.set((Math.random()-0.5)*2, 0, (Math.random()-0.5)*2);
                         spawnDrop(e.position.clone().add(offset), 'XP', 100);
                     }
                }
                else {
                    if (Math.random() > 0.90) spawnDrop(e.position, 'ITEM', 0);
                    else spawnDrop(e.position, 'XP', e.type >= 3 ? 30 : 20);
                }
                dummy.position.set(0, -100, 0);
                if (stunIconsRef.current) stunIconsRef.current.setMatrixAt(i, dummy.matrix);
            } else {
                dummy.position.copy(e.position);
                const aestheticHeight = 2.0; 
                const aestheticWidth = 0.6;

                if (e.type === 0 && e.scale < 0.9) {
                    dummy.scale.set(e.scale, e.scale * 0.5, e.scale); 
                } else {
                    dummy.scale.set(e.scale * aestheticWidth, e.scale * aestheticHeight, e.scale * aestheticWidth);
                }

                const totalHeight = 1.0 * dummy.scale.y;
                if (e.type !== 2) {
                    const bob = Math.abs(Math.sin(state.clock.elapsedTime * 5 + i)) * 0.2;
                    dummy.position.y = (totalHeight / 2) + bob;
                } else {
                    dummy.position.y = totalHeight / 2;
                }
                dummy.lookAt(playerPosition);
            }
        } else {
            dummy.position.set(0, -100, 0);
            if (stunIconsRef.current) stunIconsRef.current.setMatrixAt(i, dummy.matrix);
        }

        dummy.updateMatrix();
        meshRef.current.setMatrixAt(i, dummy.matrix);
    }

    meshRef.current.instanceMatrix.needsUpdate = true;
    if (meshRef.current.instanceColor) meshRef.current.instanceColor.needsUpdate = true;
    if (stunIconsRef.current) stunIconsRef.current.instanceMatrix.needsUpdate = true;

    minimapThrottle.current += 1;
    if (minimapThrottle.current > 10) {
        minimapThrottle.current = 0;
        const activeEnemies = enemies.current.filter(e => e.active).map(e => ({ x: e.position.x, z: e.position.z, type: e.type }));
        updateMinimapEnemies(activeEnemies);
    }
  });

  return (
    <>
        <instancedMesh ref={meshRef} args={[undefined, undefined, MAX_ENEMIES]} frustumCulled={false}>
            <boxGeometry args={[1, 1, 1]} />
            <meshStandardMaterial vertexColors roughness={0.5} metalness={0.2} />
        </instancedMesh>
        <instancedMesh ref={stunIconsRef} args={[undefined, undefined, MAX_ENEMIES]} frustumCulled={false}>
            <torusGeometry args={[0.5, 0.1, 8, 16]} />
            <meshBasicMaterial color="#facc15" />
        </instancedMesh>
    </>
  );
};

performSummon: (amount) => {
    const state = get();
    if (state.inventory.length + amount > state.maxInventorySlots) {
        set({ actionResult: { type: 'CRAFT', success: false, message: "Inventory Full!" } });
        get().addNotification("Inventory Full!", "red", "SYSTEM");
        return false;
    }

    const cost = amount === 1 ? 100 : 900;
    if (state.gems < cost) {
        get().addNotification("Not enough Gems!", "red", "SYSTEM");
        return false;
    }

    const results: Item[] = [];
    for(let i=0; i<amount; i++) {
        const r = Math.random();
        let rarity: Rarity = 'COMMON';

        // Updated Summon Probability
        if (r > 0.995) rarity = 'MYTHIC';
        else if (r > 0.975) rarity = 'LEGENDARY';
        else if (r > 0.90) rarity = 'EPIC';
        else if (r > 0.70) rarity = 'RARE';

        let pool = [...ITEMS_POOL, ...PETS_POOL].filter(it => it.rarity === rarity);
        if (pool.length === 0) pool = ITEMS_POOL;

        const template = pool[Math.floor(Math.random() * pool.length)];
        results.push({ ...template, id: Math.random().toString(), quantity: 1 });
    }

    // Add items to inventory and show results
    set({ 
        gems: state.gems - cost,
        gachaResults: results,
        status: GameStatus.GACHA_REVEAL,
        inventory: [...state.inventory, ...results]
    });

    // Show Notifications for each item
    results.forEach(item => {
         let color = COLORS.rarityCommon;
         if (item.rarity === 'RARE') color = COLORS.rarityRare;
         if (item.rarity === 'EPIC') color = COLORS.rarityEpic;
         if (item.rarity === 'LEGENDARY') color = COLORS.rarityLegendary;
         if (item.rarity === 'MYTHIC') color = COLORS.rarityMythic;
         get().addNotification(`+ ${item.name}`, color, 'ITEM');
    });

    return true;
},

const handleSummon = async (amount: 1 | 10) => {
    setIsSummoning(true);
    // Wait for animation - FAST REVEAL (500ms)
    await new Promise(resolve => setTimeout(resolve, 500));
    const success = performSummon(amount);
    setIsSummoning(false);
};

