// --- SUB COMPONENTS ---

const ItemIcon: React.FC<{ item: Item, size?: number }> = ({ item, size = 24 }) => {
    // Simple icon mapping based on type or name keywords
    let Icon = Star;
    if (item.type === 'WEAPON') Icon = Sword;
    if (item.type === 'ARMOR') Icon = ShieldCheck;
    if (item.type === 'ACCESSORY') Icon = CircleDollarSign; // Placeholder
    if (item.type === 'POTION') Icon = FlaskConical;
    if (item.type === 'PET') Icon = User; // Placeholder

    return <Icon size={size} />;
};

const NotificationItem: React.FC<{ note: any, onRemove: (id: string) => void }> = ({ note, onRemove }) => (
    <motion.div
        initial={{ opacity: 0, x: -50 }}
        animate={{ opacity: 1, x: 0 }}
        exit={{ opacity: 0, scale: 0.8 }}
        className="flex items-center gap-3 bg-slate-900/80 backdrop-blur-md px-4 py-2 rounded-lg border-l-4 shadow-lg pointer-events-auto cursor-pointer hover:bg-slate-800 transition-colors"
        style={{ borderColor: note.color }}
        onClick={() => {
            if (note.action) note.action.onClick();
            onRemove(note.id);
        }}
    >
        <div className="text-white font-bold text-sm drop-shadow-sm">{note.message}</div>
    </motion.div>
);

