const SkillIcon: React.FC<{ icon: any, level: number, cd?: number, maxCd?: number, desc: string }> = ({ icon, level, cd, maxCd, desc }) => {
    if (level <= 0) return null;
    return (
        <div className="relative w-10 h-10 bg-slate-900 rounded-lg border border-slate-600 flex items-center justify-center group">
            {icon}
            <div className="absolute -bottom-1 -right-1 bg-black/80 text-[8px] px-1 rounded text-white font-bold">{level}</div>

            {/* CD Overlay */}
            {cd !== undefined && maxCd !== undefined && cd > 0 && (
                <div 
                    className="absolute inset-0 bg-black/60 rounded-lg origin-bottom transition-all duration-100"
                    style={{ height: `${(cd / maxCd) * 100}%` }}
                />
            )}

            {/* Tooltip */}
            <div className="absolute bottom-full mb-2 left-1/2 -translate-x-1/2 w-40 bg-slate-900 text-slate-200 text-xs p-2 rounded border border-slate-600 opacity-0 group-hover:opacity-100 pointer-events-none transition-opacity z-50">
                {desc}
            </div>
        </div>
    );
};

const Minimap: React.FC = () => {
    const { minimapEnemies, playerPosition } = useGameStore();
    // Simple canvas or div based minimap
    return (
        <div className="absolute bottom-4 right-4 w-48 h-48 bg-slate-900/90 border-2 border-slate-600 rounded-full overflow-hidden shadow-xl opacity-80 hover:opacity-100 transition-opacity">
            <div className="relative w-full h-full">
                {/* Player */}
                <div className="absolute top-1/2 left-1/2 w-2 h-2 bg-blue-500 rounded-full -translate-x-1/2 -translate-y-1/2 z-10 border border-white" />

                {/* Enemies */}
                {minimapEnemies.map((e, i) => {
                    // Relative pos scaled
                    const dx = e.x - playerPosition.x;
                    const dz = e.z - playerPosition.z;
                    const scale = 2; // Minimap scale

                    if (Math.abs(dx) > 40 || Math.abs(dz) > 40) return null; // Clip

                    const cx = 50 + (dx * scale);
                    const cy = 50 + (dz * scale);

                    let color = 'bg-red-500';
                    if (e.type === 2) color = 'bg-purple-600 w-3 h-3'; // Boss
                    else if (e.type === 1) color = 'bg-orange-500 w-2 h-2'; // Elite

                    return (
                        <div 
                            key={i} 
                            className={`absolute rounded-full ${color} w-1.5 h-1.5`} 
                            style={{ left: `${cx}%`, top: `${cy}%` }}
                        />
                    );
                })}
            </div>
        </div>
    );
};

