                                    <div className="absolute inset-0 border-4 border-yellow-400/30 animate-pulse rounded-xl pointer-events-none" />
                                )}
                            </motion.div>
                        ))}
                    </div>

                    <div className="flex gap-4 mt-8">
                        <button
                            onClick={() => handleSummon(1)}
                            className="px-6 py-3 bg-purple-800 hover:bg-purple-700 text-white font-bold rounded-xl shadow-xl border border-purple-500 flex items-center gap-2 transition-transform hover:scale-105"
                        >
                            <Gem size={16} className="text-emerald-400"/>
                            <span>SUMMON 1x (100)</span>
                        </button>
                        <button
                            onClick={() => handleSummon(10)}
                            className="px-6 py-3 bg-yellow-900/80 hover:bg-yellow-800 text-white font-bold rounded-xl shadow-xl border border-yellow-500 flex items-center gap-2 transition-transform hover:scale-105"
                        >
                            <Sparkles size={16} className="text-yellow-400"/>
                            <span>SUMMON 10x (900)</span>
                        </button>
                        <button
                            onClick={clearGachaResults}
                            className="px-8 py-3 bg-slate-700 hover:bg-slate-600 text-white font-bold rounded-xl shadow-xl border border-slate-500 transition-transform hover:scale-105"
                        >
                            CLOSE
                        </button>
                    </div>
                </motion.div>
            )}
        </AnimatePresence>
      </div>
    </div>
  );
};

import { create } from 'zustand';
import { Vector3 } from 'three';
import { 
    GameStatus, HeroClass, Item, Upgrade, PlayerStats, 
    ActionResult, GameNotification, DropData, CrateData, 
    Obstacle, BulletData, EnemyData, SkillLevels, 
    PassiveSkillState, BossData, Rarity 
} from './types';
import { 
    ITEMS_POOL, PETS_POOL, COLORS, ARENA_SIZE, 
    HERO_STATS, UPGRADES_POOL 
} from './constants';

interface GameStore {
    status: GameStatus;
    hero: HeroClass;
    level: number;
    experience: number;
    experienceToNextLevel: number;
    health: number;
    mana: number;
    gems: number;
    score: number;

    stats: PlayerStats;
    inventory: Item[];
    maxInventorySlots: number;
    equipment: {
        weapon: Item | null;
        armor: Item | null;
        accessory: Item | null;
        pet: Item | null;
    };

    skills: {
        q: number;
        r: number;
        e: number;
        dash: number;
    };
    skillLevels: SkillLevels;
    passiveSkillState: PassiveSkillState;
    activeAbilityQ: string | null;

    earthwall: { active: boolean; position: Vector3; radius: number };
    rageMode: boolean;
    isInvincible: boolean;
    reviveAnimTimer: number;
    levelUpVisualTimer: number;

    wave: number;
    waveTimer: number;
    bossData: BossData;

    obstacles: Obstacle[];
    crates: CrateData[];
    drops: DropData[];

    notifications: GameNotification[];
    actionResult: ActionResult | null;
    gachaResults: Item[];
    sellConfirmationItem: Item | null;

    playerPosition: Vector3;
    minimapEnemies: {x: number, z: number, type: number}[];
