    addNotification: (message: string, color: string, type: 'ITEM' | 'BOSS' | 'SYSTEM') => void;
    removeNotification: (id: string) => void;
    performSummon: (amount: number) => boolean;
    sellItem: (item: Item) => void;
    toggleInventory: () => void;
    toggleCharacterSheet: () => void;
    openSpecificShop: (shopType: string) => void;
    setPlayerPosition: (pos: Vector3) => void;
    triggerSkillCooldown: (skill: 'q'|'r'|'e'|'dash') => void;
    tickCooldowns: (delta: number) => void;
    takeDamage: (amount: number) => void;
    useMana: (amount: number) => boolean;
    triggerInvincibility: (duration: number) => void;
    breakCrate: (id: number) => void;
    activateRage: () => void;
    activateEarthwall: (pos: Vector3) => void;
    activateWarVitality: () => void;
    activateSprint: () => void;
    addScore: (amount: number) => void;
    spawnDrop: (pos: Vector3, type: 'ITEM' | 'GOLD' | 'XP' | 'GEM', value: number, rarity?: Rarity) => void;
    collectDrop: (id: number) => void;
    advanceWave: () => void;
    setBossData: (data: Partial<BossData>) => void;
    updateMinimapEnemies: (enemies: {x: number, z: number, type: number}[]) => void;
    heal: (amount: number) => void;
    updatePassiveCooldowns: (cooldowns: Partial<PassiveSkillState>) => void;
    damageCrate: (id: number, amount: number) => void;
    setSellConfirmationItem: (item: Item | null) => void;
    clearGachaResults: () => void;
}

// Helper to generate obstacles (simple version)
const generateObstacles = (): Obstacle[] => {
    const obs: Obstacle[] = [];
    for(let i=0; i<30; i++) {
        const angle = Math.random() * Math.PI * 2;
        const radius = 20 + Math.random() * (ARENA_SIZE/2 - 25);
        obs.push({
            id: i,
            position: new Vector3(Math.cos(angle) * radius, 0, Math.sin(angle) * radius),
            radius: 1,
            type: Math.random() > 0.3 ? 'TREE' : 'ROCK',
            scale: 1 + Math.random()
        });
    }
    return obs;
};

// Initial state helpers
const INITIAL_STATS: PlayerStats = {
    maxHealth: 100, maxMana: 100, regen: 1, manaRegen: 1, moveSpeed: 10,
    damage: 10, fireRate: 1.0, projectileSpeed: 20, multishot: 1, spread: 0.2,
    dashCooldown: 3, cooldownReduction: 0, magnetRadius: 5, critRate: 0.05,
    critDamage: 1.5, defense: 0, skillDamage: 1, knockback: 0.5, dodge: 0
};

export const useGameStore = create<GameStore>((set, get) => ({
    status: GameStatus.MENU,
    hero: 'ARCHER', // Default
    level: 1,
    experience: 0,
    experienceToNextLevel: 100,
    health: 100,
    mana: 100,
    gems: 100,
    score: 0,

    stats: { ...INITIAL_STATS },
    inventory: [],
    maxInventorySlots: 50,
    equipment: { weapon: null, armor: null, accessory: null, pet: null },

    skills: { q: 0, r: 0, e: 0, dash: 0 },
    skillLevels: { 
        orbital: 0, thunder: 0, regen: 0, magnet: 0, dash: 0, weapon: 0, barrier: 0, 
        storm: 0, special: 0, piercing: 0, gravity: 0, rage: 0, burning: 0, 
        freezing: 0, freezeSpell: 0, stamp: 0 
    },
    passiveSkillState: {
        orbitalCooldown: 0, orbitalMaxCooldown: 4,
        thunderCooldown: 0, thunderMaxCooldown: 2,
        burningCooldown: 0, burningMaxCooldown: 8,
        freezingCooldown: 0, freezingMaxCooldown: 7,
        blizzardCooldown: 0, blizzardMaxCooldown: 14,
        stampCooldown: 0, stampMaxCooldown: 12,
        stormCooldown: 0, stormMaxCooldown: 15
    },
    activeAbilityQ: null,

    earthwall: { active: false, position: new Vector3(), radius: 5 },
    rageMode: false,
    isInvincible: false,
    reviveAnimTimer: 0,
    levelUpVisualTimer: 0,

    wave: 1,
    waveTimer: 0,
    bossData: { active: false, name: '', hp: 0, maxHp: 100 },

    obstacles: generateObstacles(),
    crates: [],
    drops: [],

    notifications: [],
    actionResult: null,
    gachaResults: [],
    sellConfirmationItem: null,

    playerPosition: new Vector3(),
    minimapEnemies: [],
    potionCooldown: 0,

    setStatus: (status) => set({ status }),

    addNotification: (message, color, type) => {
        const id = Math.random().toString();
        set(state => ({ notifications: [...state.notifications, { id, message, color, type }] }));
        setTimeout(() => get().removeNotification(id), 3000);
    },

    removeNotification: (id) => {
        set(state => ({ notifications: state.notifications.filter(n => n.id !== id) }));
    },

    performSummon: (amount) => {
        const state = get();
        if (state.inventory.length + amount > state.maxInventorySlots) {
            set({ actionResult: { type: 'CRAFT', success: false, message: "Inventory Full!" } });
            get().addNotification("Inventory Full!", "red", "SYSTEM");
            return false;
        }

        const cost = amount === 1 ? 100 : 900;
        if (state.gems < cost) {
            get().addNotification("Not enough Gems!", "red", "SYSTEM");
            return false;
        }

        const results: Item[] = [];
        for(let i=0; i<amount; i++) {
            const r = Math.random();
            let rarity: Rarity = 'COMMON';

            // Summon Probability
            if (r > 0.995) rarity = 'MYTHIC';
            else if (r > 0.975) rarity = 'LEGENDARY';
            else if (r > 0.90) rarity = 'EPIC';
            else if (r > 0.70) rarity = 'RARE';

            let pool = [...ITEMS_POOL, ...PETS_POOL].filter(it => it.rarity === rarity);
            if (pool.length === 0) pool = ITEMS_POOL;

            const template = pool[Math.floor(Math.random() * pool.length)];
            results.push({ ...template, id: Math.random().toString(), quantity: 1 });
        }

        // Add items to inventory and show results
        set({ 
            gems: state.gems - cost,
            gachaResults: results,
            status: GameStatus.GACHA_REVEAL,
            inventory: [...state.inventory, ...results]
        });

        // Show Notifications for each item
        results.forEach(item => {
             let color = COLORS.rarityCommon;
             if (item.rarity === 'RARE') color = COLORS.rarityRare;
             if (item.rarity === 'EPIC') color = COLORS.rarityEpic;
             if (item.rarity === 'LEGENDARY') color = COLORS.rarityLegendary;
             if (item.rarity === 'MYTHIC') color = COLORS.rarityMythic;
             get().addNotification(`+ ${item.name}`, color, 'ITEM');
        });

        return true;
    },

    sellItem: (item) => {
        const value = Math.floor(item.price * 0.3);
        set(state => ({
            gems: state.gems + value,
            inventory: state.inventory.filter(i => i.id !== item.id),
            sellConfirmationItem: null
        }));
        get().addNotification(`Sold ${item.name} for ${value} G`, COLORS.uiAccent, 'SYSTEM');
    },

    toggleInventory: () => {
        const state = get();
        if (state.status === GameStatus.PLAYING) set({ status: GameStatus.INVENTORY });
        else if (state.status === GameStatus.INVENTORY) set({ status: GameStatus.PLAYING });
    },

    toggleCharacterSheet: () => {
         get().toggleInventory();
    },

    openSpecificShop: (shopType) => {
        set({ status: GameStatus.SHOP });
    },

    setPlayerPosition: (pos) => set({ playerPosition: pos }),

    triggerSkillCooldown: (skill) => {
        set(state => ({ skills: { ...state.skills, [skill]: 10 } }));
    },

    tickCooldowns: (delta) => {
        set(state => {
            const skills = { ...state.skills };
            if (skills.q > 0) skills.q = Math.max(0, skills.q - delta);
            if (skills.r > 0) skills.r = Math.max(0, skills.r - delta);
            if (skills.e > 0) skills.e = Math.max(0, skills.e - delta);
            if (skills.dash > 0) skills.dash = Math.max(0, skills.dash - delta);

            let potionCooldown = state.potionCooldown;
            if (potionCooldown > 0) potionCooldown = Math.max(0, potionCooldown - delta);

            return { skills, potionCooldown };
        });
    },

    takeDamage: (amount) => {
        const state = get();
        if (state.isInvincible) return;

        const def = state.stats.defense;
        const damage = Math.max(1, amount * (100 / (100 + def)));

        const newHp = Math.max(0, state.health - damage);
        set({ health: newHp });

        if (newHp <= 0) {
            // Check for Revive
            const reviveItem = state.inventory.find(i => i.type === 'REVIVE');
            const petRevive = state.equipment.pet?.petSkill === 'REVIVE' && (state.equipment.pet?.petCooldown || 0) <= 0;

            if (reviveItem) {
                get().addNotification("REVIVED BY ANKH!", "yellow", "SYSTEM");
                set({ 
                    health: state.stats.maxHealth, 
                    inventory: state.inventory.filter(i => i.id !== reviveItem.id),
                    reviveAnimTimer: 2.0,
                    isInvincible: true
                });
                setTimeout(() => set({ isInvincible: false }), 2000);
            } else if (petRevive) {
                 get().addNotification("REVIVED BY PHOENIX!", "orange", "SYSTEM");
                 set({ 
                    health: state.stats.maxHealth, 
                    reviveAnimTimer: 2.0,
                    isInvincible: true
                });
                setTimeout(() => set({ isInvincible: false }), 2000);
            } else {
                set({ status: GameStatus.GAME_OVER });
            }
        }
    },

    useMana: (amount) => {
        const state = get();
        if (state.mana >= amount) {
            set({ mana: state.mana - amount });
            return true;
        }
        return false;
    },

    triggerInvincibility: (duration) => {
        set({ isInvincible: true });
        setTimeout(() => set({ isInvincible: false }), duration * 1000);
    },

    breakCrate: (id) => {
         set(state => ({ crates: state.crates.filter(c => c.id !== id) }));
    },

    activateRage: () => {
        set({ rageMode: true });
        setTimeout(() => set({ rageMode: false }), 4000);
    },

    activateEarthwall: (pos) => {
        set({ earthwall: { active: true, position: pos, radius: 5 } });
        window.dispatchEvent(new CustomEvent('barrier-trigger', { detail: { position: pos, radius: 5, force: 10 } }));
        setTimeout(() => set({ earthwall: { ...get().earthwall, active: false } }), 4000);
    },

    activateWarVitality: () => {
        const interval = setInterval(() => {
            get().heal(10);
        }, 1000);
        setTimeout(() => clearInterval(interval), 6000);
    },

    activateSprint: () => {
        set({ isInvincible: true }); 
        setTimeout(() => set({ isInvincible: false }), 4000);
    },

    addScore: (amount) => set(state => ({ score: state.score + amount })),

    spawnDrop: (pos, type, value, rarity) => {
        const id = Math.random();
        let item: Item | null = null;
        if (type === 'ITEM') {
            let pool = [...ITEMS_POOL];
            if (rarity) pool = pool.filter(i => i.rarity === rarity);
            if (pool.length > 0) {
                const tmpl = pool[Math.floor(Math.random() * pool.length)];
                item = { ...tmpl, id: Math.random().toString(), quantity: 1 };
            } else {
                return;
            }
        }

        set(state => ({
            drops: [...state.drops, { 
                id, position: pos.clone(), type, value, item, active: true, rotation: 0 
            }]
        }));
    },

    collectDrop: (id) => {
        const state = get();
        const drop = state.drops.find(d => d.id === id);
        if (!drop) return;

        if (drop.type === 'XP') {
            const nextLevel = state.level + 1;
            const xpNeeded = state.experienceToNextLevel;
            let newXp = state.experience + drop.value;
            let newLevel = state.level;

            if (newXp >= xpNeeded) {
                newXp -= xpNeeded;
                newLevel++;
                set({ 
                    level: newLevel, 
                    experience: newXp, 
                    experienceToNextLevel: Math.floor(xpNeeded * 1.2),
                    status: GameStatus.LEVEL_UP,
                    levelUpVisualTimer: 3.0
                });
            } else {
                set({ experience: newXp });
            }
        } else if (drop.type === 'GOLD') {
            set({ score: state.score + drop.value });
        } else if (drop.type === 'GEM') {
            set({ gems: state.gems + drop.value });
        } else if (drop.type === 'ITEM' && drop.item) {
             set({ inventory: [...state.inventory, drop.item] });
             get().addNotification(`Picked up ${drop.item.name}`, "white", "ITEM");
        }

        set({ drops: state.drops.filter(d => d.id !== id) });
    },

    advanceWave: () => {
        set(state => ({ wave: state.wave + 1, waveTimer: 0 }));
    },

    setBossData: (data) => set(state => ({ bossData: { ...state.bossData, ...data } })),

    updateMinimapEnemies: (enemies) => set({ minimapEnemies: enemies }),

    heal: (amount) => {
        set(state => ({ health: Math.min(state.stats.maxHealth, state.health + amount) }));
    },

    updatePassiveCooldowns: (cooldowns) => {
        set(state => ({ passiveSkillState: { ...state.passiveSkillState, ...cooldowns } }));
    },

    damageCrate: (id, amount) => {
         set(state => {
             const crates = state.crates.map(c => {
                 if (c.id === id) return { ...c, hp: c.hp - amount };
                 return c;
             });
             return { crates: crates.filter(c => c.hp > 0) };
         });
    },

    setSellConfirmationItem: (item) => set({ sellConfirmationItem: item }),

    clearGachaResults: () => set({ status: GameStatus.PLAYING, gachaResults: [] }),
}));

import React, { useRef, useEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import { InstancedMesh, Object3D, Vector3, Color } from 'three';
import { useGameStore } from '../store';
import { ARENA_SIZE, COLORS } from '../constants';
import { GameStatus, EnemyData, BulletData } from '../types';
import { SpatialHashGrid } from '../utils/SpatialHashGrid';

const MAX_ENEMIES = 400;

const dummy = new Object3D();
const tempVec = new Vector3();
const tempColor = new Color();
const pushDir = new Vector3();

// Enemy Types Map
// 0: Basic
// 1: Elite (Melee)
// 2: Boss
// 3: Ranged (Fast)
// 4: Speedy (New)
// 5: Elite Shooter (New)
// 6: Ranged (Slow)

interface EnemyManagerProps {
  bulletsDataRef: React.MutableRefObject<BulletData[]>;
  enemyBulletsDataRef: React.MutableRefObject<BulletData[]>;
  enemiesDataRef: React.MutableRefObject<EnemyData[]>;
  spatialGrid: React.MutableRefObject<SpatialHashGrid>;
}

export const EnemyManager: React.FC<EnemyManagerProps> = ({ bulletsDataRef, enemyBulletsDataRef, enemiesDataRef, spatialGrid }) => {
  const meshRef = useRef<InstancedMesh>(null);
  const stunIconsRef = useRef<InstancedMesh>(null);

  const enemies = enemiesDataRef;

  const spawnTimer = useRef(0);
  const dotTicker = useRef(0);
  const waveState = useRef({ wave: 1, bossSpawned: false, eliteSpawned: false });
  const minimapThrottle = useRef(0); 

  useEffect(() => {
    const handleBarrier = (e: CustomEvent) => {
        const { position, radius, force } = e.detail;
        enemies.current.forEach(enemy => {
            if (enemy.active) {
                const dist = enemy.position.distanceTo(position);
                if (dist < radius) {
                    const dir = new Vector3().subVectors(enemy.position, position).normalize();
                    enemy.position.add(dir.multiplyScalar(force));
                    enemy.freezeTimer = 0.5;
                }
            }
        });
    };
    window.addEventListener('barrier-trigger', handleBarrier as EventListener);
    return () => window.removeEventListener('barrier-trigger', handleBarrier as EventListener);
  }, []);

  useFrame((state, delta) => {
    // Access state directly to prevent re-renders of the component and fix potential stale access issues
    const gameState = useGameStore.getState();
    const { 
        status, level, wave, waveTimer, advanceWave, 
        addNotification, setBossData, earthwall, updateMinimapEnemies, 
        obstacles, playerPosition, addScore, takeDamage, spawnDrop 
    } = gameState;

    if (status !== GameStatus.PLAYING) return;
    if (!meshRef.current) return;

    spatialGrid.current.clear();
    const activeBullets = bulletsDataRef.current;

    activeBullets.forEach(b => { 
        if(b.active && b.type === 'BLACKHOLE') {
            b.currentPullCount = 0; 
        }
    });

    if (!meshRef.current.userData.enemies) {
        meshRef.current.userData.enemies = enemies.current;
    }

    if (waveTimer > 30) {
        advanceWave();
    }

    if (wave !== waveState.current.wave) {
        waveState.current.wave = wave;
        waveState.current.bossSpawned = false;
        waveState.current.eliteSpawned = false;
    }

    spawnTimer.current += delta;
    const spawnRate = Math.max(0.05, 0.8 - (level * 0.02) - (wave * 0.05));

    if (spawnTimer.current > spawnRate) {
        spawnTimer.current = 0;
        const enemy = enemies.current.find(e => !e.active);
        if (enemy) {
            enemy.active = true;
            enemy.burnTimer = 0;
            enemy.poisonTimer = 0;
            enemy.freezeTimer = 0;
            enemy.slowTimer = 0;
            enemy.slowFactor = 0;
            enemy.bossPattern = 0;
            enemy.bossTimer = 0;
            enemy.bossAngle = 0;

            let angle, dist, spawnPos;
            do {
                angle = Math.random() * Math.PI * 2;
                dist = (ARENA_SIZE / 2) - 5;
                spawnPos = new Vector3(Math.cos(angle) * dist, 0, Math.sin(angle) * dist);
            } while (spawnPos.distanceTo(playerPosition) < 20);

            enemy.position.copy(spawnPos);

            const hpMult = 1 + (wave * 0.5) + (level * 0.1);
            // UPDATED: Speed progression 50% slower (0.025 instead of 0.05)
            const speedMult = 1 + (wave * 0.025);
            const globalHpReduction = 0.4;
            const r = Math.random();

            let isBoss = false;

            if (wave % 10 === 0 && !waveState.current.bossSpawned) {
                isBoss = true;
                waveState.current.bossSpawned = true;
                const bossName = wave % 20 === 0 ? "VOID REAPER" : "ABYSS LORD";
                addNotification(`⚠️ ${bossName} APPEARED ⚠️`, COLORS.enemyBoss, 'BOSS');
                setBossData({ active: true, name: bossName, hp: 1, maxHp: 1 });

                enemy.type = 2; 
                // UPDATED: Boss HP 20% less
                enemy.health = (2000 + (level * 250) + (wave * 100)) * hpMult * globalHpReduction * 0.8;
                enemy.speed = (2.5 + (level * 0.1)) * speedMult;
                enemy.radius = 2.5;
                enemy.scale = 3.0; 
                setBossData({ hp: enemy.health, maxHp: enemy.health });

            } else {
                // UPDATED: Elite Monster Logic (Spawn at any wave, 2x more spawn)
                const isElite = (r < (0.05 + (wave * 0.01))) || (wave % 5 === 0 && !waveState.current.eliteSpawned);

                if (wave % 5 === 0 && !waveState.current.eliteSpawned) {
                     waveState.current.eliteSpawned = true;
                     addNotification("⚠️ ELITE SQUAD", COLORS.enemyElite, 'BOSS');
                }

                if (isElite) {
                    if (Math.random() > 0.7) {
                        // UPDATED: New Elite Shooter (Type 5)
                        enemy.type = 5; 
                        enemy.health = (120 + (level * 15)) * hpMult * globalHpReduction;
                        enemy.speed = (3.5 + (level * 0.1)) * speedMult;
                        enemy.radius = 1.8;
                        enemy.scale = 1.6;
                    } else {
                        // Standard Elite (Type 1)
                        enemy.type = 1; 
                        enemy.health = (150 + (level * 20)) * hpMult * globalHpReduction;
                        enemy.speed = (4 + (level * 0.1)) * speedMult;
                        enemy.radius = 1.5;
                        enemy.scale = 1.5; 
                    }
                } 
                // UPDATED: Ranged Spawn Logic (50% less)
                else if (wave >= 3 && r > 0.925) { 
                    if (Math.random() > 0.5) {
                        enemy.type = 3; // Normal Ranged
                        enemy.health = (15 + (level * 5)) * hpMult * globalHpReduction;
                        enemy.speed = 3.0 * speedMult;
                        enemy.radius = 0.8;
                        enemy.scale = 1.0; 
                    } else {
                        // UPDATED: Slow Ranged (Type 6)
                        enemy.type = 6;
                        enemy.health = (20 + (level * 6)) * hpMult * globalHpReduction;
                        enemy.speed = 2.0 * speedMult;
                        enemy.radius = 0.8;
                        enemy.scale = 1.1;
                    }
                } 
                // UPDATED: Speedy Monster (Type 4) - 50% HP, 2x Speed
                else if (wave >= 2 && r > 0.85) { 
                    enemy.type = 4;
                    const baseHp = (10 + (level * 4)) * hpMult * globalHpReduction;
                    enemy.health = baseHp * 0.5;
                    const baseSpeed = (4 + (level * 0.15)) * speedMult;
                    enemy.speed = baseSpeed * 2.0;
                    enemy.radius = 0.6;
                    enemy.scale = 0.8;
                }
                // Basic Enemy (Type 0)
                else {
                    enemy.type = 0; 
                    enemy.health = (10 + (level * 4)) * hpMult * globalHpReduction;
                    enemy.speed = (4 + (level * 0.15)) * speedMult;
                    enemy.radius = 0.6;
                    enemy.scale = 1.0;
                }
            }
            enemy.maxHealth = enemy.health;
        }
    }

    dotTicker.current += delta;
    const shouldTickDoT = dotTicker.current > 0.5;
    if (shouldTickDoT) dotTicker.current = 0;

    const time = state.clock.getElapsedTime();

    for (let i = 0; i < MAX_ENEMIES; i++) {
        const e = enemies.current[i];
        if (e.active) {
            spatialGrid.current.add(i, e.position.x, e.position.z);

            const distToPlayer = e.position.distanceTo(playerPosition);
            let currentSpeed = e.speed;
            let canMove = true;

            if (e.type === 2) {
                 const currentBossData = gameState.bossData;
                 if (Math.abs(currentBossData.hp - e.health) > 5) {
                     setBossData({ hp: e.health });
                 }
            }

            // DoT Logic
            if (e.burnTimer && e.burnTimer > 0) {
                e.burnTimer -= delta;
                if (shouldTickDoT) {
                    const dmg = (e.burnDamage || 5) * 0.5;
                    e.health -= dmg;
                    window.dispatchEvent(new CustomEvent('damage', { detail: { position: e.position, damage: dmg, isDoT: true, damageType: 'FIRE' } }));
                }
            }
            if (e.poisonTimer && e.poisonTimer > 0) {
                e.poisonTimer -= delta;
                if (shouldTickDoT) {
                    const dmg = (e.poisonDamage || 3) * 0.5;
                    e.health -= dmg;
                    window.dispatchEvent(new CustomEvent('damage', { detail: { position: e.position, damage: dmg, isDoT: true, damageType: 'POISON' } }));
                }
            }

            if (e.freezeTimer && e.freezeTimer > 0) {
                e.freezeTimer -= delta;
                canMove = false;
                if (stunIconsRef.current) {
                    dummy.position.copy(e.position).add(tempVec.set(0, (e.scale * 1.8) + 0.5, 0)); 
                    dummy.rotation.set(time * 5, time * 3, 0);
                    dummy.scale.set(0.5, 0.5, 0.5);
                    dummy.updateMatrix();
                    stunIconsRef.current.setMatrixAt(i, dummy.matrix);
                } 
            } else {
                if (stunIconsRef.current) {
                    dummy.position.set(0, -100, 0);
                    dummy.updateMatrix();
                    stunIconsRef.current.setMatrixAt(i, dummy.matrix);
                }
            }

            if (e.slowTimer && e.slowTimer > 0) {
                e.slowTimer -= delta;
                currentSpeed *= (1 - (e.slowFactor || 0.5));
            }

            // --- COLOR LOGIC ---
            if (e.freezeTimer && e.freezeTimer > 0) tempColor.set('#3b82f6');
            else if (e.burnTimer && e.burnTimer > 0) tempColor.set('#ef4444');
            else {
                if (e.type === 2) tempColor.set(COLORS.enemyBoss);
                else if (e.type === 3) tempColor.set(COLORS.enemyShooter);
                else if (e.type === 4) tempColor.set(COLORS.enemySpeedy); // New Color
                else if (e.type === 5) tempColor.set(COLORS.enemyEliteShooter); // New Color
                else if (e.type === 6) tempColor.set(COLORS.enemySlowShooter); // New Color
                else if (e.type === 1) {
                     if (e.scale > 1.4) tempColor.set(COLORS.enemyElite);
                     else tempColor.set(COLORS.enemyOrc);
                }
                else tempColor.set(COLORS.enemySlime);

                if (e.poisonTimer && e.poisonTimer > 0) tempColor.lerp(new Color('#4ade80'), 0.5);
            }

            meshRef.current.setColorAt(i, tempColor);

            if (canMove) {
                let moved = false;
                // Blackhole & Earthwall logic ...
                for(let b=0; b < activeBullets.length; b++) {
                    const bullet = activeBullets[b];
                    if (bullet.active && bullet.type === 'BLACKHOLE') {
                        const max = bullet.maxPullCount || 8;
                        const current = bullet.currentPullCount || 0;
                        if (current < max && e.position.distanceTo(bullet.position) < 15.0) {
                            pushDir.subVectors(bullet.position, e.position).normalize();
                            e.position.add(pushDir.multiplyScalar(currentSpeed * 2.0 * delta));
                            moved = true;
                            bullet.currentPullCount = current + 1;
                        }
                    }
                }
                if (earthwall.active) {
                    const distToWall = e.position.distanceTo(earthwall.position);
                    if (distToWall < earthwall.radius + e.radius) {
                        pushDir.subVectors(e.position, earthwall.position).normalize();
                        if (pushDir.lengthSq() === 0) pushDir.set(1, 0, 0);
                        e.position.copy(earthwall.position).add(pushDir.multiplyScalar(earthwall.radius + e.radius));
                        moved = true; 
                    }
                }

                if (!moved) {
                    const nextPos = e.position.clone();
                    // Shooters keep distance
                    if ((e.type === 3 || e.type === 5 || e.type === 6) && distToPlayer > 15) { 
                         tempVec.subVectors(playerPosition, e.position).normalize();
                         nextPos.add(tempVec.multiplyScalar(currentSpeed * delta));
                    } else if (e.type === 2 && distToPlayer > 10) { // Boss keeps slight distance
                         tempVec.subVectors(playerPosition, e.position).normalize();
                         nextPos.add(tempVec.multiplyScalar(currentSpeed * delta));
                    } else if (e.type !== 3 && e.type !== 5 && e.type !== 6 && e.type !== 2) {
                         tempVec.subVectors(playerPosition, e.position).normalize();
                         nextPos.add(tempVec.multiplyScalar(currentSpeed * delta));
                    }

                    for(const obs of obstacles) {
                        const distToObs = nextPos.distanceTo(obs.position);
                        const minDist = obs.radius + e.radius;
                        if (distToObs < minDist) {
                            pushDir.subVectors(nextPos, obs.position).normalize();
                            nextPos.copy(obs.position).add(pushDir.multiplyScalar(minDist));
                        }
                    }
                    e.position.copy(nextPos);
                }
            }

            // --- SHOOTING LOGIC ---
            e.stateTimer = (e.stateTimer || 0) + delta;

            // BOSS AI (Bullet Hell)
            if (e.type === 2 && canMove) {
                // Cycle Patterns every 5 seconds
                e.bossTimer = (e.bossTimer || 0) + delta;
                if (e.bossTimer > 5.0) {
                    e.bossTimer = 0;
                    e.bossPattern = ((e.bossPattern || 0) + 1) % 3;
                }

                const pattern = e.bossPattern || 0;

                // Pattern 0: Spiral
                if (pattern === 0) {
                    if (e.stateTimer > 0.05) { // Rapid fire
                        e.stateTimer = 0;
                        e.bossAngle = (e.bossAngle || 0) + 0.3;
                        const bullet = enemyBulletsDataRef.current.find(b => !b.active);
                        if (bullet) {
                            bullet.active = true;
                            bullet.lifetime = 4.0;
                            bullet.damage = 15; // Moderate dmg
                            bullet.position.copy(e.position).add(new Vector3(0, 1.5, 0));
                            bullet.velocity.set(Math.cos(e.bossAngle), 0, Math.sin(e.bossAngle)).multiplyScalar(10);
                        }
                    }
                } 
                // Pattern 1: Nova (Bursts)
                else if (pattern === 1) {
                     if (e.stateTimer > 0.8) {
                        e.stateTimer = 0;
                        for(let k=0; k<12; k++) {
                            const bullet = enemyBulletsDataRef.current.find(b => !b.active);
                            if (bullet) {
                                bullet.active = true;
                                bullet.lifetime = 4.0;
                                bullet.damage = 15;
                                bullet.position.copy(e.position).add(new Vector3(0, 1.5, 0));
                                const a = (Math.PI * 2 * k) / 12;
                                bullet.velocity.set(Math.cos(a), 0, Math.sin(a)).multiplyScalar(8);
                            }
                        }
                     }
                }
                // Pattern 2: Targeted Stream
                else if (pattern === 2) {
                    if (e.stateTimer > 0.15) {
                        e.stateTimer = 0;
                        const bullet = enemyBulletsDataRef.current.find(b => !b.active);
                        if (bullet) {
                            bullet.active = true;
                            bullet.lifetime = 4.0;
                            bullet.damage = 20; // High dmg
                            bullet.position.copy(e.position).add(new Vector3(0, 1.5, 0));

                            tempVec.subVectors(playerPosition, e.position).normalize();
                            // Slight spread
                            const spread = (Math.random() - 0.5) * 0.3;
                            tempVec.applyAxisAngle(new Vector3(0,1,0), spread);
                            bullet.velocity.copy(tempVec).multiplyScalar(14);
                        }
                    }
                }
            }
            // Standard Shooters
            else if ((e.type === 3 || e.type === 5 || e.type === 6) && canMove) {
                const fireRate = e.type === 5 ? 1.5 : (e.type === 6 ? 3.0 : 2.0); 

                if (e.stateTimer > fireRate && distToPlayer < 25) {
                    e.stateTimer = 0;

                    // Type 5: Elite Shooter (Spread)
                    if (e.type === 5) {
                        const baseDir = new Vector3().subVectors(playerPosition, e.position).normalize();
                        for(let k=-1; k<=1; k++) {
                             const bullet = enemyBulletsDataRef.current.find(b => !b.active);
                             if (bullet) {
                                bullet.active = true;
                                bullet.lifetime = 3.0;
                                bullet.damage = 10;
                                bullet.position.copy(e.position).add(new Vector3(0, 1, 0));
                                const dir = baseDir.clone().applyAxisAngle(new Vector3(0,1,0), k * 0.3);
                                bullet.velocity.copy(dir).multiplyScalar(12);
                             }
                        }
                    }
                    // Type 6: Slow Shooter (50% Dmg, Slow speed)
                    else if (e.type === 6) {
                        const bullet = enemyBulletsDataRef.current.find(b => !b.active);
                        if (bullet) {
                            bullet.active = true;
                            bullet.lifetime = 6.0; 
                            bullet.damage = 5; 
                            bullet.position.copy(e.position).add(new Vector3(0, 1, 0));
                            pushDir.subVectors(playerPosition, e.position).normalize();
                            bullet.velocity.copy(pushDir).multiplyScalar(6); 
                        }
                    }
                    // Type 3: Normal Shooter
                    else {
                        const bullet = enemyBulletsDataRef.current.find(b => !b.active);
                        if (bullet) {
                            bullet.active = true;
                            bullet.lifetime = 3.0;
                            bullet.damage = 10;
                            bullet.position.copy(e.position).add(new Vector3(0, 1, 0));
                            pushDir.subVectors(playerPosition, e.position).normalize();
                            bullet.velocity.copy(pushDir).multiplyScalar(15);
                        }
                    }
                }
            }

            // Collision Damage (Melee)
            if (e.type !== 3 && e.type !== 5 && e.type !== 6 && distToPlayer < e.radius + 0.5 && canMove) {
                const dmg = (e.type === 2 ? 30 : 10) * (1 + wave * 0.1); 
                takeDamage(dmg * delta);
            }

            if (e.health <= 0) {
                e.active = false;

                let goldDrops = 0;
                if (e.type === 2) goldDrops = 10; 
                else if (e.type === 1 || e.type === 5) goldDrops = 3; 
                else if (Math.random() < 0.5) goldDrops = 1; 

                for(let g=0; g<goldDrops; g++) {
                    const offset = tempVec.set((Math.random()-0.5), 0, (Math.random()-0.5));
                    spawnDrop(e.position.clone().add(offset), 'GOLD', 10);
                }

                addScore(0); 

                if (e.type === 2) { // Boss Death
                    setBossData({ active: false });
                    const roll = Math.random();
                    let dropped = false;
                    if (wave >= 60 && roll < Math.min(0.20, (wave - 50) * 0.01)) { spawnDrop(e.position, 'ITEM', 0, 'MYTHIC'); dropped = true; }
                    if (!dropped && wave >= 30 && Math.random() < Math.min(0.50, (wave - 20) * 0.02)) { spawnDrop(e.position, 'ITEM', 0, 'LEGENDARY'); dropped = true; }
                    if (!dropped) spawnDrop(e.position, 'ITEM', 0, 'EPIC');
                    spawnDrop(e.position.clone().add(tempVec.set(1,0,0)), 'XP', 1000); 
                } 
                else if (e.type === 1 || e.type === 5) { // Elite Death
                     if (Math.random() > 0.5) spawnDrop(e.position, 'ITEM', 0); 
                     for(let k=0; k<5; k++) {
                         const offset = tempVec.set((Math.random()-0.5)*2, 0, (Math.random()-0.5)*2);
                         spawnDrop(e.position.clone().add(offset), 'XP', 100);
                     }
                }
                else {
                    if (Math.random() > 0.90) spawnDrop(e.position, 'ITEM', 0);
                    else spawnDrop(e.position, 'XP', e.type >= 3 ? 30 : 20);
                }
                dummy.position.set(0, -100, 0);
                if (stunIconsRef.current) stunIconsRef.current.setMatrixAt(i, dummy.matrix);
            } else {
                dummy.position.copy(e.position);
                const aestheticHeight = 2.0; 
                const aestheticWidth = 0.6;

                if (e.type === 0 && e.scale < 0.9) {
                    dummy.scale.set(e.scale, e.scale * 0.5, e.scale); 
                } else {
                    dummy.scale.set(e.scale * aestheticWidth, e.scale * aestheticHeight, e.scale * aestheticWidth);
                }

                const totalHeight = 1.0 * dummy.scale.y;
                if (e.type !== 2) {
                    const bob = Math.abs(Math.sin(state.clock.elapsedTime * 5 + i)) * 0.2;
                    dummy.position.y = (totalHeight / 2) + bob;
                } else {
                    dummy.position.y = totalHeight / 2;
                }
                dummy.lookAt(playerPosition);
            }
        } else {
            dummy.position.set(0, -100, 0);
            if (stunIconsRef.current) stunIconsRef.current.setMatrixAt(i, dummy.matrix);
        }

        dummy.updateMatrix();
        meshRef.current.setMatrixAt(i, dummy.matrix);
    }

    meshRef.current.instanceMatrix.needsUpdate = true;
    if (meshRef.current.instanceColor) meshRef.current.instanceColor.needsUpdate = true;
    if (stunIconsRef.current) stunIconsRef.current.instanceMatrix.needsUpdate = true;

    minimapThrottle.current += 1;
    if (minimapThrottle.current > 10) {
        minimapThrottle.current = 0;
        const activeEnemies = enemies.current.filter(e => e.active).map(e => ({ x: e.position.x, z: e.position.z, type: e.type }));
        updateMinimapEnemies(activeEnemies);
    }
  });

  return (
    <>
        <instancedMesh ref={meshRef} args={[undefined, undefined, MAX_ENEMIES]} frustumCulled={false}>
            <boxGeometry args={[1, 1, 1]} />
            <meshStandardMaterial vertexColors roughness={0.5} metalness={0.2} />
        </instancedMesh>
        <instancedMesh ref={stunIconsRef} args={[undefined, undefined, MAX_ENEMIES]} frustumCulled={false}>
            <torusGeometry args={[0.5, 0.1, 8, 16]} />
            <meshBasicMaterial color="#facc15" />
        </instancedMesh>
    </>
  );
};

