          skillPoints: 30,
          health: startStats.maxHealth,
          mana: startStats.maxMana,
          baseStats: startStats,
          stats: calculateStats(startStats, finalEquipment, false, false),
          skillLevels: { 
              orbital: 0, thunder: 0, regen: 0, magnet: 0, dash: 0, weapon: 1, barrier: 1, storm: 0, special: 0,
              piercing: 0, burning: 0, freezing: 0, freezeSpell: 0, gravity: 0, stamp: 0, rage: 0
          },
          activeAbilityQ: null,
          playerPosition: new Vector3(0, 0, 0),
          inventory: finalInventory,
          equipment: finalEquipment,
          drops: [],
          skills: { dash: 0, q: 0, r: 0, e: 0, pet: 0 },
          // Initialize Dash
          dashCharges: 1,
          maxDashCharges: 1,
          obstacles: generateObstacles(),
          crates: generateCrates(),
          wave: 1,
          waveTimer: 0,
          accumulatedWaveGold: 0,
          isInventoryOpen: false,
          isShopOpen: false,
          isCharacterSheetOpen: false,
          isCodexOpen: false,
          potionCooldown: 0,
          barrierCooldown: 0,
          petReviveCooldown: 0,
          isInvincible: false,
          invincibilityTimer: 0,
          levelUpVisualTimer: 0,
          reviveAnimTimer: 0,
          bossData: { active: false, name: '', hp: 0, maxHp: 0 },
          notifications: [],
          rageMode: false,
          earthwall: { active: false, position: new Vector3(), timer: 0, radius: 10.0 },
          maxInventorySlots: 50,
        });
    },

    // ... (rest of simple actions: addNotification, removeNotification, performSummon, sellItem, massSell etc. unchanged, assuming they exist)

    // Updated Upgrade Skill for Dash Cap
    upgradeSkill: (skill) => set((state) => {
      const currentLevel = state.skillLevels[skill];

      // Dash Cap at Level 1
      if (skill === 'dash' && currentLevel >= 1) {
          get().addNotification("Dash is already max level!", "red", "SYSTEM");
          return {};
      }

      let cost = skill === 'special' ? 5 : (currentLevel === 0 ? 3 : currentLevel + 1);
      if (skill === 'regen') cost = currentLevel === 0 ? 6 : 5;

      if (state.skillPoints >= cost) {
          const newLevels = { ...state.skillLevels, [skill]: currentLevel + 1 };

          // Apply Dash Upgrade Effect immediately
          let newMaxDash = state.maxDashCharges;
          let newCurrentDash = state.dashCharges;
          if (skill === 'dash') {
              newMaxDash = 2; // Level 1 = 2 Charges
              newCurrentDash = 2; // Refill on upgrade
          }

          let newActiveQ = state.activeAbilityQ;
          if (skill === 'piercing') newActiveQ = 'PIERCING_SHOT';
          if (skill === 'gravity') newActiveQ = 'GRAVITY_SPELL';
          if (skill === 'rage') newActiveQ = 'RAGE';

          return {
              skillPoints: state.skillPoints - cost,
              skillLevels: newLevels,
              activeAbilityQ: newActiveQ,
              maxDashCharges: newMaxDash,
              dashCharges: newCurrentDash
          };
      }
      return {};
    }),

    triggerSkillCooldown: (skill) => set((state) => {
      const baseCD = { q: 7.0, r: 15.0, e: 20.0, dash: state.stats.dashCooldown }[skill];
      if (!baseCD) return {};
      const cooldown = baseCD * (1 - state.stats.cooldownReduction);
      return { skills: { ...state.skills, [skill]: cooldown } };
    }),

    triggerPetCooldown: () => set((state) => {
        const pet = state.equipment.pet;
        if (!pet || !pet.petCooldown) return {};
        return { skills: { ...state.skills, pet: pet.petCooldown } };
    }),

    // New Perform Dash Action
    performDash: () => {
        const state = get();
        if (state.dashCharges > 0) {
            set(s => {
                const newCharges = s.dashCharges - 1;
                // If we just used a charge and there was no cooldown running, start one to regenerate this charge
                const newDashCD = s.skills.dash <= 0 ? s.stats.dashCooldown * (1 - s.stats.cooldownReduction) : s.skills.dash;
                return { 
                    dashCharges: newCharges, 
                    skills: { ...s.skills, dash: newDashCD } 
                };
            });
            return true;
        }
        return false;
    },

    tickCooldowns: (delta) => {
      const state = get();

      // Standard Skills
      let q = Math.max(0, state.skills.q - delta);
      let r = Math.max(0, state.skills.r - delta);
      let e = Math.max(0, state.skills.e - delta);
      let pet = Math.max(0, state.skills.pet - delta);

      // Dash Charge Regeneration Logic
      let dashCD = state.skills.dash;
      let dashCharges = state.dashCharges;

      if (dashCharges < state.maxDashCharges) {
          dashCD -= delta;
          if (dashCD <= 0) {
              dashCharges += 1;
              // If still missing charges, restart timer
              if (dashCharges < state.maxDashCharges) {
                  dashCD = state.stats.dashCooldown * (1 - state.stats.cooldownReduction);
              } else {
                  dashCD = 0;
              }
          }
      } else {
          dashCD = 0; // At max charges, no timer
      }

      // ... (rest of tick logic for rage, potions, etc.)
      let rageTimer = state.rageTimer;
      let rageMode = state.rageMode;
      let sprintTimer = state.sprintTimer;
      let stats = state.stats;

      let earthwall = { ...state.earthwall };
      if (earthwall.active) {
          earthwall.timer -= delta;
          if (earthwall.timer <= 0) earthwall.active = false;
      }

      let warVitalityTimer = state.warVitalityTimer;
      if (warVitalityTimer > 0) {
          warVitalityTimer -= delta;
          if (state.health < state.stats.maxHealth) {
              get().heal(10 * delta);
          }
      }

      if (sprintTimer > 0) sprintTimer -= delta;

      let recalc = false;
      if (rageMode) {
          rageTimer -= delta;
          if (rageTimer <= 0) { rageMode = false; recalc = true; }
      }
      if (state.sprintTimer > 0 && sprintTimer <= 0) recalc = true;
      if (recalc) stats = calculateStats(state.baseStats, state.equipment, rageMode, sprintTimer > 0);

      const newBarrierCooldown = Math.max(0, state.barrierCooldown - delta);
      const newPotionCD = Math.max(0, state.potionCooldown - delta);

      set({
          skills: { q, r, e, dash: dashCD, pet },
          dashCharges,
          stats,
          rageMode, rageTimer, sprintTimer: Math.max(0, sprintTimer),
          earthwall, warVitalityTimer: Math.max(0, warVitalityTimer),
          potionCooldown: newPotionCD,
          barrierCooldown: newBarrierCooldown,
          waveTimer: state.waveTimer + delta,
          // ... other timers
      });
    },

    // ... (rest of store unchanged)
    addNotification: (message, color = 'white', type = 'ITEM', action) => set(state => ({ notifications: [...state.notifications, { id: Math.random().toString(), message, color, type, action }] })),
    removeNotification: (id) => set(state => ({ notifications: state.notifications.filter(n => n.id !== id) })),
    toggleInventory: () => set(state => ({ isInventoryOpen: !state.isInventoryOpen, isShopOpen: false, isCharacterSheetOpen: false, isCodexOpen: false, status: !state.isInventoryOpen ? GameStatus.PAUSED : GameStatus.PLAYING })),
    toggleCharacterSheet: () => set(state => ({ isCharacterSheetOpen: !state.isCharacterSheetOpen, isShopOpen: false, isInventoryOpen: false, isCodexOpen: false, status: !state.isCharacterSheetOpen ? GameStatus.PAUSED : GameStatus.PLAYING })),
    toggleCodex: () => set(state => ({ isCodexOpen: !state.isCodexOpen, isShopOpen: false, isInventoryOpen: false, isCharacterSheetOpen: false, status: !state.isCodexOpen ? GameStatus.PAUSED : GameStatus.MENU })),
    closeAllUI: () => set({ isInventoryOpen: false, isShopOpen: false, isCharacterSheetOpen: false, isCodexOpen: false, status: GameStatus.PLAYING }),
    openSpecificShop: (tab) => set({ isShopOpen: true, isInventoryOpen: false, activeShopTab: tab, status: GameStatus.PAUSED }),
    clearActionResult: () => set({ actionResult: null }),
    addScore: (amount) => set((state) => ({ score: state.score + amount })),
    addGems: (amount) => set((state) => ({ gems: state.gems + amount })),
    addExperience: (amount) => { /* ... existing logic ... */ },
    takeDamage: (amount) => { /* ... existing logic ... */ },
    heal: (amount) => set((state) => ({ health: Math.min(state.health + amount, state.stats.maxHealth) })),
    restoreMana: (amount) => set((state) => ({ mana: Math.min(state.mana + amount, state.stats.maxMana) })),
    setPlayerPosition: (pos) => set({ playerPosition: pos }),
    triggerInvincibility: (duration) => set((state) => ({ invincibilityTimer: Math.max(state.invincibilityTimer, duration), isInvincible: true })),
    // ... insert other simple setters/getters
    spawnDrop: (pos, type, value, rarity) => { /* ... existing logic */ },
    collectDrop: (id) => { /* ... existing logic */ },
    activateRage: () => set(state => ({ rageMode: true, rageTimer: 4.0, stats: calculateStats(state.baseStats, state.equipment, true, state.sprintTimer>0) })),
    activateEarthwall: (pos) => set(state => ({ earthwall: { active: true, position: pos, timer: 4.0, radius: 12.0 } })),
    activateWarVitality: () => set({ warVitalityTimer: 6.0 }),
    activateSprint: () => {
        const s = get();
        set({ sprintTimer: 4.0, stats: calculateStats(s.baseStats, s.equipment, s.rageMode, true), invincibilityTimer: Math.max(s.invincibilityTimer, 4.0), isInvincible: true });
    },
    updatePassiveCooldowns: (p) => set(s => ({ passiveSkillState: { ...s.passiveSkillState, ...p } })),
    advanceWave: () => {
        const u = generateUpgradeOptions(get().hero);
        set(s => ({ wave: s.wave + 1, waveTimer: 0, accumulatedWaveGold: s.accumulatedWaveGold + 100, status: GameStatus.LEVEL_UP, upgradeOptions: u }));
    },
    setBossData: (d) => set(s => ({ bossData: { ...s.bossData, ...d } })),
    updateMinimapEnemies: (e) => set({ minimapEnemies: e }),
    breakCrate: (id) => { /* ... existing */ },
    damageCrate: (id, amt) => { /* ... existing */ },
    setSellConfirmationItem: (i) => set({ sellConfirmationItem: i }),
    clearGachaResults: () => set({ status: GameStatus.PLAYING, gachaResults: [] }),
    resetGame: () => set({ status: GameStatus.MENU }),
    handleInventoryFull: () => { /* ... existing */ },
    equipItem: (item) => { /* ... existing */ },
    unequipItem: (slot) => { /* ... existing */ },
    autoEquip: () => { /* ... existing */ },
    buyItem: (item, q) => { /* ... existing */ },
    sellItem: (item) => { /* ... existing */ },
    massSell: (r) => { /* ... existing */ },
    recycleItem: (i) => { /* ... existing */ },
    massRecycle: (r) => { /* ... existing */ },
    combineMaterials: (r) => { /* ... existing */ },
    craftItem: (r) => { /* ... existing */ },
    buyInventorySlots: () => { /* ... existing */ },
    performSummon: (a) => { /* ... existing */ },
    upgradeItem: (i) => { /* ... existing */ },
    applyUpgrade: (u) => { /* ... existing */ },
    selectUpgrade: (u) => { /* ... existing */ },
}));

// ... existing imports
import React, { useRef, useState } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import { Html } from '@react-three/drei';
import { Vector3, InstancedMesh, Mesh, Raycaster, Plane } from 'three';
import { useGameStore } from '../store';
import { COLORS, PLAYER_RADIUS, ARENA_SIZE } from '../constants';
import { BulletManager } from './BulletManager';
import { GameStatus, BulletData, EnemyData } from '../types';
import { SpatialHashGrid } from '../utils/SpatialHashGrid';

interface PlayerProps {
  bulletsDataRef: React.MutableRefObject<BulletData[]>;
  enemyBulletsDataRef: React.MutableRefObject<BulletData[]>;
  targetPosRef: React.MutableRefObject<Vector3>;
  // New props
  enemiesDataRef: React.MutableRefObject<EnemyData[]>;
  spatialGrid?: React.MutableRefObject<SpatialHashGrid>;
}

export const Player: React.FC<PlayerProps> = ({ bulletsDataRef, enemyBulletsDataRef, targetPosRef, enemiesDataRef, spatialGrid }) => {
  const meshRef = useRef<any>(null);
  const axeSpinRef = useRef<any>(null);

  const { stats, status, setPlayerPosition, skills, triggerSkillCooldown, tickCooldowns, takeDamage, equipment, useMana, triggerInvincibility, obstacles, crates, isInvincible, toggleInventory, breakCrate, hero, levelUpVisualTimer, health, mana, level, activeAbilityQ, activateRage, rageMode, skillLevels, activateEarthwall, activateWarVitality, activateSprint, reviveAnimTimer, performDash } = useGameStore();
  const { camera, scene, raycaster, pointer } = useThree();

  const [pos] = useState(new Vector3(0, 0, 0));
  const [velocity] = useState(new Vector3(0, 0, 0));
  const [keys, setKeys] = useState<{ [key: string]: boolean }>({});

  const groundPlane = new Plane(new Vector3(0, 1, 0), 0);

  const dashVelocity = useRef(new Vector3());
  const dashTime = useRef(0);
  const axeSpinTime = useRef(0);
  const axeDamageTimer = useRef(0);
  const arrowRainState = useRef({ active: false, wavesLeft: 0, timer: 0 });

  React.useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        if (e.code === 'Space') e.preventDefault(); 
        setKeys((k) => ({ ...k, [e.code]: true }));
        if (e.code === 'KeyI') toggleInventory();
    };
    const handleKeyUp = (e: KeyboardEvent) => setKeys((k) => ({ ...k, [e.code]: false }));
    const handleMouseDown = (e: MouseEvent) => {
        if (e.button === 2) setKeys((k) => ({ ...k, 'RightClick': true })); 
    };
    const handleMouseUp = (e: MouseEvent) => {
        if (e.button === 2) setKeys((k) => ({ ...k, 'RightClick': false }));
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    window.addEventListener('mousedown', handleMouseDown);
    window.addEventListener('mouseup', handleMouseUp);
    window.addEventListener('contextmenu', (e) => e.preventDefault());

    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
      window.removeEventListener('mousedown', handleMouseDown);
      window.removeEventListener('mouseup', handleMouseUp);
      window.removeEventListener('contextmenu', (e) => e.preventDefault());
    };
  }, [toggleInventory]);

  // ... (spawnBullet and handleAbility helpers remain same)
  const spawnBullet = (type: any, speed: number, damageMult: number, overrides: Partial<BulletData> = {}) => {
      const bullet = bulletsDataRef.current.find(b => !b.active);
      if (bullet) {
          bullet.active = true;
          bullet.lifetime = overrides.lifetime || 3.0;
          let aimDir = new Vector3().subVectors(targetPosRef.current, pos).normalize();

          if (type === 'BLACKHOLE') {
              bullet.position.copy(pos).add(aimDir.clone().multiplyScalar(15.0)).add(new Vector3(0, 1.5, 0));
              bullet.velocity.set(0, 0, 0); 
          } else {
              bullet.position.copy(pos).add(new Vector3(0, 1.5, 0));
              bullet.velocity.copy(aimDir).multiplyScalar(speed);
          }

          bullet.type = type;
          bullet.pierce = overrides.pierce || 1;
          bullet.damageMultiplier = damageMult * stats.skillDamage * 2.0; 
          bullet.hitIds = [];
          if (overrides.knockback) bullet.knockback = overrides.knockback;
          if (overrides.effect) bullet.effect = overrides.effect;
          if (overrides.trailTimer !== undefined) bullet.trailTimer = overrides.trailTimer;
          if (overrides.maxPullCount) bullet.maxPullCount = overrides.maxPullCount;

          return bullet;
      }
      return null;
  };

  const handleAbility = (ability: string, isQ: boolean) => {
      if (useMana(30)) {
          triggerSkillCooldown(isQ ? 'q' : 'r');

          if (ability === 'RAGE') {
              activateRage();
          } else if (ability === 'PIERCING_SHOT') {
              spawnBullet('PIERCING_ARROW', 50, 1.75, { pierce: 99, knockback: 4.0, lifetime: 3.0 });
          } else if (ability === 'GRAVITY_SPELL') {
              const limit = 8 + (skillLevels.gravity * 1);
              spawnBullet('BLACKHOLE', 0, 5.0, { pierce: 99, lifetime: 2.6, trailTimer: 0.1, maxPullCount: limit }); 
          } else if (ability === 'ARROW_RAIN') {
              arrowRainState.current.active = true;
              arrowRainState.current.wavesLeft = 3;
              arrowRainState.current.timer = 0; 
          } else if (ability === 'FIREBALL') {
              spawnBullet('FIREBALL', 5, 2.0 * 0.63, { 
                  pierce: 100, 
                  lifetime: 5.0, 
                  effect: { type: 'BURN', duration: 5, value: stats.damage * 0.3 } 
              });
          } else if (ability === 'AXE_SPIN') {
              axeSpinTime.current = 3.0;
              axeDamageTimer.current = 0.2; 
          }
      }
  };

  const handleSkillE = () => {
      if (skillLevels.special <= 0) return;
      if (skills.e > 0) return;

      const manaCost = 20; 
      if (useMana(manaCost)) {
          triggerSkillCooldown('e');
          if (hero === 'BARBARIAN') {
              activateWarVitality();
          } else if (hero === 'WIZARD') {
              activateEarthwall(pos.clone());
          } else if (hero === 'ARCHER') {
              activateSprint();
          }
      }
  };

  useFrame((state, delta) => {
    if (status !== GameStatus.PLAYING) return;
    if (!meshRef.current) return;

    tickCooldowns(delta);

    raycaster.setFromCamera(pointer, camera);
    const target = new Vector3();
    raycaster.ray.intersectPlane(groundPlane, target);
    targetPosRef.current.copy(target); 

    const moveDir = new Vector3(0, 0, 0);
    if (keys['KeyW'] || keys['ArrowUp']) moveDir.z -= 1;
    if (keys['KeyS'] || keys['ArrowDown']) moveDir.z += 1;
    if (keys['KeyA'] || keys['ArrowLeft']) moveDir.x -= 1;
    if (keys['KeyD'] || keys['ArrowRight']) moveDir.x += 1;
    moveDir.normalize();

    if (keys['KeyQ'] && skills.q <= 0 && activeAbilityQ) {
        handleAbility(activeAbilityQ, true);
    }

    if ((keys['KeyR'] || keys['RightClick']) && skills.r <= 0) {
        const ability = equipment.weapon?.ability;
        if (ability) {
            handleAbility(ability, false);
        }
    }

    if (keys['KeyE']) {
        handleSkillE();
    }

    // ... (Arrow Rain and Axe Spin logic preserved)
    if (arrowRainState.current.active) {
        arrowRainState.current.timer -= delta;
        if (arrowRainState.current.timer <= 0) {
            const count = 12; 
            const angleOffset = (3 - arrowRainState.current.wavesLeft) * (Math.PI / 8); 

            for (let i = 0; i < count; i++) {
                const bullet = bulletsDataRef.current.find(b => !b.active);
                if (bullet) {
                    bullet.active = true;
                    bullet.lifetime = 1.0;
                    bullet.position.copy(pos).add(new Vector3(0, 1, 0));
                    const angle = (Math.PI * 2 * i) / count + angleOffset;
                    bullet.velocity.set(Math.cos(angle), 0, Math.sin(angle)).multiplyScalar(25);
                    bullet.type = 'ARROW';
                    bullet.pierce = 3; 
                    bullet.damageMultiplier = 1.5 * 0.63 * stats.skillDamage * 2.0; 
                    bullet.knockback = 3.0; 
                }
            }
            arrowRainState.current.wavesLeft--;
            arrowRainState.current.timer = 0.2; 
            if (arrowRainState.current.wavesLeft <= 0) arrowRainState.current.active = false;
        }
    }

    if (axeSpinTime.current > 0) {
        axeSpinTime.current -= delta;
        axeDamageTimer.current += delta;
        if (axeSpinRef.current) {
            axeSpinRef.current.visible = true;
            axeSpinRef.current.rotation.y += delta * 20; 
            const barrierRadius = 7.0; 
            const damageRange = 8.0;

            const tickRate = 0.2; 
            if (axeDamageTimer.current >= tickRate) {
                 const tickDamage = stats.damage * tickRate * 5 * stats.skillDamage * 2.0 * 0.63; 
                 axeDamageTimer.current = 0;
                 // Optimized: Use enemiesDataRef
                 const enemies = enemiesDataRef.current;
                 for (let i = 0; i < enemies.length; i++) {
                    const enemy = enemies[i];
                    if (!enemy.active) continue;
                    const dist = enemy.position.distanceTo(pos);
                    if (dist < damageRange) {
                        enemy.health -= tickDamage;
                        window.dispatchEvent(new CustomEvent('damage', { 
                            detail: { position: enemy.position, damage: tickDamage, isCrit: false, isPlayer: false } 
                        }));
                    }
                 }
            }
            // Push enemies away
            const enemies = enemiesDataRef.current;
            for (let i = 0; i < enemies.length; i++) {
                const enemy = enemies[i];
                if (!enemy.active) continue;
                const dist = enemy.position.distanceTo(pos);
                if (dist < barrierRadius) {
                        const pushDir = new Vector3().subVectors(enemy.position, pos).normalize();
                        enemy.position.copy(pos).add(pushDir.multiplyScalar(barrierRadius));
                }
            }
        }
    } else if (axeSpinRef.current) {
        axeSpinRef.current.visible = false;
    }

    // UPDATED DASH LOGIC: Use Charge System
    // Check if dash time is running so we don't dash while dashing
    if (keys['Space'] && dashTime.current <= 0) {
        if (performDash()) {
            if (useMana(5)) {
                dashTime.current = 0.2; 
                dashVelocity.current.copy(moveDir.length() > 0 ? moveDir.normalize() : new Vector3(0, 0, -1).applyQuaternion(meshRef.current.quaternion));
                dashVelocity.current.multiplyScalar(40); 
                triggerInvincibility(0.2);
            }
        }
    }

    if (dashTime.current > 0) {
        dashTime.current -= delta;
        velocity.copy(dashVelocity.current);
    } else {
        velocity.lerp(moveDir.multiplyScalar(stats.moveSpeed), delta * 8);
    }

    // ... (rest of movement and collision preserved)
    const proposedPos = pos.clone().add(velocity.clone().multiplyScalar(delta));
    proposedPos.y = 0;

    for (const obs of obstacles) {
        const dist = proposedPos.distanceTo(obs.position);
        const minDistance = obs.radius + 0.4; 
        if (dist < minDistance) {
            const dir = new Vector3().subVectors(proposedPos, obs.position).normalize();
            proposedPos.copy(obs.position).add(dir.multiplyScalar(minDistance));
        }
    }

    for (const crate of crates) {
        if (crate.active) {
            const dist = proposedPos.distanceTo(crate.position);
            const minDistance = 0.7 + 0.4;
            if (dist < minDistance) {
                breakCrate(crate.id);
            }
        }
    }

    const limit = (ARENA_SIZE / 2) - 2;
    if (proposedPos.length() > limit) {
        proposedPos.normalize().multiplyScalar(limit);
    }
    proposedPos.y = 0;

    pos.copy(proposedPos);
    meshRef.current.position.copy(pos);
    setPlayerPosition(pos.clone());

    meshRef.current.lookAt(targetPosRef.current);

    const enemyBullets = enemyBulletsDataRef.current;
    if (dashTime.current <= 0) { 
        for(let i = 0; i < enemyBullets.length; i++) {
            const b = enemyBullets[i];
            if (b.active && b.position.distanceTo(pos) < PLAYER_RADIUS + 0.5) { 
                const dmg = b.damage || 10;
                takeDamage(dmg);
                b.active = false;
                window.dispatchEvent(new CustomEvent('damage', { 
                    detail: { position: pos, damage: dmg, isCrit: false, isPlayer: true } 
                }));
            }
        }
    }

    const targetCamPos = new Vector3(pos.x, 35, pos.z + 28);
    camera.position.lerp(targetCamPos, delta * 4);
    camera.lookAt(pos.x, 0, pos.z);
  });

  const hpPercent = Math.max(0, health / stats.maxHealth) * 100;
  const mpPercent = Math.max(0, mana / stats.maxMana) * 100;

  return (
    <>
      <BulletManager 
          playerPos={pos} 
          targetPosRef={targetPosRef} 
          bulletsDataRef={bulletsDataRef}
          projectileType={equipment.weapon?.projectileType}
          enemiesDataRef={enemiesDataRef}
          spatialGrid={spatialGrid}
      />

      <group ref={meshRef} position={[0, 1, 0]}>

        <Html position={[0, -1.2, 0]} center style={{ pointerEvents: 'none' }} zIndexRange={[0, 0]}>
            <div className="flex items-center gap-2" style={{ opacity: 0.8 }}>
                <div className="w-8 h-8 rounded-full bg-slate-900 border-2 border-slate-500 flex items-center justify-center shadow-lg">
                    <span className="text-white font-bold text-sm">{level}</span>
                </div>
                <div className="flex flex-col gap-1 w-16">
                    <div className="h-1.5 w-full bg-slate-800 rounded-full overflow-hidden border border-slate-600">
                        <div className="h-full bg-red-500 transition-all duration-100" style={{ width: `${hpPercent}%` }} />
                    </div>
                    <div className="h-1.5 w-full bg-slate-800 rounded-full overflow-hidden border border-slate-600">
                        <div className="h-full bg-blue-500 transition-all duration-100" style={{ width: `${mpPercent}%` }} />
                    </div>
                </div>
            </div>
        </Html>

        {levelUpVisualTimer > 0 && (
            <>
                <Html position={[0, 2.5, 0]} center zIndexRange={[100, 0]}>
                    <div className="text-yellow-400 font-black text-2xl drop-shadow-[0_2px_2px_rgba(0,0,0,0.8)] animate-bounce whitespace-nowrap">
                        LEVEL UP!
                    </div>
                </Html>
                <mesh position={[0, 0.5, 0]} scale={[2, 4, 2]}>
                    <cylinderGeometry args={[0.5, 0.5, 1, 16]} />
                    <meshBasicMaterial color="#facc15" transparent opacity={levelUpVisualTimer * 0.5} depthWrite={false} side={2} />
                </mesh>
            </>
        )}

        {reviveAnimTimer > 0 && (
            <mesh position={[0, 0, 0]}>
                <cylinderGeometry args={[2, 2, 20, 16, 1, true]} />
                <meshBasicMaterial 
                    color="#fef3c7" 
                    transparent 
                    opacity={Math.min(1, reviveAnimTimer) * 0.6} 
                    depthWrite={false} 
                    side={2} 
                    blending={2} 
                />
            </mesh>
        )}

        {rageMode && (
            <mesh position={[0, 0.5, 0]}>
                <sphereGeometry args={[1.0, 16, 16]} />
                <meshBasicMaterial color="red" wireframe transparent opacity={0.3} />
            </mesh>
        )}

        <mesh visible={isInvincible}>
            <sphereGeometry args={[1.2, 16, 16]} />
            <meshStandardMaterial color="orange" transparent opacity={0.4} emissive="orange" emissiveIntensity={0.5} />
        </mesh>

        <group position={[0, 0, 0]}>
            <mesh castShadow receiveShadow position={[0, 0.5, 0]}>
                <capsuleGeometry args={[0.4, 1, 4, 8]} />
                <meshStandardMaterial 
                    color={rageMode ? 'red' : (levelUpVisualTimer > 0 ? '#facc15' : COLORS.player)} 
                    emissive={rageMode ? '#991b1b' : (levelUpVisualTimer > 0 ? '#facc15' : 'black')}
                    emissiveIntensity={rageMode ? 1 : levelUpVisualTimer}
                    roughness={0.4} metalness={0.6} 
                />
            </mesh>
            <mesh castShadow position={[0, 1.4, 0]}>
                <boxGeometry args={[0.5, 0.5, 0.5]} />
                <meshStandardMaterial color="#cbd5e1" metalness={0.8} roughness={0.2} />
            </mesh>
            <mesh position={[0.6, 0.5, 0.4]}>
                <boxGeometry args={[0.2, 0.2, 0.8]} />
                <meshStandardMaterial color="#94a3b8" />
