                         <Zap size={28} className={skills.r > 0 ? 'text-slate-500' : 'text-purple-400'} />}
                    level={skillLevels.weapon} 
                    cooldown={skills.r}
                    label="R / Click"
                    desc={weaponAbilityDesc}
                    active={true}
                    borderColor={skills.r > 0 ? 'border-slate-600' : 'border-purple-400 shadow-[0_0_15px_rgba(168,85,247,0.5)]'}
