                />

                <ActiveSkillSlot 
                    icon={activeAbilityQ ? <Star size={28} className={skills.q > 0 ? 'text-slate-500' : 'text-yellow-400'} /> : <div className="text-slate-700 text-xs">Locked</div>}
                    level={1} 
                    cooldown={skills.q}
