                    <SkillIcon icon={<Activity size={24} className="text-blue-400"/>} level={skillLevels.orbital} cd={passiveSkillState.orbitalCooldown} maxCd={passiveSkillState.orbitalMaxCooldown} desc={`Orbital Blades: ${2+skillLevels.orbital} blades.`} />
                    <SkillIcon icon={<Tornado size={24} className="text-indigo-400"/>} level={skillLevels.storm} cd={passiveSkillState.stormCooldown} maxCd={passiveSkillState.stormMaxCooldown} desc="Storm: Bouncing typhoon." />
                    <SkillIcon icon={<Flame size={24} className="text-red-500"/>} level={skillLevels.burning} cd={passiveSkillState.burningCooldown} maxCd={passiveSkillState.burningMaxCooldown} desc="Burning Arrow: Explosive fire." />
                    <SkillIcon icon={<Gem size={24} className="text-cyan-300"/>} level={skillLevels.freezing} cd={passiveSkillState.freezingCooldown} maxCd={passiveSkillState.freezingMaxCooldown} desc="Freezing Arrow: Explosive ice." />
                    <SkillIcon icon={<Zap size={24} className="text-blue-400"/>} level={skillLevels.freezeSpell} cd={passiveSkillState.blizzardCooldown} maxCd={passiveSkillState.blizzardMaxCooldown} desc="Blizzard: AOE Freeze." />
                    <SkillIcon icon={<Hammer size={24} className="text-orange-500"/>} level={skillLevels.stamp} cd={passiveSkillState.stampCooldown} maxCd={passiveSkillState.stampMaxCooldown} desc="Mega Stamp: Stun & Knockback." />

                    {/* Energy Shield with Cooldown */}
                    <SkillIcon icon={<ShieldCheck size={24} className="text-orange-400"/>} level={skillLevels.barrier} cd={barrierCooldown} maxCd={Math.max(5, 12-skillLevels.barrier)} desc="Energy Shield" />

                    <SkillIcon icon={<Heart size={24} className="text-green-400"/>} level={skillLevels.regen} desc="Regeneration" />
                    <SkillIcon icon={<Magnet size={24} className="text-purple-400"/>} level={skillLevels.magnet} desc="Magnet" />
