export const Environment: React.FC = React.memo(() => {
  const { mapRadius, status } = useGameStore(state => ({ mapRadius: state.mapRadius, status: state.status }));

  // Memoize boundary trees to create a dense forest wall outside the walkable area
  const boundaryTrees = useMemo(() => {
      const arr = [];
      const count = 400; // Dense wall

      for(let i=0; i<count; i++) {
          const angle = (i / count) * Math.PI * 2;
          // Place trees in a band outside the map radius
          const r = mapRadius + 2 + Math.random() * 15; 

          arr.push({
              position: [Math.cos(angle) * r, 0, Math.sin(angle) * r] as [number, number, number],
              scale: 1.5 + Math.random()
          });
      }
      return arr;
  }, [mapRadius]); // Re-generate when map radius changes (Lobby vs Playing)

  // Ground patches logic (simplified for cleaner look)
  const groundPatches = useMemo(() => {
      return [...Array(15)].map((_, i) => ({
          key: `patch-${i}`,
          size: 5 + Math.random() * 10,
          position: [(Math.random()-0.5)*mapRadius*1.5, -0.05, (Math.random()-0.5)*mapRadius*1.5] as [number, number, number]
      }));
  }, [mapRadius]);

  return (
    <group>
      {/* Playable Ground */}
      <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, -0.1, 0]} receiveShadow>
        <circleGeometry args={[mapRadius + 1, 64]} />
        <meshStandardMaterial color={COLORS.ground} roughness={1} metalness={0} />
      </mesh>

      {/* Dark Void Floor (Unwalkable Zone) */}
      <mesh rotation={[-Math.PI/2, 0, 0]} position={[0, -0.11, 0]}>
          <ringGeometry args={[mapRadius, mapRadius + 50, 64]} />
          <meshBasicMaterial color={COLORS.void} />
      </mesh>

      {/* Ground Decals */}
      {groundPatches.map((patch) => (
        <mesh key={patch.key} rotation={[-Math.PI/2, 0, 0]} position={patch.position}>
            <circleGeometry args={[patch.size, 16]} />
            <meshStandardMaterial color={COLORS.groundDark} opacity={0.5} transparent depthWrite={false} />
        </mesh>
      ))}

      {/* Boundary Trees Wall */}
      <Instances range={boundaryTrees.length}>
        <cylinderGeometry args={[0.3, 0.6, 6, 8]} />
        <meshStandardMaterial color="#3f2e18" />
        {boundaryTrees.map((t, i) => (
            <group key={`bound-${i}`} position={t.position} scale={[t.scale, t.scale, t.scale]}>
                <Instance />
                <mesh position={[0, 3, 0]}>
                    <coneGeometry args={[2, 5, 8]} />
                    <meshStandardMaterial color="#0f3d0f" />
                </mesh>
            </group>
        ))}
      </Instances>
    </group>
  );
});

import React, { useRef } from 'react';
import { useFrame } from '@react-three/fiber';
import { Text } from '@react-three/drei';
import { Vector3, Group } from 'three';
import { useGameStore } from '../store';
import { GameStatus, HeroClass } from '../types';
import { COLORS } from '../constants';

const HeroDummy: React.FC<{ 
    position: [number, number, number], 
    hero: HeroClass, 
    label: string, 
    color: string, 
    isSelected: boolean,
    onSelect: () => void 
}> = ({ position, hero, label, color, isSelected, onSelect }) => {
    const groupRef = useRef<Group>(null);

    useFrame((state) => {
        if (!groupRef.current) return;
        if (isSelected) {
            groupRef.current.rotation.y = state.clock.elapsedTime * 2;
            groupRef.current.position.y = 0.5 + Math.sin(state.clock.elapsedTime * 4) * 0.1;
        } else {
            groupRef.current.rotation.y = 0;
            groupRef.current.position.y = 0;
        }
    });

    return (
        <group position={position} onClick={(e) => { e.stopPropagation(); onSelect(); }}>
            <group ref={groupRef}>
                {/* Simplified Body Representation */}
                <mesh position={[0, 1, 0]}>
                    <capsuleGeometry args={[0.4, 1, 4, 8]} />
                    <meshStandardMaterial color={color} emissive={isSelected ? color : 'black'} emissiveIntensity={isSelected ? 0.5 : 0} />
                </mesh>
                {/* Head */}
                <mesh position={[0, 1.8, 0]}>
                    <boxGeometry args={[0.4, 0.4, 0.4]} />
                    <meshStandardMaterial color="#fbbf24" />
                </mesh>
                {/* Weapon Hint */}
                {hero === 'ARCHER' && <mesh position={[0.5, 1, 0]} rotation={[0,0,-0.5]}><cylinderGeometry args={[0.05,0.05,1.5]} /><meshStandardMaterial color="brown"/></mesh>}
                {hero === 'WIZARD' && <mesh position={[0.5, 1, 0]}><cylinderGeometry args={[0.05,0.05,1.5]} /><meshStandardMaterial color="blue"/></mesh>}
                {hero === 'BARBARIAN' && <mesh position={[0.5, 1, 0]}><boxGeometry args={[0.2,1,0.2]} /><meshStandardMaterial color="red"/></mesh>}
            </group>

            {/* Platform */}
            <mesh position={[0, 0.1, 0]} receiveShadow>
                <cylinderGeometry args={[1, 1.2, 0.2, 32]} />
                <meshStandardMaterial color="#334155" />
            </mesh>

            {/* Selection Ring */}
            {isSelected && (
                <mesh rotation={[-Math.PI/2, 0, 0]} position={[0, 0.25, 0]}>
                    <ringGeometry args={[1.1, 1.3, 32]} />
                    <meshBasicMaterial color="#fbbf24" />
                </mesh>
            )}

            <Text position={[0, 2.5, 0]} fontSize={0.4} color="white" outlineWidth={0.02} outlineColor="black" anchorX="center" anchorY="bottom" billboard>
                {label}
            </Text>
        </group>
    );
};

const Portal: React.FC<{ position: [number, number, number], onClick: () => void }> = ({ position, onClick }) => {
    const meshRef = useRef<any>(null);
    useFrame((state) => {
        if(meshRef.current) {
            meshRef.current.rotation.z = state.clock.elapsedTime * 2;
            meshRef.current.scale.setScalar(1 + Math.sin(state.clock.elapsedTime * 5) * 0.1);
        }
    });

    return (
        <group position={position} onClick={(e) => { e.stopPropagation(); onClick(); }}>
            <mesh ref={meshRef} position={[0, 2, 0]}>
                <torusGeometry args={[1.5, 0.2, 16, 32]} />
                <meshStandardMaterial color="#a855f7" emissive="#a855f7" emissiveIntensity={2} />
            </mesh>
            <mesh position={[0, 2, 0]}>
                <circleGeometry args={[1.3, 32]} />
                <meshBasicMaterial color="black" opacity={0.8} transparent />
            </mesh>

            {/* Base */}
            <mesh position={[0, 0.1, 0]} rotation={[-Math.PI/2, 0, 0]}>
                <circleGeometry args={[2, 32]} />
                <meshStandardMaterial color="#581c87" />
            </mesh>

            <Text position={[0, 4, 0]} fontSize={0.6} color="#e879f9" outlineWidth={0.05} outlineColor="black" anchorX="center" anchorY="bottom" billboard>
                ENTER PORTAL
            </Text>
        </group>
    );
}

