const ItemIcon: React.FC<{ item: Item; size?: number }> = ({ item, size = 24 }) => {
  if (item.type === 'POTION') return <FlaskConical size={size} className="text-red-400" />;
  if (item.type === 'CORE') return <Hexagon size={size} className="text-blue-400" />;
  if (item.type === 'REVIVE') {
      if (item.id.includes('gem')) return <Gem size={size} className="text-green-400" />;
      return <Heart size={size} className="text-yellow-500" fill="rgba(234, 179, 8, 0.5)" />;
  }
  if (item.type === 'WEAPON') {
      if (item.projectileType === 'MAGIC') return <Wand2 size={size} className="text-purple-400" />;
      if (item.projectileType === 'ARROW') return <Crosshair size={size} className="text-green-400" />;
      if (item.projectileType === 'AXE') return <Axe size={size} className="text-red-400" />;
      return <Sword size={size} className="text-slate-300" />;
  }
  if (item.type === 'ARMOR') return <Shield size={size} className="text-blue-300" />;
  if (item.type === 'ACCESSORY') return <Gem size={size} className="text-yellow-400" />;
  if (item.type === 'PET') return <Ghost size={size} className="text-pink-400" />;
  return <Package size={size} />;
};

