// Helper Definitions
const getRarityTextColor = (rarity?: Rarity) => {
    switch(rarity) {
        case 'MYTHIC': return 'text-red-500 drop-shadow-[0_0_2px_rgba(239,68,68,0.8)]';
        case 'LEGENDARY': return 'text-yellow-400 drop-shadow-[0_0_2px_rgba(250,204,21,0.8)]';
        case 'EPIC': return 'text-purple-400';
        case 'RARE': return 'text-blue-400';
        default: return 'text-slate-200';
    }
};

const RARITY_LEVEL_REQ: Record<string, number> = {
    'COMMON': 0,
    'RARE': 5,
    'EPIC': 15,
    'LEGENDARY': 30,
    'MYTHIC': 50
};

// ... (ItemIcon, NotificationItem helpers)
const ItemIcon: React.FC<{ item: Item; size?: number }> = ({ item, size = 24 }) => {
  if (item.type === 'POTION') return <FlaskConical size={size} className="text-red-400" />;
  if (item.type === 'CORE') return <Hexagon size={size} className="text-blue-400" />;
  if (item.type === 'REVIVE') {
      if (item.id.includes('gem')) return <Gem size={size} className="text-green-400" />;
      return <Heart size={size} className="text-yellow-500" fill="rgba(234, 179, 8, 0.5)" />;
  }
  if (item.type === 'WEAPON') {
      if (item.projectileType === 'MAGIC') return <Wand2 size={size} className="text-purple-400" />;
      if (item.projectileType === 'ARROW') return <Crosshair size={size} className="text-green-400" />;
      if (item.projectileType === 'AXE') return <Axe size={size} className="text-red-400" />;
      return <Sword size={size} className="text-slate-300" />;
  }
  if (item.type === 'ARMOR') return <Shield size={size} className="text-blue-300" />;
  if (item.type === 'ACCESSORY') return <Gem size={size} className="text-yellow-400" />;
  if (item.type === 'PET') return <Ghost size={size} className="text-pink-400" />;
  return <Package size={size} />;
};

const NotificationItem: React.FC<{ note: GameNotification; onRemove: (id: string) => void }> = React.memo(({ note, onRemove }) => {
    useEffect(() => {
        const timer = setTimeout(() => onRemove(note.id), 4000);
        return () => clearTimeout(timer);
    }, []);

    return (
        <motion.div
            initial={{ x: -50, opacity: 0 }}
            animate={{ x: 0, opacity: 1 }}
            exit={{ x: -50, opacity: 0 }}
            layout 
            className={`p-3 rounded-r-lg border-l-4 shadow-lg backdrop-blur-md bg-slate-900/80 text-sm font-bold flex flex-col gap-1 pointer-events-auto w-full`}
            style={{ borderColor: note.color }}
        >
            <div style={{ color: note.color }}>{note.message}</div>
            {note.action && (
                <button
                    onClick={() => { note.action!.onClick(); onRemove(note.id); }}
                    className="self-start text-[10px] bg-slate-700 hover:bg-slate-600 px-2 py-1 rounded text-white mt-1 border border-slate-500"
                >
                    {note.action.label}
                </button>
            )}
        </motion.div>
    );
});

