const INITIAL_STATS: PlayerStats = {
    maxHealth: 100, maxMana: 100, regen: 1, manaRegen: 1, moveSpeed: 10,
    damage: 10, fireRate: 1.0, projectileSpeed: 20, multishot: 1, spread: 0.2,
    dashCooldown: 3, cooldownReduction: 0, magnetRadius: 5, critRate: 0.05,
    critDamage: 1.5, defense: 0, skillDamage: 1, knockback: 0.5, dodge: 0
};

export const calculateItemCP = (item: Item): number => {
    if (item.type === 'POTION' || item.type === 'CORE' || item.type === 'REVIVE') return 0;
    if (!item.stats) return 0;
    let cp = 0;
    const s = item.stats;
    if (s.damage) cp += s.damage * 10;
    if (s.maxHealth) cp += s.maxHealth * 1;
    if (s.defense) cp += s.defense * 8;
    return Math.floor(cp);
};

export const calculateTotalCP = (stats: PlayerStats): number => {
    let cp = 0;
    if (stats.maxHealth) cp += stats.maxHealth * 0.5;
    if (stats.damage) cp += stats.damage * 10;
    if (stats.defense) cp += stats.defense * 5;
    if (stats.critRate) cp += stats.critRate * 500;
    if (stats.critDamage) cp += (stats.critDamage - 1) * 100;
    if (stats.skillDamage) cp += (stats.skillDamage - 1) * 100;
    if (stats.moveSpeed) cp += stats.moveSpeed * 2;
    if (stats.regen) cp += stats.regen * 10;
    if (stats.manaRegen) cp += stats.manaRegen * 10;
    return Math.floor(cp);
};

const calculateStats = (base: PlayerStats, equipment: any, rageMode: boolean, sprintActive: boolean) => {
    const final = { ...base };
    Object.values(equipment).forEach((item: any) => {
        if (item && item.stats) {
            Object.entries(item.stats).forEach(([key, val]) => {
                // @ts-ignore
                final[key] = (final[key] || 0) + (val as number);
            });
        }
    });
    if (rageMode) final.fireRate *= 2;
    if (sprintActive) final.moveSpeed *= 2;
    return final;
};

const generateUpgradeOptions = (heroClass: HeroClass): Upgrade[] => {
    const options: Upgrade[] = [];
    const pool = UPGRADES_POOL.filter(u => u.classType === undefined || u.classType === heroClass);
    for (let i = 0; i < 3; i++) {
        if (pool.length === 0) break;
        const index = Math.floor(Math.random() * pool.length);
        options.push({ ...pool[index], id: Math.random().toString() });
    }
    return options;
};

