// Helper Definitions
const getRarityTextColor = (rarity?: Rarity) => {
    switch(rarity) {
        case 'MYTHIC': return 'text-red-500 drop-shadow-[0_0_2px_rgba(239,68,68,0.8)]';
        case 'LEGENDARY': return 'text-yellow-400 drop-shadow-[0_0_2px_rgba(250,204,21,0.8)]';
        case 'EPIC': return 'text-purple-400';
        case 'RARE': return 'text-blue-400';
        default: return 'text-slate-200';
    }
};

const getRarityColor = (rarity?: Rarity) => {
    switch(rarity) {
        case 'MYTHIC': return 'border-red-500 shadow-[0_0_20px_rgba(239,68,68,0.4)]';
        case 'LEGENDARY': return 'border-yellow-400 shadow-[0_0_15px_rgba(250,204,21,0.4)]';
        case 'EPIC': return 'border-purple-500 shadow-[0_0_15px_rgba(168,85,247,0.4)]';
        case 'RARE': return 'border-blue-400 shadow-[0_0_10px_rgba(59,130,246,0.4)]';
        default: return 'border-slate-600';
    }
};

