const ItemIcon: React.FC<{ item: Item; size?: number }> = ({ item, size = 24 }) => {
  if (item.type === 'POTION') return <FlaskConical size={size} className="text-red-400" />;
  if (item.type === 'CORE') return <Hexagon size={size} className="text-blue-400" />;
  if (item.type === 'REVIVE') {
      if (item.id.includes('gem')) return <Gem size={size} className="text-green-400" />;
      return <Heart size={size} className="text-yellow-500" fill="rgba(234, 179, 8, 0.5)" />;
  }
  if (item.type === 'WEAPON') {
      if (item.projectileType === 'MAGIC') return <Wand2 size={size} className="text-purple-400" />;
      if (item.projectileType === 'ARROW') return <Crosshair size={size} className="text-green-400" />;
      if (item.projectileType === 'AXE') return <Axe size={size} className="text-red-400" />;
      return <Sword size={size} className="text-slate-300" />;
  }
  if (item.type === 'ARMOR') return <Shield size={size} className="text-blue-300" />;
  if (item.type === 'ACCESSORY') return <Gem size={size} className="text-yellow-400" />;
  if (item.type === 'PET') return <Ghost size={size} className="text-pink-400" />;
  return <Package size={size} />;
};

const NotificationItem: React.FC<{ note: GameNotification; onRemove: (id: string) => void }> = React.memo(({ note, onRemove }) => {
    useEffect(() => {
        const timer = setTimeout(() => onRemove(note.id), 4000);
        return () => clearTimeout(timer);
    }, []);

    return (
        <motion.div
            initial={{ x: -50, opacity: 0 }}
            animate={{ x: 0, opacity: 1 }}
            exit={{ x: -50, opacity: 0 }}
            layout 
            className={`p-3 rounded-r-lg border-l-4 shadow-lg backdrop-blur-md bg-slate-900/80 text-sm font-bold flex flex-col gap-1 pointer-events-auto w-full`}
            style={{ borderColor: note.color }}
        >
            <div style={{ color: note.color }}>{note.message}</div>
            {note.action && (
                <button
                    onClick={() => { note.action!.onClick(); onRemove(note.id); }}
                    className="self-start text-[10px] bg-slate-700 hover:bg-slate-600 px-2 py-1 rounded text-white mt-1 border border-slate-500"
                >
                    {note.action.label}
                </button>
            )}
        </motion.div>
    );
});

const Minimap: React.FC = () => {
    const { minimapEnemies, drops, playerPosition } = useGameStore(s => ({
        minimapEnemies: s.minimapEnemies,
        drops: s.drops,
        playerPosition: s.playerPosition
    }));

    return (
        <div className="absolute bottom-6 right-6 w-40 h-40 bg-slate-900/90 rounded-full border-2 border-slate-600 shadow-2xl overflow-hidden pointer-events-auto z-10">
             <div className="relative w-full h-full opacity-80">
                <div className="absolute top-1/2 left-1/2 w-2 h-2 bg-white rounded-full -translate-x-1/2 -translate-y-1/2 shadow-[0_0_5px_white] z-20 ring-2 ring-black/50" />

                {minimapEnemies.map((e, i) => {
                    const dx = e.x - playerPosition.x;
                    const dy = e.z - playerPosition.z;
                    // Radius ~ 40
                    const relX = dx / 80;
                    const relY = dy / 80;

                    if (relX * relX + relY * relY > 0.23) return null;

                    let color = 'bg-red-500';
                    let size = 'w-1.5 h-1.5';
                    if (e.type === 2) { color = 'bg-red-600 animate-pulse'; size = 'w-3 h-3'; }
                    else if (e.type === 5) { color = 'bg-purple-500'; size = 'w-2 h-2'; }
                    else if (e.type === 0) { color = 'bg-green-500'; }
                    else if (e.type === 1) { color = 'bg-orange-600'; }

                    return (
                        <div 
                            key={i} 
                            className={`absolute rounded-full ${color} ${size}`}
                            style={{ 
                                left: `${50 + relX * 100}%`, 
                                top: `${50 + relY * 100}%`,
                                transform: 'translate(-50%, -50%)'
                            }}
                        />
                    );
                })}
                {drops.map(d => {
                    if (d.type === 'XP' || d.type === 'GOLD') return null; 
                    const dx = d.position.x - playerPosition.x;
                    const dy = d.position.z - playerPosition.z;
                    const relX = dx / 80;
                    const relY = dy / 80;
                    if (relX * relX + relY * relY > 0.23) return null;

                    let color = 'bg-cyan-400';
                    if (d.item?.rarity === 'LEGENDARY' || d.item?.rarity === 'MYTHIC') color = 'bg-yellow-400 animate-ping';
                    else if (d.item?.rarity === 'EPIC') color = 'bg-purple-400';

                    return (
                        <div 
                            key={`d-${d.id}`} 
                            className={`absolute rounded-full ${color} w-1.5 h-1.5`}
                            style={{ 
                                left: `${50 + relX * 100}%`, 
                                top: `${50 + relY * 100}%`,
                                transform: 'translate(-50%, -50%)'
                            }}
                        />
                    );
                })}
             </div>
             <div className="absolute inset-0 rounded-full border border-white/10 pointer-events-none" />
             <div className="absolute bottom-2 left-1/2 -translate-x-1/2 text-[10px] text-slate-400 font-mono font-bold bg-black/40 px-1 rounded">
                 {Math.round(playerPosition.x)}, {Math.round(playerPosition.z)}
             </div>
        </div>
    );
};

