const ActiveSkillSlot: React.FC<{
    icon: React.ReactNode;
    level: number;
    cooldown: number;
    label: string;
    desc: string;
    borderColor: string;
    active: boolean;
    manaCost?: number;
    currentMana?: number;
    heroClass?: string;
    charges?: number;
    maxCharges?: number;
}> = ({ icon, level, cooldown, label, desc, borderColor, active, manaCost = 0, currentMana = 999, heroClass, charges, maxCharges }) => {
    const actualCost = heroClass === 'WIZARD' ? Math.ceil(manaCost * 1.3) : manaCost;
    const canAfford = currentMana >= actualCost;
    const onCooldown = charges !== undefined ? charges === 0 : cooldown > 0;

    return (
        <div className="relative group flex flex-col items-center">
            <div className={`w-16 h-16 bg-slate-900 border-2 rounded-xl flex items-center justify-center relative overflow-hidden transition-all 
                ${active ? borderColor : 'border-slate-800 opacity-50'}
                ${!canAfford && !onCooldown && active ? 'grayscale opacity-70' : ''}
            `}>
                {icon}
                {charges !== undefined && maxCharges !== undefined && maxCharges > 1 && (
                    <div className="absolute top-1 right-1 text-[10px] font-bold bg-black/60 px-1 rounded text-white z-20">
                        {charges}
                    </div>
                )}
                {active && cooldown > 0 && (
                    <div className={`absolute inset-0 flex items-center justify-center text-xl font-bold text-white z-20 ${charges !== undefined ? 'bg-black/40' : 'bg-black/80'}`}>
                        {charges !== undefined && charges > 0 ? '' : cooldown.toFixed(1)}
                        {charges !== undefined && (
                             <div className="absolute bottom-0 left-0 h-1 bg-white" style={{ width: '100%', transform: `scaleX(${1 - (cooldown / 3)})`, transformOrigin: 'left' }}/>
                        )}
                    </div>
                )}
                {!active && (
                    <div className="absolute inset-0 bg-black/60 flex items-center justify-center z-20 flex-col">
                        <span className="text-slate-400 text-[8px] font-bold">LOCKED</span>
                    </div>
                )}
                {!canAfford && !onCooldown && active && (
                    <div className="absolute inset-0 bg-blue-900/60 flex items-center justify-center z-10 flex-col">
                        <span className="text-blue-200 text-xs font-bold drop-shadow-md">NO</span>
                        <span className="text-blue-200 text-xs font-bold drop-shadow-md">MANA</span>
                    </div>
                )}
                {active && (
                    <div className="absolute bottom-1 right-1 flex gap-0.5 z-20">
                        {level > 0 && (
                            <span className="text-[10px] font-bold bg-black/60 px-1 rounded text-yellow-400">Lv.{level}</span>
                        )}
                    </div>
                )}
            </div>
            <div className="absolute -top-3 left-1/2 -translate-x-1/2 text-[10px] font-bold bg-slate-800 px-1.5 rounded border border-slate-600 whitespace-nowrap z-30">
                {label}
            </div>
            <div className="absolute bottom-full mb-2 left-1/2 -translate-x-1/2 w-56 bg-slate-900 text-xs p-3 rounded border border-slate-600 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none z-50 text-center shadow-xl backdrop-blur-md">
                <div className="font-bold text-yellow-400 mb-1">{desc}</div>
                {manaCost > 0 && active && <div className="text-blue-400 font-mono mt-1 font-bold">Cost: {actualCost} MP</div>}
                {!active && <div className="text-red-400 font-mono mt-1 font-bold">Locked</div>}
            </div>
        </div>
    );
};

