      if (skill === 'dash' && currentLevel >= 1) {
          get().addNotification("Dash is already max level!", "red", "SYSTEM");
          return {};
      }

      let cost = skill === 'special' ? 5 : (currentLevel === 0 ? 3 : currentLevel + 1);
      if (skill === 'regen') cost = currentLevel === 0 ? 6 : 5;

      if (state.skillPoints >= cost) {
          const newLevels = { ...state.skillLevels, [skill]: currentLevel + 1 };

          let newMaxDash = state.maxDashCharges;
          let newCurrentDash = state.dashCharges;
          if (skill === 'dash') {
              newMaxDash = 2; 
              newCurrentDash = 2;
          }

          let newActiveQ = state.activeAbilityQ;
          if (skill === 'piercing') newActiveQ = 'PIERCING_SHOT';
          if (skill === 'gravity') newActiveQ = 'GRAVITY_SPELL';
          if (skill === 'rage') newActiveQ = 'RAGE';

          return {
              skillPoints: state.skillPoints - cost,
              skillLevels: newLevels,
              activeAbilityQ: newActiveQ,
              maxDashCharges: newMaxDash,
              dashCharges: newCurrentDash
          };
      }
      return {};
    }),

    triggerSkillCooldown: (skill) => set((state) => {
      const baseCD = { q: 7.0, r: 15.0, e: 20.0, dash: state.stats.dashCooldown }[skill];
      if (!baseCD) return {};
      const cooldown = baseCD * (1 - state.stats.cooldownReduction);
      return { skills: { ...state.skills, [skill]: cooldown } };
    }),

    triggerPetCooldown: () => set((state) => {
        const pet = state.equipment.pet;
        if (!pet || !pet.petCooldown) return {};
        return { skills: { ...state.skills, pet: pet.petCooldown } };
    }),

    performDash: () => {
        const state = get();
        if (state.dashCharges > 0) {
            set(s => {
                const newCharges = s.dashCharges - 1;
                const newDashCD = s.skills.dash <= 0 ? s.stats.dashCooldown * (1 - s.stats.cooldownReduction) : s.skills.dash;
                return { 
                    dashCharges: newCharges, 
                    skills: { ...s.skills, dash: newDashCD } 
                };
            });
            return true;
        }
        return false;
    },

    tickCooldowns: (delta) => {
      const state = get();

      let q = Math.max(0, state.skills.q - delta);
      let r = Math.max(0, state.skills.r - delta);
      let e = Math.max(0, state.skills.e - delta);
      let pet = Math.max(0, state.skills.pet - delta);

      let dashCD = state.skills.dash;
      let dashCharges = state.dashCharges;

      if (dashCharges < state.maxDashCharges) {
          dashCD -= delta;
          if (dashCD <= 0) {
              dashCharges += 1;
              if (dashCharges < state.maxDashCharges) {
                  dashCD = state.stats.dashCooldown * (1 - state.stats.cooldownReduction);
              } else {
                  dashCD = 0;
              }
          }
      } else {
          dashCD = 0; 
      }

      // Check if skills actually changed to avoid object reference churn
      let skillsChanged = false;
      if (Math.abs(q - state.skills.q) > 0.0001 || 
          Math.abs(r - state.skills.r) > 0.0001 || 
          Math.abs(e - state.skills.e) > 0.0001 ||
          Math.abs(dashCD - state.skills.dash) > 0.0001 ||
          Math.abs(pet - state.skills.pet) > 0.0001) {
          skillsChanged = true;
      }

      let rageTimer = state.rageTimer;
      let rageMode = state.rageMode;
      let sprintTimer = state.sprintTimer;
      let stats = state.stats;

      let earthwall = { ...state.earthwall };
      let earthwallChanged = false;
      if (earthwall.active) {
          earthwall.timer -= delta;
          earthwallChanged = true;
          if (earthwall.timer <= 0) earthwall.active = false;
      }

      let warVitalityTimer = state.warVitalityTimer;
      let newHealth = state.health;
      let healthChanged = false;

      if (warVitalityTimer > 0) {
          warVitalityTimer -= delta;
          if (newHealth < stats.maxHealth) {
              newHealth = Math.min(stats.maxHealth, newHealth + (10 * delta));
              healthChanged = true;
          }
      }

      if (sprintTimer > 0) sprintTimer -= delta;

      let recalc = false;
      if (rageMode) {
          rageTimer -= delta;
          if (rageTimer <= 0) { rageMode = false; recalc = true; }
      }
      if (state.sprintTimer > 0 && sprintTimer <= 0) recalc = true;
      if (recalc) stats = calculateStats(state.baseStats, state.equipment, rageMode, sprintTimer > 0);

      const newBarrierCooldown = Math.max(0, state.barrierCooldown - delta);
      const newPotionCD = Math.max(0, state.potionCooldown - delta);

      // Construct update object
      const update: Partial<GameStore> = {
          waveTimer: state.waveTimer + delta, // Always update logic timer
      };

      if (skillsChanged) update.skills = { q, r, e, dash: dashCD, pet };
      if (dashCharges !== state.dashCharges) update.dashCharges = dashCharges;
      if (recalc) {
          update.stats = stats;
          update.rageMode = rageMode;
      }
      if (rageMode && rageTimer !== state.rageTimer) update.rageTimer = rageTimer;
      if (sprintTimer !== state.sprintTimer) update.sprintTimer = Math.max(0, sprintTimer);
      if (earthwallChanged) update.earthwall = earthwall;
      if (warVitalityTimer !== state.warVitalityTimer) update.warVitalityTimer = Math.max(0, warVitalityTimer);
      if (newPotionCD !== state.potionCooldown) update.potionCooldown = newPotionCD;
      if (newBarrierCooldown !== state.barrierCooldown) update.barrierCooldown = newBarrierCooldown;
      if (healthChanged) update.health = newHealth;

      set(update);
    },

    addNotification: (message, color = 'white', type = 'ITEM', action) => set(state => ({ notifications: [...state.notifications, { id: Math.random().toString(), message, color, type, action }] })),
    removeNotification: (id) => set(state => ({ notifications: state.notifications.filter(n => n.id !== id) })),
    toggleInventory: () => set(state => ({ isInventoryOpen: !state.isInventoryOpen, isShopOpen: false, isCharacterSheetOpen: false, isCodexOpen: false, status: !state.isInventoryOpen ? GameStatus.PAUSED : GameStatus.PLAYING })),
    toggleCharacterSheet: () => set(state => ({ isCharacterSheetOpen: !state.isCharacterSheetOpen, isShopOpen: false, isInventoryOpen: false, isCodexOpen: false, status: !state.isCharacterSheetOpen ? GameStatus.PAUSED : GameStatus.PLAYING })),
    toggleCodex: () => set(state => ({ isCodexOpen: !state.isCodexOpen, isShopOpen: false, isInventoryOpen: false, isCharacterSheetOpen: false, status: !state.isCodexOpen ? GameStatus.PAUSED : GameStatus.MENU })),
    closeAllUI: () => set({ isInventoryOpen: false, isShopOpen: false, isCharacterSheetOpen: false, isCodexOpen: false, status: GameStatus.PLAYING }),
    openSpecificShop: (tab) => set({ isShopOpen: true, isInventoryOpen: false, activeShopTab: tab, status: GameStatus.PAUSED }),
    clearActionResult: () => set({ actionResult: null }),
    addScore: (amount) => set((state) => ({ score: state.score + amount })),
    addGems: (amount) => set((state) => ({ gems: state.gems + amount })),
    addExperience: (amount) => { 
        set(state => {
            let xp = state.experience + amount;
            let level = state.level;
            let next = state.experienceToNextLevel;
            let points = state.skillPoints;
            let leveledUp = false;

            while (xp >= next) {
                xp -= next;
                level++;
                points++;
                next = Math.floor(next * 1.2);
                leveledUp = true;
            }

            if (leveledUp) {
                // Visual effect logic would be triggered via effect component listening to level change
                return { level, experience: xp, experienceToNextLevel: next, skillPoints: points, levelUpVisualTimer: 2.0, health: state.stats.maxHealth, mana: state.stats.maxMana };
            }
            return { experience: xp };
        })
    },
    takeDamage: (amount) => {
        const s = get();
        if (s.isInvincible || s.status !== GameStatus.PLAYING) return;

        // Defense Calc
        const dmg = Math.max(1, amount - (s.stats.defense * 0.5));

        // Barrier Logic
        if (s.skillLevels.barrier > 0 && s.barrierCooldown <= 0) {
            set({ barrierCooldown: Math.max(5, 12 - s.skillLevels.barrier), invincibilityTimer: 1.0, isInvincible: true });
            // Knockback all enemies visually handled in EnemyManager via barrier-trigger event
            window.dispatchEvent(new CustomEvent('barrier-trigger', { detail: { position: s.playerPosition, radius: 5.0, force: 5.0 } }));
            return;
        }

        // Dodge
        if (Math.random() < s.stats.dodge) {
             // Dodged
             return;
        }

        const newHp = s.health - dmg;
        if (newHp <= 0) {
            // Revive Logic
            const reviveItem = s.inventory.find(i => i.type === 'REVIVE');
            const phoenix = s.equipment.pet?.petSkill === 'REVIVE' && s.equipment.pet.petCooldown && s.skills.pet <= 0;

            if (reviveItem) {
                const newInv = s.inventory.filter(i => i !== reviveItem);
                set({ health: s.stats.maxHealth, inventory: newInv, reviveAnimTimer: 2.0, isInvincible: true, invincibilityTimer: 3.0 });
                get().addNotification("Revived by Ankh!", COLORS.rarityEpic, "SYSTEM");
            } else if (phoenix) {
                set({ health: s.stats.maxHealth, reviveAnimTimer: 2.0, isInvincible: true, invincibilityTimer: 3.0 });
                get().triggerPetCooldown();
                get().addNotification("Revived by Phoenix!", COLORS.rarityLegendary, "SYSTEM");
            } else {
                set({ health: 0, status: GameStatus.GAME_OVER });
            }
        } else {
            set({ health: newHp });
        }
    },
    heal: (amount) => set((state) => ({ health: Math.min(state.health + amount, state.stats.maxHealth) })),
    restoreMana: (amount) => set((state) => ({ mana: Math.min(state.mana + amount, state.stats.maxMana) })),
    setPlayerPosition: (pos) => set({ playerPosition: pos }),
    triggerInvincibility: (duration) => set((state) => ({ invincibilityTimer: Math.max(state.invincibilityTimer, duration), isInvincible: true })),
    spawnDrop: (pos, type, value, rarity) => { 
        set(s => {
            // Limit total drops
            if (s.drops.length > 200) {
                // Remove oldest non-item drop
                const idx = s.drops.findIndex(d => d.type !== 'ITEM');
                if (idx !== -1) {
                    s.drops.splice(idx, 1);
                }
            }

            let item = null;
            if (type === 'ITEM') {
                // Generate item based on rarity or random
                const pool = ITEMS_POOL; // Simplified
                item = pool[Math.floor(Math.random() * pool.length)];
                // ... (Logic to respect rarity if passed)
            }

            return {
                drops: [...s.drops, { 
                    id: Math.random(), 
                    position: pos, 
                    type, 
                    value, 
                    item, 
                    active: true, 
                    rotation: Math.random() * Math.PI 
                }]
            };
        })
    },
    collectDrop: (id) => { 
        const s = get();
        const drop = s.drops.find(d => d.id === id);
        if (!drop) return;

        if (drop.type === 'XP') s.addExperience(drop.value);
        if (drop.type === 'GOLD') s.addScore(drop.value);
        if (drop.type === 'GEM') s.addGems(drop.value);
        if (drop.type === 'ITEM' && drop.item) {
            // Add to inventory
            if (s.inventory.length < s.maxInventorySlots) {
                const newItem = { ...drop.item, id: Math.random().toString() };
                set({ inventory: [...s.inventory, newItem] });
                s.addNotification(`Picked up ${drop.item.name}`, COLORS.dropItem, "ITEM");
            } else {
                s.addNotification("Inventory Full!", "red", "SYSTEM");
                return; // Don't remove drop
            }
        }

        set({ drops: s.drops.filter(d => d.id !== id) });
    },
    activateRage: () => set(state => ({ rageMode: true, rageTimer: 4.0, stats: calculateStats(state.baseStats, state.equipment, true, state.sprintTimer>0) })),
    activateEarthwall: (pos) => set(state => ({ earthwall: { active: true, position: pos, timer: 4.0, radius: 12.0 } })),
    activateWarVitality: () => set({ warVitalityTimer: 6.0 }),
    activateSprint: () => {
        const s = get();
        set({ sprintTimer: 4.0, stats: calculateStats(s.baseStats, s.equipment, s.rageMode, true), invincibilityTimer: Math.max(s.invincibilityTimer, 4.0), isInvincible: true });
    },
    updatePassiveCooldowns: (p) => set(s => ({ passiveSkillState: { ...s.passiveSkillState, ...p } })),
    advanceWave: () => {
        const u = generateUpgradeOptions(get().hero);
        set(s => ({ wave: s.wave + 1, waveTimer: 0, accumulatedWaveGold: s.accumulatedWaveGold + 100, status: GameStatus.LEVEL_UP, upgradeOptions: u }));
    },
    setBossData: (d) => set(s => ({ bossData: { ...s.bossData, ...d } })),
    updateMinimapEnemies: (e) => set({ minimapEnemies: e }),
    breakCrate: (id) => { 
        set(s => {
            const crates = s.crates.map(c => c.id === id ? { ...c, active: false } : c);
            return { crates };
        })
    },
    damageCrate: (id, amt) => { 
        set(s => {
            const crates = s.crates.map(c => c.id === id ? { ...c, hp: c.hp - amt } : c);
            return { crates };
        })
    },
    setSellConfirmationItem: (i) => set({ sellConfirmationItem: i }),
    clearGachaResults: () => set({ status: GameStatus.PLAYING, gachaResults: [] }),
    resetGame: () => { get().enterLobby(); }, 
    handleInventoryFull: () => { },
    equipItem: (item) => { 
        const s = get();
        // Simple logic: Swap
        let slot: keyof typeof s.equipment = 'weapon';
        if (item.type === 'ARMOR') slot = 'armor';
        if (item.type === 'ACCESSORY') slot = 'accessory';
        if (item.type === 'PET') slot = 'pet';

        const oldItem = s.equipment[slot];
        const newInv = s.inventory.filter(i => i.id !== item.id);
        if (oldItem) newInv.push(oldItem);

        const newEquip = { ...s.equipment, [slot]: item };
        const newStats = calculateStats(s.baseStats, newEquip, s.rageMode, s.sprintTimer > 0);

        set({ equipment: newEquip, inventory: newInv, stats: newStats });
    },
    unequipItem: (slot) => { 
        const s = get();
        const item = s.equipment[slot];
        if (!item) return;
        if (s.inventory.length >= s.maxInventorySlots) {
            s.addNotification("Inventory Full", "red", "SYSTEM");
            return;
        }

        const newEquip = { ...s.equipment, [slot]: null };
        const newStats = calculateStats(s.baseStats, newEquip, s.rageMode, s.sprintTimer > 0);
        set({ equipment: newEquip, inventory: [...s.inventory, item], stats: newStats });
    },
    autoEquip: () => { },
    buyItem: (item, q) => { 
        const s = get();
        const cost = (item.price || 0) * (q || 1);
        if (s.score >= cost) {
            // Check inventory
            if (s.inventory.length < s.maxInventorySlots) {
                const newItem = { ...item, id: Math.random().toString(), quantity: q || 1 };
                set({ score: s.score - cost, inventory: [...s.inventory, newItem] });
                s.addNotification(`Bought ${item.name}`, "yellow", "ITEM");
                return true;
            } else {
                s.addNotification("Inventory Full", "red", "SYSTEM");
            }
        } else {
            s.addNotification("Not enough Gold", "red", "SYSTEM");
        }
        return false;
    },
    sellItem: (item) => { 
        const s = get();
        const val = Math.floor((item.price || 0) * 0.3);
        const newInv = s.inventory.filter(i => i.id !== item.id);
        set({ score: s.score + val, inventory: newInv });
        s.addNotification(`Sold ${item.name} for ${val} G`, "yellow", "SYSTEM");
    },
    massSell: (r) => { },
    recycleItem: (i) => { },
    massRecycle: (r) => { },
    combineMaterials: (r) => { },
    craftItem: (r) => { return false; },
    buyInventorySlots: () => { return false; },
    performSummon: (a) => { 
        const s = get();
        const cost = a === 1 ? 100 : 1000; // Gems
        if (s.gems >= cost) {
            // Generate items
            const results = [];
            for(let i=0; i<a; i++) {
                const pool = ITEMS_POOL;
                results.push({ ...pool[Math.floor(Math.random() * pool.length)], id: Math.random().toString() });
            }

            // Add to inventory (ignoring limit for gacha for now, or handle it)
            set({ gems: s.gems - cost, gachaResults: results, status: GameStatus.GACHA_REVEAL, inventory: [...s.inventory, ...results] });
            return true;
        }
        return false;
    },
    upgradeItem: (i) => { },
    applyUpgrade: (u) => { 
        const s = get();
        const newStats = { ...s.baseStats };
        // Apply permanent stat boost
        if (u.type === 'DAMAGE') newStats.damage *= (1 + u.value);
        if (u.type === 'HEALTH') newStats.maxHealth += u.value;
        // ... simple implementation

        // Skill Levels
        const newSkills = { ...s.skillLevels };
        if (u.type === 'SKILL_ORBITAL') newSkills.orbital++;
        if (u.type === 'SKILL_THUNDER') newSkills.thunder++;
        // ...

        set({ baseStats: newStats, skillLevels: newSkills, status: GameStatus.PLAYING });
    },
    selectUpgrade: (u) => { get().applyUpgrade(u); },
}));

