const Minimap: React.FC = () => {
    const minimapEnemies = useGameStore(s => s.minimapEnemies);
    const drops = useGameStore(s => s.drops);
    const playerPosition = useGameStore(s => s.playerPosition);

    return (
        <div className="absolute bottom-6 right-6 w-40 h-40 bg-slate-900/90 rounded-full border-2 border-slate-600 shadow-2xl overflow-hidden pointer-events-auto z-10">
             <div className="relative w-full h-full opacity-80">
                <div className="absolute top-1/2 left-1/2 w-2 h-2 bg-white rounded-full -translate-x-1/2 -translate-y-1/2 shadow-[0_0_5px_white] z-20 ring-2 ring-black/50" />

                {minimapEnemies.map((e, i) => {
                    const dx = e.x - playerPosition.x;
                    const dy = e.z - playerPosition.z;
                    // Radius ~ 40
                    const relX = dx / 80;
                    const relY = dy / 80;

                    if (relX * relX + relY * relY > 0.23) return null;

                    let color = 'bg-red-500';
                    let size = 'w-1.5 h-1.5';
                    if (e.type === 2) { color = 'bg-red-600 animate-pulse'; size = 'w-3 h-3'; }
                    else if (e.type === 5) { color = 'bg-purple-500'; size = 'w-2 h-2'; }
                    else if (e.type === 0) { color = 'bg-green-500'; }
                    else if (e.type === 1) { color = 'bg-orange-600'; }

                    return (
                        <div 
                            key={i} 
                            className={`absolute rounded-full ${color} ${size}`}
                            style={{ 
                                left: `${50 + relX * 100}%`, 
                                top: `${50 + relY * 100}%`,
                                transform: 'translate(-50%, -50%)'
                            }}
                        />
                    );
                })}
                {drops.map(d => {
                    if (d.type === 'XP' || d.type === 'GOLD') return null; 
                    const dx = d.position.x - playerPosition.x;
                    const dy = d.position.z - playerPosition.z;
                    const relX = dx / 80;
                    const relY = dy / 80;
                    if (relX * relX + relY * relY > 0.23) return null;

                    let color = 'bg-cyan-400';
                    if (d.item?.rarity === 'LEGENDARY' || d.item?.rarity === 'MYTHIC') color = 'bg-yellow-400 animate-ping';
                    else if (d.item?.rarity === 'EPIC') color = 'bg-purple-400';

                    return (
                        <div 
                            key={`d-${d.id}`} 
                            className={`absolute rounded-full ${color} w-1.5 h-1.5`}
                            style={{ 
                                left: `${50 + relX * 100}%`, 
                                top: `${50 + relY * 100}%`,
                                transform: 'translate(-50%, -50%)'
                            }}
                        />
                    );
                })}
             </div>
             <div className="absolute inset-0 rounded-full border border-white/10 pointer-events-none" />
             <div className="absolute bottom-2 left-1/2 -translate-x-1/2 text-[10px] text-slate-400 font-mono font-bold bg-black/40 px-1 rounded">
                 {Math.round(playerPosition.x)}, {Math.round(playerPosition.z)}
             </div>
        </div>
    );
};

